// V2 B3 (201–250):    A2=7,  B1=13, B2=19, C1=11 | Grammar=26, Vocabulary=16, Reading=8
// Total (250 items):  A2=33, B1=69, B2=87, C1=61 | Grammar=118, Vocabulary=85, Reading=47

export const ITEM_BANK = [{"item_id": "39a5364c-c9bf-4b26-910b-b1bf988d98c1", "stem": "She ______ to school every day by bus.", "options": ["go", "goes", "going", "gone"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.8, "irt_c_param": 0.25, "explanation_text": "With 'she' (third person singular), present simple verbs add -s or -es. 'She goes' is correct. Vietnamese doesn't change verb forms for different subjects, so this is a common area to practise.", "distractor_traps": {"0": "L1 transfer: Vietnamese verbs don't conjugate \u2014 'go' feels complete without the -s", "2": "Confuses present simple with present continuous form", "3": "Past participle form \u2014 unrelated to present habitual meaning"}, "goal_tags": ["A", "B", "C", "D", "E"]}, {"item_id": "616ab857-2257-4c14-9239-f4b9f904455e", "stem": "I ______ my homework before dinner yesterday.", "options": ["finish", "finished", "have finished", "am finishing"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.6, "irt_c_param": 0.25, "explanation_text": "'Yesterday' tells us this happened in the past and is complete. Past simple ('finished') is the right choice. 'Have finished' (present perfect) connects past to present, but 'yesterday' anchors this firmly in the past.", "distractor_traps": {"0": "L1 transfer: Vietnamese uses time words instead of verb changes \u2014 'finish' + 'yesterday' feels complete", "2": "Present perfect \u2014 tempting because it involves a completed action, but 'yesterday' blocks it", "3": "Present continuous \u2014 wrong time frame entirely"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "54a8bfc5-fa70-4ed3-9960-d01ffe37551a", "stem": "Look! The children ______ in the park right now.", "options": ["play", "plays", "are playing", "played"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.5, "irt_c_param": 0.22, "explanation_text": "'Look!' and 'right now' signal something happening at this moment. Present continuous (are + verb-ing) describes actions in progress. 'Are playing' matches the ongoing action.", "distractor_traps": {"0": "L1 transfer: Vietnamese uses '\u0111ang' for ongoing actions but the verb itself doesn't change", "1": "Third person -s applied to a plural subject", "3": "Past simple \u2014 contradicts 'right now'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "2823c03a-e72c-4116-9446-a35a08949fc0", "stem": "I ______ in this company for three years, and I still enjoy the work.", "options": ["work", "worked", "have worked", "had worked"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": -0.4, "irt_c_param": 0.2, "explanation_text": "'For three years' + 'still enjoy' tells us the action started in the past and continues now. Present perfect ('have worked') connects past to present. Past simple would mean you no longer work there.", "distractor_traps": {"0": "L1 transfer: Vietnamese '\u0111\u00e3...\u0111\u01b0\u1ee3c 3 n\u0103m' doesn't require a special verb form", "1": "Past simple \u2014 implies the job ended, which contradicts 'still enjoy'", "3": "Past perfect \u2014 used for an action before another past action, not for a connection to now"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "abe5db8a-a23f-45d1-b299-75cd151870d3", "stem": "When I called her, she said she ______ dinner for her family.", "options": ["cooks", "cooked", "was cooking", "has cooked"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.2, "irt_c_param": 0.2, "explanation_text": "The cooking was in progress at the moment of the phone call. Past continuous ('was cooking') shows an action that was ongoing when another past action interrupted it. 'Cooked' would mean the cooking was already finished.", "distractor_traps": {"0": "Wrong time frame \u2014 present tense inside past reporting", "1": "Past simple \u2014 implies the cooking was complete, losing the 'in progress' meaning", "3": "Present perfect \u2014 can't be used inside past-tense reported speech without shifting to past perfect"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "6c66af79-463f-497a-b01e-8067192ab4ff", "stem": "The train ______ at 6:15 tomorrow morning. Please don't be late.", "options": ["leaves", "will leave", "is leaving", "left"], "correct_choice": 0, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B1", "irt_a_param": 1.4, "irt_b_param": 0, "irt_c_param": 0.2, "explanation_text": "Scheduled timetable events (trains, flights, classes) use present simple even when they're in the future. 'The train leaves at 6:15' treats the departure as a fixed schedule. 'Will leave' and 'is leaving' are grammatically possible but less natural for timetabled events.", "distractor_traps": {"1": "Logical but less natural: 'will leave' works for predictions, but timetables prefer present simple", "2": "Present continuous for future \u2014 works for personal plans but not fixed schedules", "3": "Past simple \u2014 contradicts 'tomorrow'"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "511261ae-5c7a-40fc-b55a-a8f7a79bf9d7", "stem": "She ______ three different countries before she turned twenty-five.", "options": ["visits", "visited", "has visited", "had visited"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "Two past events need ordering: visiting countries happened before turning twenty-five. Past perfect ('had visited') marks the earlier event. Both events are complete and in the past, so present perfect doesn't apply here.", "distractor_traps": {"0": "Wrong time frame entirely", "1": "Past simple \u2014 technically communicates the meaning, but misses the 'before another past event' relationship that B1 learners need to master", "2": "Present perfect \u2014 tempting because of 'experience' meaning, but 'before she turned' anchors both events in finished past time"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "3e7a9eb3-ca76-448c-9856-d0b0a86c773e", "stem": "By this time next year, I hope I ______ enough money to travel abroad.", "options": ["save", "saved", "will save", "will have saved"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B1", "irt_a_param": 1.4, "irt_b_param": 0.3, "irt_c_param": 0.18, "explanation_text": "'By this time next year' sets a future deadline. Future perfect ('will have saved') describes something that will be complete before a point in the future. It means: between now and then, the saving will be finished.", "distractor_traps": {"0": "L1 transfer: Vietnamese doesn't mark future completion differently from future action", "1": "Past simple \u2014 wrong time frame", "2": "Future simple \u2014 'will save' talks about the action but doesn't emphasise completion before the deadline"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "36057cbd-3995-40c8-bded-117b4b026b55", "stem": "The scientists announced that they ______ a new species in the Amazon, though peer review of their findings is still ongoing.", "options": ["discover", "discovered", "had discovered", "have discovered"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "The discovery happened in the past but its relevance continues \u2014 the peer review is 'still ongoing.' Present perfect ('have discovered') connects the past event to its present significance. Past perfect would over-distance the event, and past simple would ignore the ongoing relevance.", "distractor_traps": {"0": "Wrong time frame", "1": "Past simple \u2014 grammatically acceptable but loses the present-relevance connection that 'still ongoing' demands", "2": "Past perfect \u2014 implies the discovery is distanced and complete, which contradicts the active peer review"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "d8aab118-b24f-4334-b0c2-7740bb225b38", "stem": "The committee ______ the proposal for over two hours when the chairperson finally called for a vote.", "options": ["discussed", "was discussing", "had been discussing", "has been discussing"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "B2", "irt_a_param": 1.6, "irt_b_param": 0.9, "irt_c_param": 0.18, "explanation_text": "Past perfect continuous ('had been discussing') shows a prolonged action that was in progress before another past event. The discussion was ongoing for two hours, then the vote happened. This combines duration ('for over two hours') with the before-another-past-event relationship.", "distractor_traps": {"0": "Past simple \u2014 loses the ongoing, prolonged nature of the discussion", "1": "Past continuous \u2014 shows an action in progress but doesn't emphasise the duration or the completed-before-another-event relationship", "3": "Present perfect continuous \u2014 wrong: both events are in the past with no present connection"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "623fda84-083e-43af-93b0-7be0505e5e45", "stem": "The manuscript, which ______ on the editor's desk for six months without comment, was quietly returned to the author.", "options": ["sat", "had sat", "has sat", "had been sitting"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.4, "irt_c_param": 0.15, "explanation_text": "Past perfect continuous ('had been sitting') captures both duration ('for six months') and the ongoing nature of the inaction before the return. 'Had sat' is grammatically possible but loses the continuous, neglected quality. The continuous form here carries emotional weight \u2014 it suggests the manuscript was languishing.", "distractor_traps": {"0": "Past simple \u2014 loses the 'before another past event' relationship and the duration emphasis", "1": "Past perfect simple \u2014 grammatically close but loses the continuous, ongoing quality that gives the sentence its tone of neglect", "2": "Present perfect \u2014 the manuscript was returned (past), so present perfect breaks the time frame"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "16a34266-2a5d-4bc4-a4c4-bb7d75886414", "stem": "It is high time the government ______ its approach to renewable energy funding.", "options": ["reconsidered", "reconsiders", "would reconsider", "has reconsidered"], "correct_choice": 0, "skill": "Grammar", "sub_skill": "Verb Tenses", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.6, "irt_c_param": 0.15, "explanation_text": "'It is high time' is a fixed expression that requires past simple \u2014 even though the meaning is about the present or future. This is subjunctive-like usage: the past tense signals unreality or urgency, not past time. Similar to 'I wish I knew' (present meaning, past form).", "distractor_traps": {"1": "Logical but wrong: 'reconsiders' matches the present meaning but violates the 'it's time + past' structure", "2": "'Would reconsider' \u2014 conditional form feels right for expressing desire, but 'it's high time' demands past simple specifically", "3": "Present perfect \u2014 sounds formal enough to be tempting at this level, but doesn't follow the fixed pattern"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "f5068030-da68-470a-93d1-dadf6d86d05b", "stem": "If it ______ tomorrow, we will stay at home.", "options": ["rain", "rains", "will rain", "rained"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.4, "irt_c_param": 0.25, "explanation_text": "In first conditional (if + present simple, will + verb), the 'if' clause uses present simple \u2014 not 'will.' 'If it rains, we will stay' is the pattern. The future meaning is already carried by 'will' in the main clause.", "distractor_traps": {"0": "L1 transfer: no conjugation in Vietnamese \u2014 'rain' without -s feels complete", "2": "Common error: putting 'will' in both clauses because both refer to the future", "3": "Past simple \u2014 would create a second conditional meaning (unlikely/hypothetical)"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "138debbe-ec78-4569-94f2-ede6a523ce75", "stem": "If I ______ more time, I would learn another language.", "options": ["have", "had", "will have", "would have"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.3, "irt_c_param": 0.22, "explanation_text": "Second conditional uses 'if + past simple' to describe an unreal or unlikely present situation. 'If I had more time' doesn't mean past \u2014 it means 'but I don't have enough time right now.' The past form signals imagination, not history.", "distractor_traps": {"0": "First conditional pattern \u2014 would make this a real/likely condition, changing the meaning", "2": "'Will have' mixes first conditional into the if-clause \u2014 grammatically impossible", "3": "'Would have' belongs in third conditional (past unreal), not second"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "194d15f4-e24f-4339-b11d-aa6b5ee5782b", "stem": "If she had studied harder, she ______ the exam.", "options": ["will pass", "would pass", "would have passed", "passed"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0, "irt_c_param": 0.2, "explanation_text": "Third conditional: 'if + had + past participle, would have + past participle.' This describes an unreal past \u2014 she didn't study hard enough, and she didn't pass. Both the condition and the result are imagined alternatives to what actually happened.", "distractor_traps": {"0": "First conditional result \u2014 can't pair with 'had studied' (past unreal condition)", "1": "Second conditional result \u2014 'would pass' is for present unreal, but 'had studied' is past unreal", "3": "Past simple \u2014 states a fact rather than an unreal alternative"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "19fe0a4a-1c41-4ae1-be55-2c883bc877c1", "stem": "I wouldn't have known about the job opening if my friend ______ me.", "options": ["doesn't tell", "didn't tell", "hadn't told", "won't tell"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.2, "irt_c_param": 0.2, "explanation_text": "'Wouldn't have known' is the third conditional result. The matching condition needs 'if + had + past participle' \u2014 'hadn't told.' The friend did tell you (that's why you know), and this sentence imagines the alternative: what if they hadn't?", "distractor_traps": {"0": "Present simple \u2014 wrong time frame for a past unreal condition", "1": "Past simple \u2014 this is the second conditional 'if' pattern, but the result clause ('wouldn't have known') demands third conditional", "3": "Future \u2014 entirely wrong time frame"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "71773c8d-2318-4b30-9292-1564655cb425", "stem": "If the researchers ______ the sample size, the results might have been more reliable \u2014 but the funding had already been cut.", "options": ["increased", "had increased", "would increase", "could increase"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'Might have been' in the result clause signals third conditional (past unreal). The condition needs 'had + past participle.' The final clause ('the funding had already been cut') confirms this is a past situation that can't be changed \u2014 pure counterfactual.", "distractor_traps": {"0": "Past simple \u2014 tempting because it's past, but it doesn't signal the 'unreal' quality that the counterfactual demands", "2": "'Would increase' \u2014 conditional mood but wrong form for a past counterfactual", "3": "'Could increase' \u2014 expresses ability/possibility but doesn't match the past unreal structure"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "7bead928-f580-48cb-8909-a7029a3e6cb8", "stem": "______ I in your position, I would request a formal review of the decision.", "options": ["Am", "Was", "Were", "Being"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "B2", "irt_a_param": 1.6, "irt_b_param": 1, "irt_c_param": 0.18, "explanation_text": "This is an inverted second conditional: 'Were I in your position' replaces 'If I were in your position.' In formal English, 'were' is used for all subjects in subjunctive/hypothetical constructions \u2014 'were I,' 'were he,' 'were she.' The inversion drops 'if' and moves 'were' to the front.", "distractor_traps": {"0": "'Am' \u2014 real present, but the sentence is hypothetical", "1": "'Was' \u2014 commonly used in informal speech but incorrect in this formal inverted structure, which requires subjunctive 'were'", "3": "'Being' \u2014 present participle doesn't work in conditional inversion"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "2802a054-d2a0-41f5-a24a-4f12fce4a00d", "stem": "But for the timely intervention of the central bank, the currency ______ far more sharply than it did.", "options": ["would depreciate", "had depreciated", "would have depreciated", "deprecated"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "'But for' means 'if it were not for' or 'if it had not been for.' Here, 'than it did' confirms this is past. So: 'But for X, Y would have happened' \u2014 third conditional without 'if.' 'Would have depreciated' is the past counterfactual result.", "distractor_traps": {"0": "'Would depreciate' \u2014 second conditional result (present unreal), but 'than it did' makes this past", "1": "'Had depreciated' \u2014 past perfect states a fact rather than a counterfactual", "3": "'Deprecated' \u2014 wrong word entirely (deprecated means outdated/disapproved, not decreased in value)"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "54a57843-895d-4e8b-9590-97eaf9f55b85", "stem": "The project would never have succeeded ______ the team abandoned their original methodology halfway through.", "options": ["if", "had", "unless", "should"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Conditionals", "cefr_difficulty": "C1", "irt_a_param": 1.9, "irt_b_param": 1.7, "irt_c_param": 0.15, "explanation_text": "This is inverted third conditional with an unusual meaning: the project succeeded because they did abandon the old methodology. 'Had the team abandoned' = 'if the team had not abandoned' is wrong \u2014 actually, 'had' here introduces the positive condition. The tricky part: this reads as 'the project succeeded, and the reason is that they changed methodology.' Inversion with 'had' replaces 'if...had.'", "distractor_traps": {"0": "'If' works semantically but requires restructuring: 'if the team had not abandoned' \u2014 the sentence as written uses inversion, which drops 'if'", "2": "'Unless' changes the logical meaning \u2014 'unless they abandoned' means 'if they did not abandon,' which reverses the intended condition", "3": "'Should' is used for future-possibility inversion ('should you need help'), not past counterfactual"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "da96436c-839c-481b-9edb-122966adfc17", "stem": "Can you pass me ______ salt, please?", "options": ["a", "an", "the", "\u2014"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.5, "irt_c_param": 0.25, "explanation_text": "'The salt' refers to a specific salt \u2014 the one on the table that both speakers can see. 'The' is used when both people know which specific thing is meant. Vietnamese doesn't have articles, so this is about building a new habit: if both people know which one, use 'the.'", "distractor_traps": {"0": "'A' \u2014 used for non-specific things ('a restaurant'), not when pointing to a specific one", "1": "'An' \u2014 same as 'a' but before vowel sounds; still wrong because the salt is specific", "3": "No article \u2014 Vietnamese doesn't use articles, so dropping them entirely is the strongest L1 transfer error"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "7af55fec-0613-4252-a196-705d76f54c4f", "stem": "My sister is ______ doctor. She works at the city hospital.", "options": ["a", "an", "the", "\u2014"], "correct_choice": 0, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.3, "irt_c_param": 0.25, "explanation_text": "'A doctor' describes her profession \u2014 she is one of many doctors. We use 'a/an' when introducing what someone is or what something is for the first time. The second sentence uses 'the' because now we're talking about a specific hospital.", "distractor_traps": {"1": "'An' \u2014 wrong because 'doctor' starts with a consonant sound", "2": "'The' \u2014 would mean a specific, unique doctor that both people already know about", "3": "No article \u2014 direct L1 transfer from Vietnamese where 'ch\u1ecb t\u00f4i l\u00e0 b\u00e1c s\u0129' has no article"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "07ef5b17-88b7-4217-b265-fd33b3db734d", "stem": "______ advice she gave me turned out to be very useful.", "options": ["A", "An", "The", "\u2014"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.2, "irt_c_param": 0.22, "explanation_text": "'The advice she gave me' is specific \u2014 it's defined by 'she gave me.' When a noun is followed by a phrase that identifies exactly which one we mean, it takes 'the.' Note: 'advice' is uncountable in English, so 'a advice' is impossible.", "distractor_traps": {"0": "'A' \u2014 impossible: 'advice' is uncountable ('a piece of advice' works, but 'a advice' doesn't)", "1": "'An' \u2014 same problem: uncountable noun", "3": "No article \u2014 the defining clause 'she gave me' makes this specific, requiring 'the'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "ea880fca-8e5d-42dc-9487-2231fd300566", "stem": "______ happiness is something everyone wants, but few people agree on what it means.", "options": ["A", "The", "\u2014", "An"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0, "irt_c_param": 0.2, "explanation_text": "Abstract concepts used in a general sense (happiness, love, freedom, education) take no article. 'Happiness is something everyone wants' talks about happiness in general \u2014 not a specific happiness. If we said 'the happiness I felt,' the defining phrase would make it specific.", "distractor_traps": {"0": "'A' \u2014 'happiness' is uncountable and abstract", "1": "'The' \u2014 would make this about a specific instance of happiness, but the sentence discusses the concept generally", "3": "'An' \u2014 uncountable noun, same issue as 'a'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "d5779125-791a-464b-a217-334448f3c1cb", "stem": "The research examines ______ role of social media in shaping public opinion during election campaigns.", "options": ["a", "the", "\u2014", "an"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "'The role of X in Y' is a specific construction: the role is defined and limited by 'of social media in shaping public opinion.' Academic English frequently uses 'the' before nouns that are specified by a following 'of' phrase. This is a pattern worth internalising for academic writing.", "distractor_traps": {"0": "'A role' \u2014 implies one of several possible roles, which weakens the academic precision of the sentence", "2": "No article \u2014 in academic writing, 'role of X in Y' nearly always requires 'the' because the 'of' phrase makes it specific", "3": "'An' \u2014 wrong because 'role' starts with a consonant sound"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "0b63ab49-084d-4b61-b527-9c2ff2f8ef22", "stem": "______ elderly are disproportionately affected by cuts to public healthcare funding.", "options": ["An", "The", "\u2014", "Some"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Articles", "cefr_difficulty": "C1", "irt_a_param": 1.6, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "'The + adjective' can refer to an entire group of people: the elderly, the homeless, the unemployed, the young. This is formal usage \u2014 it means 'elderly people as a category.' Without 'the,' the adjective has no noun function. This pattern is common in academic and policy writing.", "distractor_traps": {"0": "'An elderly' \u2014 would need a noun after it ('an elderly person'); 'elderly' alone as a noun requires 'the'", "2": "No article \u2014 'elderly' without 'the' is just an adjective floating without a noun", "3": "'Some elderly' \u2014 would need a noun ('some elderly people'); also shifts meaning from the category to an unspecified subset"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "7340ab83-8193-4306-9929-9670f4c3d661", "stem": "The meeting is ______ Monday at 10 o'clock.", "options": ["in", "on", "at", "to"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.6, "irt_c_param": 0.25, "explanation_text": "Days of the week use 'on': on Monday, on Friday, on Saturday. Times use 'at': at 10 o'clock. Months and years use 'in': in March, in 2026. This on/at/in pattern for time is one of the most useful to memorise.", "distractor_traps": {"0": "'In' \u2014 used for months, years, and longer periods, not specific days", "2": "'At' \u2014 used for clock times and specific points ('at noon'), not days", "3": "'To' \u2014 doesn't indicate time position"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "68e9bacb-448b-417b-ac06-ea654a10978c", "stem": "She has lived in Ho Chi Minh City ______ 2019.", "options": ["for", "since", "from", "during"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.2, "irt_c_param": 0.22, "explanation_text": "'Since' is used with a specific starting point (2019, Monday, January). 'For' is used with a duration (three years, two weeks). She has lived there since 2019 = from 2019 until now. 'For' would need a time period: 'for five years.'", "distractor_traps": {"0": "'For' \u2014 requires a duration ('for five years'), not a starting point", "2": "'From' \u2014 needs a matching 'to' ('from 2019 to 2024'), and implies the action ended", "3": "'During' \u2014 describes when within a period ('during the summer'), not a starting point"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "2c2112e6-b4d3-45da-be64-5f627398d066", "stem": "The company's success depends ______ the quality of its customer service.", "options": ["in", "on", "for", "with"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.1, "irt_c_param": 0.2, "explanation_text": "'Depend on' is a fixed verb-preposition combination. English has many of these: rely on, consist of, result in, contribute to. They must be memorised because the preposition choice doesn't follow a logical rule.", "distractor_traps": {"0": "'Depend in' \u2014 L1 transfer from Vietnamese 'ph\u1ee5 thu\u1ed9c v\u00e0o' where 'v\u00e0o' can map to several English prepositions", "2": "'Depend for' \u2014 confused with 'responsible for'", "3": "'Depend with' \u2014 no such combination exists"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "69f9be8a-f70c-40d4-8bdd-ca8918183c5b", "stem": "She apologised ______ being late to the meeting and promised it wouldn't happen again.", "options": ["about", "for", "of", "to"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "'Apologise for' is the correct combination. You apologise for something (the action) and apologise to someone (the person). Here, 'for being late' describes what she apologised about.", "distractor_traps": {"0": "'About' \u2014 commonly used with 'sorry about,' which makes 'apologise about' feel natural, but it's non-standard", "2": "'Of' \u2014 confused with 'accused of' or 'aware of'", "3": "'To' \u2014 'apologise to' takes a person, not an action"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "51e103a7-c5a3-4d51-8499-9ca0f810dd99", "stem": "The report draws attention ______ the gap between policy intention and actual implementation in rural areas.", "options": ["at", "for", "on", "to"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "'Draw attention to' is a fixed academic collocation meaning to highlight or emphasise something. In academic and professional writing, these fixed phrases ('in accordance with,' 'with regard to,' 'in response to') are essential and must be learned as complete units.", "distractor_traps": {"0": "'Draw attention at' \u2014 confused with 'look at'", "1": "'Draw attention for' \u2014 confused with 'call for attention'", "2": "'Draw attention on' \u2014 confused with 'focus on'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "b30f2e3d-f1d1-4280-b747-c402a7e194ec", "stem": "The policy was implemented ______ the objections of several senior advisors, which later proved to be well-founded.", "options": ["against", "despite", "notwithstanding", "regardless"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Prepositions", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.4, "irt_c_param": 0.15, "explanation_text": "'Notwithstanding' is a formal preposition meaning 'despite' or 'in spite of.' It's followed directly by a noun phrase ('notwithstanding the objections'). 'Despite' also works grammatically, but 'notwithstanding' is specifically tested at C1 for its formal register. 'Regardless' needs 'of' to function as a preposition.", "distractor_traps": {"0": "'Against' \u2014 means in opposition to, but doesn't carry the concessive meaning of 'despite/even though'", "1": "'Despite' \u2014 semantically correct and grammatically fine, but this item specifically tests whether learners recognise 'notwithstanding' as the more formal equivalent in academic/legal writing", "3": "'Regardless' \u2014 needs 'of' ('regardless of the objections') to be grammatically correct as a preposition"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "9bdb8316-46cc-409c-a016-b2fdfd0fe0d4", "stem": "You ______ have told me earlier \u2014 I could have helped you with the project.", "options": ["must", "should", "would", "can"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Modal Verbs", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0, "irt_c_param": 0.2, "explanation_text": "'Should have + past participle' expresses regret or criticism about the past \u2014 something that was the right thing to do but didn't happen. 'You should have told me' means: telling me was the right thing, but you didn't do it. 'Must have' would mean certainty about the past, not regret.", "distractor_traps": {"0": "'Must have told' \u2014 expresses certainty ('I'm sure you told me'), not criticism about a missed action", "2": "'Would have told' \u2014 part of a conditional ('would have told me if...'), not a standalone criticism", "3": "'Can have told' \u2014 not a natural English construction"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "2e23efcc-5a57-4f40-b15c-cd263d829e51", "stem": "The restaurant ______ be good \u2014 there's always a long queue outside.", "options": ["can", "must", "should", "would"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Modal Verbs", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.1, "irt_c_param": 0.22, "explanation_text": "'Must' here expresses logical deduction \u2014 you're drawing a conclusion from evidence (the long queue). 'It must be good' means 'based on what I can see, I'm fairly certain it's good.' This is different from 'must' meaning obligation ('you must arrive by 9').", "distractor_traps": {"0": "'Can be good' \u2014 expresses possibility, not deduction from evidence", "2": "'Should be good' \u2014 expresses expectation, weaker than the certainty the evidence supports", "3": "'Would be good' \u2014 conditional/hypothetical, not a conclusion from evidence"}, "goal_tags": ["A", "C", "D", "E"]}, {"item_id": "ee870495-9023-44cb-969f-cc5f50ecc4ae", "stem": "The results ______ have been affected by the unusually small sample size, though the authors do not acknowledge this limitation.", "options": ["should", "might", "must", "will"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Modal Verbs", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'Might have been affected' expresses possibility about the past \u2014 the small sample size may or may not have influenced the results. 'Must have' would be too certain (we don't know for sure), and 'should have' implies criticism rather than uncertainty.", "distractor_traps": {"0": "'Should have been affected' \u2014 implies obligation or expectation, not possibility", "2": "'Must have been affected' \u2014 too certain; the sentence hedges with 'though the authors do not acknowledge,' suggesting this is a possibility, not a certainty", "3": "'Will have been affected' \u2014 future perfect, wrong time frame entirely"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "d1d1d7af-43be-4e9f-a7d1-686907faaf27", "stem": "The ambassador's remarks, which ______ have been intended as diplomatic reassurance, were widely interpreted as a veiled threat.", "options": ["may well", "should", "would rather", "had better"], "correct_choice": 0, "skill": "Grammar", "sub_skill": "Modal Verbs", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "'May well have been intended' expresses concessive possibility \u2014 it's quite likely the intention was diplomatic, but the effect was the opposite. 'May well' is stronger than 'may' alone and carries a tone of 'even if this is true, it doesn't matter because...' This is sophisticated hedging common in political and academic analysis.", "distractor_traps": {"1": "'Should have been intended' \u2014 implies the remarks failed at their purpose (criticism), but the sentence is analysing perception, not judging intention", "2": "'Would rather have been intended' \u2014 'would rather' expresses preference, not possibility", "3": "'Had better have been intended' \u2014 'had better' is a warning about consequences, not an analysis of possibility"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "10fac7d4-f5bb-4cb4-8d58-6316ef44dae6", "stem": "Not only ______ the deadline, but she also delivered work of exceptional quality.", "options": ["she met", "she did meet", "did she meet", "has she met"], "correct_choice": 2, "skill": "Grammar", "sub_skill": "Sentence Structure", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.2, "irt_c_param": 0.2, "explanation_text": "'Not only' at the start of a clause triggers subject-verb inversion. Normal order: 'She met the deadline.' Inverted: 'Not only did she meet the deadline.' The auxiliary 'did' moves before the subject. This pattern makes sentences more emphatic and is common in formal writing.", "distractor_traps": {"0": "Normal word order \u2014 correct meaning but ignores the inversion required by 'not only' at the start", "1": "Emphatic 'did' but without inversion \u2014 'she did meet' keeps normal subject-verb order", "3": "Present perfect with inversion \u2014 wrong tense for a completed past event paired with 'delivered'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "ed56206b-c925-4c91-85c4-7fd190534c33", "stem": "The proposal, ______ had taken the team six months to develop, was rejected in under five minutes.", "options": ["that", "which", "what", "it"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Sentence Structure", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "The clause between the commas is a non-defining relative clause \u2014 it adds extra information about the proposal. Non-defining clauses use 'which,' not 'that.' The commas are the signal: with commas = 'which'; without commas = 'that' or 'which.'", "distractor_traps": {"0": "'That' \u2014 used in defining relative clauses (no commas), not non-defining ones", "2": "'What' \u2014 introduces noun clauses ('what he said'), not relative clauses modifying a named noun", "3": "'It' \u2014 would create a run-on sentence, not a relative clause"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "b9d75a4a-519e-48c2-a878-667e5d1888db", "stem": "______ impressive the initial results appeared, the methodology was later found to contain serious flaws.", "options": ["Despite", "Although", "However", "No matter how"], "correct_choice": 3, "skill": "Grammar", "sub_skill": "Sentence Structure", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.9, "irt_c_param": 0.18, "explanation_text": "'No matter how + adjective + subject + verb' is a concessive structure: 'no matter how impressive the results appeared.' It means 'regardless of how impressive they seemed.' 'Although' would need 'although the results appeared impressive' \u2014 different word order.", "distractor_traps": {"0": "'Despite' \u2014 needs a noun or gerund ('despite the impressive results'), not an adjective clause", "1": "'Although' \u2014 needs normal clause order ('although the results appeared impressive'), not adjective-first", "2": "'However' \u2014 can mean 'no matter how' in formal English ('however impressive'), but in modern usage this is archaic and the more natural construction is 'no matter how'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "1334812d-d906-41b8-a58b-e924098ac267", "stem": "Rarely ______ a single policy shift generated such widespread public debate across the political spectrum.", "options": ["does", "has", "had", "is"], "correct_choice": 1, "skill": "Grammar", "sub_skill": "Sentence Structure", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "Negative adverbs at the start of a sentence (rarely, never, seldom, hardly) trigger inversion. 'Rarely has a single policy shift generated...' = 'A single policy shift has rarely generated...' The present perfect 'has generated' is correct because the debate is ongoing.", "distractor_traps": {"0": "'Does' \u2014 would require base form 'generate' and present simple, which doesn't match the ongoing nature of the debate", "2": "'Had' \u2014 past perfect would imply this is before another past event, but there's no second past reference", "3": "'Is' \u2014 doesn't collocate with 'generated' and would need passive construction"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "86056459-04ba-4f22-a093-65c0a37670f1", "stem": "I need to ______ a decision about which university to attend.", "options": ["do", "make", "take", "have"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.4, "irt_c_param": 0.25, "explanation_text": "'Make a decision' is a fixed collocation. English divides 'do' and 'make' in ways that Vietnamese ('l\u00e0m') doesn't: 'make' is for creating or producing something (make a decision, make a mistake, make progress), while 'do' is for tasks and activities (do homework, do research, do business).", "distractor_traps": {"0": "L1 transfer: Vietnamese 'l\u00e0m' covers both 'do' and 'make'", "2": "'Take a decision' exists in British formal usage but is much less common and not standard for learners", "3": "'Have a decision' \u2014 not a standard English collocation"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "cb887625-845a-45cb-876a-4a7493e2ed1a", "stem": "Could you please ______ me a favour and send this email?", "options": ["make", "do", "give", "take"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.2, "irt_c_param": 0.25, "explanation_text": "'Do someone a favour' is the correct collocation. This is one of the 'do' collocations: do a favour, do your best, do the dishes, do someone a service. These must be memorised as pairs.", "distractor_traps": {"0": "'Make a favour' \u2014 L1 transfer: Vietnamese 'l\u00e0m \u01a1n' maps more naturally to 'make'", "2": "'Give a favour' \u2014 logical but not how English works", "3": "'Take a favour' \u2014 not a standard collocation"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "0be96527-1ac5-45f1-9dd9-52755e46a7c1", "stem": "The new employee made a very good ______ on her first day at the office.", "options": ["impression", "expression", "impact", "opinion"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.2, "irt_c_param": 0.22, "explanation_text": "'Make an impression' is the correct collocation \u2014 it means to create a particular feeling or image in other people's minds. 'Make an impact' exists but means to have a significant effect, which is too strong for a first day at work.", "distractor_traps": {"1": "'Expression' sounds similar to 'impression' \u2014 a common confusion for learners", "2": "'Impact' \u2014 'make an impact' exists but means something much stronger and broader", "3": "'Opinion' \u2014 you 'form' or 'have' an opinion, not 'make' one in this context"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "c17d2a1e-cc01-49da-8097-c7cf83aae747", "stem": "The government plans to ______ measures to reduce air pollution in major cities.", "options": ["do", "implement", "make", "set"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "'Implement measures' is the standard formal collocation. 'Implement' means to put a plan or decision into action. In academic and news English, 'implement' pairs with: measures, policies, strategies, changes, reforms.", "distractor_traps": {"0": "'Do measures' \u2014 L1 transfer from Vietnamese 'th\u1ef1c hi\u1ec7n' which could map to 'do'", "2": "'Make measures' \u2014 sounds plausible but 'make' doesn't pair with 'measures' in standard English", "3": "'Set measures' \u2014 'set' pairs with 'standards,' 'goals,' 'targets' \u2014 not 'measures'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "665d8d09-42a2-4227-90b2-2002991daa37", "stem": "We need to ______ advantage of the low prices before they go up again.", "options": ["make", "get", "take", "have"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0, "irt_c_param": 0.22, "explanation_text": "'Take advantage of' is a fixed three-word collocation meaning to use an opportunity. The full pattern: take advantage of + noun/gerund. Similar fixed patterns: take part in, take care of, take responsibility for.", "distractor_traps": {"0": "'Make advantage' \u2014 not a standard English collocation", "1": "'Get advantage' \u2014 not standard; confused with 'get ahead' or 'gain an advantage'", "3": "'Have advantage' \u2014 'have an advantage' exists (meaning to possess one), but 'have advantage of' as a phrasal expression doesn't"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "a6e2ee98-fb89-4392-91b9-fe23db6f983d", "stem": "The findings ______ serious doubts about the effectiveness of the current approach to urban planning.", "options": ["make", "give", "raise", "put"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "'Raise doubts' is the academic collocation. In formal English, you raise doubts, raise concerns, raise questions, raise awareness, and raise issues. 'Raise' in this sense means to bring something to attention \u2014 not to lift physically.", "distractor_traps": {"0": "'Make doubts' \u2014 not a standard collocation in any register", "1": "'Give doubts' \u2014 informal and non-standard; you can 'give rise to doubts' but not 'give doubts'", "3": "'Put doubts' \u2014 not standard; you can 'cast doubt' but not 'put doubts'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "2a656987-d391-45db-8b8f-1c67dedc2928", "stem": "The study ______ light on why some communities are more resilient to natural disasters than others.", "options": ["throws", "puts", "sheds", "gives"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'Shed light on' means to make something clearer or easier to understand. This is a very common academic collocation: 'The research sheds light on...' is a standard way to introduce findings. 'Throw light on' exists in British English but is less common.", "distractor_traps": {"0": "'Throws light on' \u2014 exists in British English but is less standard in academic writing than 'sheds'", "1": "'Puts light on' \u2014 not a standard collocation", "3": "'Gives light on' \u2014 not a standard collocation; confused with 'gives insight into'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "465d3940-b616-409f-979b-89e1922b1fbe", "stem": "The CEO's decision to resign came ______ the wake of a financial scandal that had damaged the company's reputation.", "options": ["on", "at", "in", "by"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "'In the wake of' is a fixed expression meaning 'following' or 'as a result of' \u2014 usually something significant or disruptive. Originally nautical (the 'wake' is the trail of water behind a ship), it now means in the aftermath of an event.", "distractor_traps": {"0": "'On the wake' \u2014 not a standard English expression", "1": "'At the wake' \u2014 a 'wake' can be a funeral gathering, creating a confusing alternative meaning", "3": "'By the wake' \u2014 not a standard collocation"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "da1aa99c-b380-4d35-b422-ff9e806073c0", "stem": "The committee reached a decision that, while not universally popular, ______ a reasonable compromise between competing interests.", "options": ["struck", "hit", "made", "found"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "'Strike a compromise' is the formal collocation meaning to achieve a balance between opposing positions. You also 'strike a deal,' 'strike a balance,' and 'strike an agreement.' This is distinct from the physical meaning of 'strike.'", "distractor_traps": {"1": "'Hit a compromise' \u2014 'hit' is too informal and aggressive for this context; you can 'hit a snag' but not 'hit a compromise'", "2": "'Made a compromise' \u2014 grammatically possible but less precise; 'made a compromise' is more general, while 'struck a compromise' is the established formal expression", "3": "'Found a compromise' \u2014 acceptable in general English but less idiomatic than 'struck' in formal/academic writing"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "55b1fd7e-0ba3-4b1c-b3b6-3cd133106ddb", "stem": "The evidence presented at the hearing was ______ circumstantial and failed to establish a direct link between the defendant and the crime.", "options": ["deeply", "highly", "purely", "strongly"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Collocations", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "'Purely circumstantial' is the standard legal and academic collocation. 'Purely' means entirely or completely, and it collocates with: circumstantial, hypothetical, speculative, academic, coincidental. 'Highly circumstantial' sounds plausible but is non-standard.", "distractor_traps": {"0": "'Deeply circumstantial' \u2014 'deeply' collocates with emotions and qualities (deeply concerned, deeply flawed), not with 'circumstantial'", "1": "'Highly circumstantial' \u2014 'highly' collocates with adjectives like 'unlikely,' 'effective,' 'competitive' \u2014 but not 'circumstantial'", "3": "'Strongly circumstantial' \u2014 'strongly' modifies verbs and some adjectives ('strongly disagree,' 'strongly opposed'), not 'circumstantial'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "ba15d27f-1b69-4e94-8707-0bda62e4e773", "stem": "Please ______ the light. It's too dark in here.", "options": ["turn on", "turn off", "turn up", "turn down"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.5, "irt_c_param": 0.25, "explanation_text": "'Turn on' means to start a device or make something work. 'It's too dark' is the clue \u2014 the light needs to start working. 'Turn off' means stop, 'turn up' means increase, and 'turn down' means decrease.", "distractor_traps": {"1": "'Turn off' \u2014 opposite of what's needed; the darkness means the light is already off", "2": "'Turn up' \u2014 means increase (volume, heat), but a light is either on or off in most contexts", "3": "'Turn down' \u2014 means decrease or reject"}, "goal_tags": ["A", "C", "D", "E"]}, {"item_id": "1482b729-d172-4866-8e47-61635bb4da0f", "stem": "The meeting has been ______ until next Thursday because the director is travelling.", "options": ["put off", "put on", "put up", "put away"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.1, "irt_c_param": 0.22, "explanation_text": "'Put off' means to postpone or delay. 'Until next Thursday' confirms the meeting is being moved to a later date. 'Put on' means to wear or stage an event. 'Put up' means to accommodate someone or display something. 'Put away' means to store.", "distractor_traps": {"1": "'Put on' \u2014 means to organise/stage an event or to wear clothing, not to delay it", "2": "'Put up' \u2014 means to provide accommodation or to erect/display something", "3": "'Put away' \u2014 means to store or tidy, unrelated to scheduling"}, "goal_tags": ["A", "C", "E"]}, {"item_id": "3a36c5e4-2b44-491b-9511-bfc4b85b9f00", "stem": "She promised to ______ the report before Friday so we could review it over the weekend.", "options": ["hand over", "hand in", "hand out", "hand down"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0.1, "irt_c_param": 0.22, "explanation_text": "'Hand in' means to submit work to someone in authority \u2014 a report to a boss, homework to a teacher. 'Hand over' means to transfer control. 'Hand out' means to distribute. 'Hand down' means to pass to the next generation.", "distractor_traps": {"0": "'Hand over' \u2014 means to transfer or surrender, not to submit work", "2": "'Hand out' \u2014 means to distribute copies to many people", "3": "'Hand down' \u2014 means to pass traditions, possessions, or legal decisions to the next generation or lower level"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "127e9434-3454-40fd-abee-fc09c64eee6d", "stem": "I was so tired that I ______ asleep during the lecture.", "options": ["fell", "felt", "dropped", "went"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "B1", "irt_a_param": 1.1, "irt_b_param": -0.3, "irt_c_param": 0.22, "explanation_text": "'Fall asleep' is the natural English expression for the moment of going to sleep, especially unintentionally. 'Go to sleep' exists but requires 'to' ('went to sleep'). 'Fell asleep' captures the involuntary, gradual nature of falling into sleep.", "distractor_traps": {"1": "'Felt asleep' \u2014 'felt' (from 'feel') sounds very similar to 'fell' and is a common pronunciation-based error", "2": "'Dropped asleep' \u2014 'dropped off' (to sleep) exists informally, but 'dropped asleep' doesn't", "3": "'Went asleep' \u2014 'went to sleep' works, but 'went asleep' without 'to' is non-standard"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "91c51a53-fd84-43ed-90d3-ef49cbfde861", "stem": "After months of investigation, the police finally ______ the source of the illegal activity.", "options": ["tracked down", "ran down", "broke down", "turned down"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "'Track down' means to find something or someone after a thorough search. It implies persistent effort over time \u2014 exactly matching 'after months of investigation.' 'Run down' can mean to review a list or to physically deteriorate. 'Break down' means to analyse or to stop functioning.", "distractor_traps": {"1": "'Ran down' \u2014 can mean 'reviewed' or 'pursued,' which is close enough to be confusing, but doesn't mean 'found after searching'", "2": "'Broke down' \u2014 means to analyse into parts or to stop functioning, not to discover", "3": "'Turned down' \u2014 means to reject or decrease volume"}, "goal_tags": ["A", "C", "D", "E"]}, {"item_id": "db809098-01b7-416c-8c44-c8b635686501", "stem": "The charity's annual report ______ the need for more volunteers in rural healthcare facilities.", "options": ["brought out", "brought up", "brought about", "brought forward"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'Bring up' means to raise or mention a topic for discussion. In formal contexts, reports and studies 'bring up' issues or concerns. 'Bring about' means to cause something to happen. 'Bring out' means to release or reveal. 'Bring forward' means to reschedule earlier.", "distractor_traps": {"0": "'Brought out' \u2014 means to reveal or release (a product), not to raise a topic", "2": "'Brought about' \u2014 means to cause something, not to mention or highlight it", "3": "'Brought forward' \u2014 means to move a date/event earlier"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "6a4886fc-fa33-4ad9-8460-ee7a8157393d", "stem": "The government's attempt to ______ public criticism by releasing the data selectively only intensified the backlash.", "options": ["fend off", "put off", "call off", "write off"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "'Fend off' means to defend against or deflect an attack, criticism, or unwanted attention. It implies active resistance against something threatening. The government tried to deflect criticism, but the attempt backfired. 'Put off' means to delay. 'Call off' means to cancel. 'Write off' means to dismiss as worthless.", "distractor_traps": {"1": "'Put off' \u2014 means to postpone, which doesn't match defending against criticism", "2": "'Call off' \u2014 means to cancel an event or activity, not to deflect criticism", "3": "'Write off' \u2014 means to dismiss something as a loss, which is close but lacks the defensive, active quality of 'fend off'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "2f351160-35cb-4c79-a084-12bece690484", "stem": "The negotiations ______ when both sides refused to make concessions on the territorial dispute.", "options": ["fell through", "fell apart", "fell behind", "fell out"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Phrasal Verbs", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "'Fell apart' means to collapse or disintegrate \u2014 used for plans, relationships, negotiations, and structures that completely break down. 'Fell through' is very close in meaning but typically describes plans or deals that fail to materialise rather than active collapse. The key distinction: 'fell apart' suggests disintegration; 'fell through' suggests failure to complete.", "distractor_traps": {"0": "'Fell through' \u2014 means a plan or deal failed to happen, very close but implies passive failure rather than active collapse from conflict", "2": "'Fell behind' \u2014 means to lag or not keep pace, unrelated to collapse", "3": "'Fell out' \u2014 means to quarrel; the people fell out, but the negotiations fell apart"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "0ee11595-81b3-4b70-8682-030dbe906148", "stem": "The film was really ______. I almost fell asleep in the cinema.", "options": ["boring", "bored", "bore", "boredom"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "A2", "irt_a_param": 1, "irt_b_param": -1.3, "irt_c_param": 0.25, "explanation_text": "'-ing' adjectives describe the thing that causes a feeling: the film was boring (it caused boredom). '-ed' adjectives describe the person feeling it: I was bored. This -ing/-ed distinction doesn't exist in Vietnamese, making it one of the most important patterns to master.", "distractor_traps": {"1": "'Bored' \u2014 describes the person's feeling, not the film's quality; 'the film was bored' would mean the film felt boredom", "2": "'Bore' \u2014 the verb form, not an adjective", "3": "'Boredom' \u2014 a noun; grammatically wrong after 'was really'"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "ef3f5502-1a9d-452a-b88d-829b4c85570e", "stem": "The ______ of the internet has changed the way people communicate around the world.", "options": ["develop", "development", "developing", "developed"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.2, "irt_c_param": 0.22, "explanation_text": "After 'the,' we need a noun. 'Development' is the noun form of 'develop.' Common noun-forming suffixes: -ment (development, improvement), -tion (education, information), -ness (happiness, darkness), -ity (possibility, electricity).", "distractor_traps": {"0": "'Develop' \u2014 verb form; can't follow 'the' as the subject of a sentence", "2": "'Developing' \u2014 adjective/present participle; 'the developing of the internet' is non-standard (would need 'the developing internet')", "3": "'Developed' \u2014 adjective/past participle; 'the developed' would refer to developed countries/things, not the process"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "b40f0fd6-efd3-4912-95af-e7ff04249ac1", "stem": "It is ______ to compare the two studies directly because they used different methodologies.", "options": ["meaning", "meaningless", "meaningful", "meaningfully"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "'It is + adjective + to' is the pattern. 'Meaningless' (adjective) means without meaning or purpose. The '-less' suffix creates adjectives meaning 'without': meaningless, homeless, careless, hopeless. The sentence says comparison is pointless because the methodologies differ.", "distractor_traps": {"0": "'Meaning' \u2014 noun or verb form, doesn't fit the 'it is ___ to' adjective slot", "2": "'Meaningful' \u2014 opposite meaning: would say the comparison is valuable, contradicting 'different methodologies'", "3": "'Meaningfully' \u2014 adverb form, not an adjective"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "5188cdf2-57df-43d3-9fdc-c4f504752e55", "stem": "The ______ of the witness's account was called into question when contradictory evidence emerged.", "options": ["reliable", "reliability", "reliably", "reliance"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "'The ______ of X' requires a noun. 'Reliability' is the noun form of 'reliable.' The suffix '-ility' (or '-ability') converts adjectives into abstract nouns: reliable \u2192 reliability, available \u2192 availability, possible \u2192 possibility. 'Reliance' is a different noun meaning 'dependence on.'", "distractor_traps": {"0": "'Reliable' \u2014 adjective, can't fill a noun position after 'the'", "2": "'Reliably' \u2014 adverb form", "3": "'Reliance' \u2014 a real noun but wrong meaning: 'reliance' means dependence, not trustworthiness"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "b99fa6b8-159e-45c2-82f8-cb0544669ab9", "stem": "The report's conclusions were ______ optimistic given the limited scope of the data collected.", "options": ["exceed", "exceeding", "exceedingly", "excessive"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'Exceedingly' is an adverb modifying the adjective 'optimistic.' Adverbs modify adjectives: exceedingly optimistic, remarkably accurate, deeply concerned. 'Excessive' is an adjective that would need to replace 'optimistic,' not modify it.", "distractor_traps": {"0": "'Exceed' \u2014 verb form, can't modify an adjective", "1": "'Exceeding' \u2014 present participle/adjective; 'exceeding optimistic' is archaic and non-standard in modern English", "3": "'Excessive' \u2014 adjective; 'excessive optimistic' puts two adjectives together without coordination"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "e91b80ab-13b1-48e7-beeb-9ae379255a89", "stem": "The author's ______ of the data was later criticised for omitting key variables that would have altered the conclusions significantly.", "options": ["interpret", "interpretation", "interpretive", "interpretative"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Word Formation", "cefr_difficulty": "C1", "irt_a_param": 1.6, "irt_b_param": 1.2, "irt_c_param": 0.15, "explanation_text": "'The author's ______ of the data' requires a noun (possessive + noun + of). 'Interpretation' is the correct noun. The C1 challenge here is distinguishing between 'interpretive' and 'interpretative' (both adjectives) and 'interpretation' (noun). All three look similar but serve different grammatical functions.", "distractor_traps": {"0": "'Interpret' \u2014 verb form, can't follow a possessive", "2": "'Interpretive' \u2014 adjective ('interpretive dance,' 'interpretive framework'), wrong word class", "3": "'Interpretative' \u2014 adjective variant of 'interpretive,' still wrong word class for this position"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "946bb083-593c-4d44-b483-bfd44e173925", "stem": "The study was ______ to determine whether exercise improves sleep quality in older adults.", "options": ["conducted", "guided", "directed", "managed"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0, "irt_c_param": 0.22, "explanation_text": "'Conduct a study/research/experiment' is the standard academic collocation. In academic English, studies are 'conducted,' not 'done' or 'made.' This word appears frequently in IELTS reading passages.", "distractor_traps": {"1": "'Guided' \u2014 means to lead or direct a person, not to carry out research", "2": "'Directed' \u2014 means to manage or point towards; you 'direct' a film or a team, not a study", "3": "'Managed' \u2014 means to handle or oversee operations, not to perform research"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "ddfe5eaf-6323-4d1b-a2aa-8867ee7a46c8", "stem": "There is ______ evidence that regular reading improves vocabulary acquisition in second-language learners.", "options": ["considerate", "considerable", "considered", "considering"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.2, "irt_c_param": 0.2, "explanation_text": "'Considerable evidence' means a large amount of evidence. 'Considerable' = large in amount or significant. 'Considerate' means thoughtful towards others \u2014 a completely different word. This is a classic confusion pair for learners.", "distractor_traps": {"0": "'Considerate' \u2014 means kind/thoughtful towards people; it describes behaviour, not quantity", "2": "'Considered' \u2014 means carefully thought about ('a considered opinion'), not large in amount", "3": "'Considering' \u2014 a preposition/conjunction ('considering the evidence'), not an adjective modifying 'evidence'"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "fc7982e9-5f53-4cd6-84c2-991ed032e82c", "stem": "The researchers ______ that cultural factors play a more significant role in language acquisition than previously thought.", "options": ["concluded", "resulted", "achieved", "obtained"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.5, "irt_c_param": 0.18, "explanation_text": "'Conclude that...' is the standard academic verb for stating a research finding. You 'conclude' a study, 'conclude' that something is the case. 'Result' doesn't take a 'that' clause in standard usage ('resulted in,' not 'resulted that').", "distractor_traps": {"1": "'Resulted' \u2014 requires 'in' + noun, not 'that' + clause; 'resulted that' is non-standard", "2": "'Achieved' \u2014 means to accomplish a goal, not to reach a research conclusion", "3": "'Obtained' \u2014 means to get or acquire something physical or concrete, not to reach an intellectual conclusion"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "e6db1aa6-3643-4a5a-9e29-4262b3a98efe", "stem": "The government has ______ a new set of regulations aimed at reducing carbon emissions by thirty per cent over the next decade.", "options": ["introduced", "produced", "presented", "demonstrated"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "'Introduce regulations/legislation/policies' is the standard collocation for when a government creates new rules. 'Produce' means to create a physical product. 'Present' means to show or display. 'Demonstrate' means to prove or show through evidence.", "distractor_traps": {"1": "'Produced' \u2014 means to manufacture or create something tangible", "2": "'Presented' \u2014 means to show to an audience; you present findings, not regulations", "3": "'Demonstrated' \u2014 means to prove or show evidence of something"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "81ece695-48c3-4c91-b998-ea0cfa05c083", "stem": "The theory has been largely ______ by recent empirical evidence, though a small number of researchers continue to defend it.", "options": ["discredited", "discarded", "discontinued", "discouraged"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "'Discredited' means shown to be false or unreliable through evidence. A theory is 'discredited' when evidence undermines it. 'Discarded' means thrown away \u2014 used for objects or ideas that are abandoned, not proven wrong. The distinction matters in academic writing.", "distractor_traps": {"1": "'Discarded' \u2014 means abandoned or thrown away, which is stronger and more final than 'discredited'; also lacks the evidential meaning", "2": "'Discontinued' \u2014 means stopped being produced or available, used for products or services, not theories", "3": "'Discouraged' \u2014 means advised against or disheartened, not shown to be false"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "12be6b94-231c-48ac-a5b7-ca29b63cb796", "stem": "The author ______ a distinction between voluntary migration and forced displacement, arguing that existing policy frameworks conflate the two.", "options": ["makes", "draws", "takes", "pulls"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Academic Word List", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "'Draw a distinction' is the precise academic collocation. In scholarly writing, you 'draw' distinctions, parallels, and comparisons. 'Make a distinction' is acceptable in general English but less precise. At C1, the expectation is to know the more academic form.", "distractor_traps": {"0": "'Makes a distinction' \u2014 acceptable in everyday English but less precise in academic register", "2": "'Takes a distinction' \u2014 not a standard English collocation", "3": "'Pulls a distinction' \u2014 not a standard English collocation"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "6502ac0b-67f2-4255-a6bf-866f22fe4da0", "stem": "I haven't made up my ______ yet about which course to take next semester.", "options": ["brain", "head", "mind", "thought"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Idioms", "cefr_difficulty": "B1", "irt_a_param": 1.1, "irt_b_param": -0.2, "irt_c_param": 0.22, "explanation_text": "'Make up your mind' is a common idiom meaning to decide. The full expression is fixed: make up + possessive + mind. You can't substitute 'brain,' 'head,' or 'thought' \u2014 even though they're all related to thinking.", "distractor_traps": {"0": "'Brain' \u2014 related concept but wrong idiom; 'rack your brain' exists but 'make up your brain' doesn't", "1": "'Head' \u2014 'make up your head' is a direct translation error from some L1s", "3": "'Thought' \u2014 'make up your thought' doesn't exist as an idiom"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "4136913f-4d28-4388-a735-2f69e8cafe82", "stem": "Learning a new language is difficult, but don't give ______. You'll get better with practice.", "options": ["out", "away", "in", "up"], "correct_choice": 3, "skill": "Vocabulary", "sub_skill": "Idioms", "cefr_difficulty": "B1", "irt_a_param": 1.1, "irt_b_param": -0.3, "irt_c_param": 0.22, "explanation_text": "'Give up' means to stop trying or to surrender. It's one of the most essential phrasal verb idioms in English. 'Give in' means to surrender to someone's demands. 'Give out' means to distribute or to stop working. 'Give away' means to donate or reveal.", "distractor_traps": {"0": "'Give out' \u2014 means to distribute or exhaust, not to quit trying", "1": "'Give away' \u2014 means to donate or reveal a secret", "2": "'Give in' \u2014 means to yield to pressure from someone else, slightly different from giving up entirely"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "c657141f-8d0f-4a55-9416-bc54758aa017", "stem": "The new regulations are a ______ in the right direction, though much more needs to be done to address the underlying problem.", "options": ["step", "walk", "move", "jump"], "correct_choice": 0, "skill": "Vocabulary", "sub_skill": "Idioms", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.5, "irt_c_param": 0.18, "explanation_text": "'A step in the right direction' is a fixed idiom meaning a positive but small improvement. The idiom implies progress that is welcome but insufficient. 'Move in the right direction' is close but less idiomatic.", "distractor_traps": {"1": "'Walk' \u2014 not part of this fixed expression", "2": "'Move' \u2014 'a move in the right direction' is occasionally used but 'step' is the standard, expected form", "3": "'Jump' \u2014 would imply a large, sudden change, which contradicts 'though much more needs to be done'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "33215de0-c020-4068-a20f-a212e51732a7", "stem": "The company has been ______ hot water with regulators over its failure to comply with data protection laws.", "options": ["under", "on", "in", "at"], "correct_choice": 2, "skill": "Vocabulary", "sub_skill": "Idioms", "cefr_difficulty": "B2", "irt_a_param": 1.4, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "'In hot water' is an idiom meaning in trouble or facing criticism. The full expression: 'be in hot water' or 'get into hot water.' It always uses 'in' \u2014 no other preposition works with this idiom.", "distractor_traps": {"0": "'Under hot water' \u2014 logical (under pressure), but not the fixed expression", "1": "'On hot water' \u2014 not a standard idiom", "3": "'At hot water' \u2014 not a standard idiom"}, "goal_tags": ["A", "C", "D", "E"]}, {"item_id": "92857966-cd52-4aad-a99c-5663d3afa2e6", "stem": "The minister's statement was a thinly ______ attempt to shift public attention away from the scandal.", "options": ["covered", "veiled", "hidden", "masked"], "correct_choice": 1, "skill": "Vocabulary", "sub_skill": "Idioms", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.4, "irt_c_param": 0.15, "explanation_text": "'Thinly veiled' is a fixed collocation meaning barely disguised \u2014 the true intention is almost visible beneath the surface. 'Thinly disguised' also exists, but 'thinly veiled' is the most established form in formal English. 'Masked' and 'hidden' don't collocate with 'thinly' in standard usage.", "distractor_traps": {"0": "'Thinly covered' \u2014 not a standard English collocation", "2": "'Thinly hidden' \u2014 not a standard collocation; 'hidden' doesn't naturally pair with 'thinly'", "3": "'Thinly masked' \u2014 rare and non-standard compared to 'thinly veiled'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "673a0953-dfc8-45db-b06b-5ee03a9d347f", "stem": "Read the text and answer the question.\n\n\"The caf\u00e9 was completely empty when we arrived at 3pm. By 3:30, every table was taken and people were waiting at the door.\"\n\nWhat can we understand from this text?", "options": ["The caf\u00e9 is always busy.", "The caf\u00e9 became very popular very quickly that afternoon.", "The caf\u00e9 has bad service.", "The writer didn't enjoy the caf\u00e9."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.4, "irt_c_param": 0.25, "explanation_text": "The text tells us two things: the caf\u00e9 was empty at 3pm, and full by 3:30. The change happened quickly (30 minutes). We can infer it became popular fast that day. We can't say it's 'always' busy \u2014 we only know about one afternoon.", "distractor_traps": {"0": "'Always busy' \u2014 overgeneralises from one instance; we only know about this one visit", "2": "Bad service \u2014 nothing in the text mentions service quality", "3": "Didn't enjoy \u2014 no information about the writer's feelings"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "fe0025f4-a9fa-49e1-9f0f-493e8f9d29d9", "stem": "Read the text and answer the question.\n\n\"My neighbour always smiles and says good morning. Last week, she brought me soup when I was ill. Yesterday, she helped me carry my shopping upstairs.\"\n\nWhat is the writer's neighbour like?", "options": ["She is a doctor.", "She is a kind and helpful person.", "She is the writer's best friend.", "She wants something from the writer."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.5, "irt_c_param": 0.25, "explanation_text": "Three actions \u2014 smiling, bringing soup, carrying shopping \u2014 all point to kindness and helpfulness. We can infer this is the neighbour's character. We can't say she's a doctor (bringing soup doesn't mean medical care) or a best friend (she's described as 'neighbour').", "distractor_traps": {"0": "Bringing soup when someone is ill doesn't make someone a doctor \u2014 it's a common neighbourly act", "2": "'Best friend' \u2014 the text calls her 'my neighbour,' not 'my friend'", "3": "Cynical reading \u2014 nothing in the text suggests ulterior motives"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "601fb885-f355-4bb9-9c7d-d167a206df8e", "stem": "Read the text and answer the question.\n\n\"The company announced record profits for the third consecutive quarter. However, internal documents obtained by journalists revealed that dozens of factory workers had not been paid for overtime during the same period.\"\n\nWhat does the text suggest about the company?", "options": ["The company is very successful and treats its workers well.", "The company's profits may have come partly at the expense of its workers.", "The journalists are trying to damage the company's reputation.", "The factory workers are planning to go on strike."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0, "irt_c_param": 0.2, "explanation_text": "The text creates a contrast: record profits on one side, unpaid overtime on the other. The word 'however' signals this contrast. The inference: the profits may be connected to not paying workers properly. The text doesn't state this directly \u2014 you have to connect the two facts.", "distractor_traps": {"0": "Contradicted by the second sentence \u2014 workers weren't paid for overtime", "2": "The text doesn't evaluate the journalists' motives \u2014 it simply states what they found", "3": "A possible future consequence but nothing in the text mentions or implies a strike"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "87896eef-be14-4760-a841-b91d9f08caf5", "stem": "Read the text and answer the question.\n\n\"After twenty years of teaching, Mr. Nguyen packed his desk, said goodbye to his colleagues, and walked out of the school for the last time. He paused at the gate and looked back at the building where he had spent half his life.\"\n\nHow does Mr. Nguyen most likely feel?", "options": ["He is angry about having to leave the school.", "He is relieved that his career is finally over.", "He feels a mixture of emotions as he leaves something meaningful behind.", "He is worried about finding a new job."], "correct_choice": 2, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "'Paused at the gate and looked back' \u2014 this physical action reveals emotion. If he were simply relieved, he would walk away without stopping. If he were angry, he wouldn't look back fondly. The pause and backward glance suggest attachment and reflection. 'Half his life' reinforces how meaningful the place is to him.", "distractor_traps": {"0": "Nothing suggests anger \u2014 packing his desk and saying goodbye suggests a planned, peaceful departure", "1": "'Relieved' contradicts the pause and backward look \u2014 someone relieved doesn't linger", "3": "Nothing in the text mentions future employment or financial concern"}, "goal_tags": ["A", "D", "E"]}, {"item_id": "029be2ea-5806-4e29-9b6b-7221ff7fd7f0", "stem": "Read the text and answer the question.\n\n\"The hotel website showed bright, spacious rooms with ocean views. When the Tran family arrived, they found a small room facing the car park. The bathroom light flickered, and the air conditioning made a constant rattling noise.\"\n\nWhat does the text imply about the hotel?", "options": ["The hotel was recently renovated.", "The hotel's online presentation did not match the reality.", "The Tran family booked the wrong room by mistake.", "The hotel was full, so they were given a different room."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.1, "irt_c_param": 0.22, "explanation_text": "The text contrasts what the website showed (bright, spacious, ocean views) with what the family found (small, car park, broken fixtures). The gap between promise and reality is the core inference. The text doesn't say the family made a mistake or that the hotel was full.", "distractor_traps": {"0": "'Recently renovated' contradicts the flickering light and rattling AC \u2014 these suggest poor maintenance", "2": "The text doesn't suggest a booking error \u2014 it presents the gap as the hotel's misrepresentation", "3": "Possible but not implied \u2014 the text attributes the problem to the hotel's website being misleading, not to capacity issues"}, "goal_tags": ["A", "C", "D", "E"]}, {"item_id": "ae771d78-c2fb-4ee9-bd5f-1b1a6348f677", "stem": "Read the text and answer the question.\n\n\"The university's new admissions policy aims to increase diversity by considering applicants' socioeconomic backgrounds alongside academic performance. Critics argue that this approach undermines meritocracy, while supporters contend that academic performance itself is shaped by socioeconomic factors, making a purely grades-based system inherently biased.\"\n\nWhat position do the supporters of the policy hold?", "options": ["Academic grades are the only fair measure of student ability.", "Socioeconomic background is more important than grades.", "A grades-only system already favours privileged applicants, so additional context is needed.", "The university should eliminate academic requirements entirely."], "correct_choice": 2, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "The supporters argue that academic performance is 'shaped by socioeconomic factors,' making a grades-only system 'inherently biased.' This means grades don't reflect pure ability \u2014 they reflect privilege too. Therefore, considering socioeconomic background compensates for an existing bias, not introduces a new one.", "distractor_traps": {"0": "This is the critics' implicit position, not the supporters'", "1": "The supporters don't argue background is 'more important' \u2014 they argue it should be considered 'alongside' grades", "3": "Extreme overinterpretation \u2014 the policy adds a factor, it doesn't eliminate academic requirements"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "ddf63ee4-40b9-4192-a4ad-e3b0a525fe1c", "stem": "Read the text and answer the question.\n\n\"A recent longitudinal study found that children who were read to daily before age five scored significantly higher on reading comprehension tests at age twelve than those who were not. The researchers noted, however, that families who read to their children daily also tended to have higher household incomes and more educated parents.\"\n\nWhat concern does the second sentence raise about the study's findings?", "options": ["The study proves that reading to children guarantees better academic outcomes.", "Higher income might be the real reason for the better test scores, not the reading itself.", "The study was too short to produce meaningful results.", "Parents with higher education are better at choosing books."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B2", "irt_a_param": 1.6, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "The second sentence introduces a confounding variable: income and parent education correlate with both daily reading AND test scores. This means we can't be certain reading caused the better scores \u2014 the real cause might be the advantages that come with higher income. This is a correlation vs. causation problem.", "distractor_traps": {"0": "The opposite of what the second sentence suggests \u2014 it raises doubt about the causal claim, not confirms it", "2": "'Longitudinal' (tracking subjects over years) means the study was long-term, not short", "3": "Book selection quality isn't mentioned \u2014 the concern is about confounding economic factors"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "a9c43774-f00e-4bf1-99cd-1da2a8e54ab1", "stem": "Read the text and answer the question.\n\n\"The pharmaceutical company published a study showing its new drug reduced symptoms in 70% of patients. However, the study only included patients with mild symptoms, excluded those taking other medications, and was funded entirely by the company itself.\"\n\nWhat is the author's likely purpose in mentioning these details?", "options": ["To celebrate the drug's success rate.", "To suggest the study's conclusions may not be reliable or generalisable.", "To encourage patients to ask their doctors about the drug.", "To explain why pharmaceutical research is so expensive."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "B2", "irt_a_param": 1.6, "irt_b_param": 0.9, "irt_c_param": 0.18, "explanation_text": "The author lists three limitations: narrow patient selection, exclusion criteria, and self-funding. Each one is a reason to question the study's conclusions. The author is not stating the study is wrong \u2014 they're highlighting reasons to be sceptical. 'However' signals that what follows will challenge the initial positive claim.", "distractor_traps": {"0": "The limitations undermine the celebration, not reinforce it", "2": "Nothing in the text encourages patients to take action \u2014 it raises concerns, not recommendations", "3": "Research costs are not mentioned or implied"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "be916062-6816-4714-8827-a95bb3c2d33d", "stem": "Read the text and answer the question.\n\n\"The government's pledge to achieve carbon neutrality by 2050 has been met with cautious optimism by environmental groups. While they welcome the target, several organisations have pointed out that the pledge is accompanied by neither a detailed implementation plan nor legally binding intermediate milestones. One prominent climate scientist described the announcement as 'an excellent destination with no map and no road.'\"\n\nWhat is the climate scientist's view of the government's pledge?", "options": ["The goal is admirable but the lack of concrete planning makes it unlikely to be achieved.", "The government should set a more ambitious target than 2050.", "Environmental groups should be more supportive of the government's efforts.", "Carbon neutrality is not a realistic goal for any government."], "correct_choice": 0, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "The metaphor 'an excellent destination with no map and no road' praises the goal ('excellent destination') while criticising the lack of a plan ('no map and no road'). The scientist accepts the ambition but doubts the execution. This is sophisticated hedged criticism \u2014 agreeing with the principle while challenging the practicality.", "distractor_traps": {"1": "The scientist doesn't challenge the target's ambition \u2014 they call it 'excellent'", "2": "The scientist is not commenting on environmental groups' attitudes", "3": "Calling the destination 'excellent' shows the scientist believes the goal is worthy, not unrealistic"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "94bfd67a-f2b9-4394-a6a4-1bfb96bfe91e", "stem": "Read the text and answer the question.\n\n\"The rapid expansion of online education during the pandemic was initially celebrated as a democratisation of knowledge \u2014 anyone with an internet connection could access world-class instruction. Five years on, research consistently shows that online learning outcomes correlate strongly with students' pre-existing digital literacy, access to quiet study spaces, and stable internet connectivity \u2014 all of which are themselves correlated with socioeconomic status.\"\n\nWhat does the passage suggest about the 'democratisation of knowledge' claim?", "options": ["It has been proven correct by five years of evidence.", "It was idealistic \u2014 the same inequalities that exist offline have reproduced themselves online.", "Online education is less effective than in-person education for all students.", "Governments should invest more in internet infrastructure."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Inference", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "The passage sets up the initial claim ('democratisation') then undercuts it: success online depends on digital literacy, quiet spaces, and internet quality \u2014 all tied to socioeconomic status. The promise of equal access masks unequal outcomes. The 'democratisation' claim was naive because it assumed equal conditions, which don't exist.", "distractor_traps": {"0": "The research contradicts the claim, not supports it", "2": "The passage doesn't compare online vs. in-person \u2014 it says online outcomes vary by socioeconomic factors", "3": "Infrastructure investment might help but is not what the passage argues \u2014 it focuses on the reproduction of inequality"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "e65e489b-068c-43c7-8da7-9e9388363125", "stem": "Read the text and answer the question.\n\n\"First, preheat the oven to 180\u00b0C. Next, mix the flour and sugar in a large bowl. Then, add the eggs and butter. Finally, pour the mixture into a baking tin and bake for 25 minutes.\"\n\nWhat type of text is this?", "options": ["A news report", "A set of instructions", "A personal letter", "An advertisement"], "correct_choice": 1, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.6, "irt_c_param": 0.25, "explanation_text": "The sequencing words (first, next, then, finally) and imperative verbs (preheat, mix, add, pour, bake) are signals of instructional text. Instructions tell someone how to do something in order. The topic (baking) is secondary \u2014 the structure is the key identifier.", "distractor_traps": {"0": "News reports describe events, not give commands", "2": "Personal letters use 'I/you' and discuss personal topics, not give step-by-step commands", "3": "Advertisements try to persuade you to buy something \u2014 this text simply instructs"}, "goal_tags": ["A", "E"]}, {"item_id": "41b1fe4e-7c1b-4bab-b35b-5dbdee9c02fb", "stem": "Read the text and answer the question.\n\n\"Remote working has become increasingly common since 2020. Supporters argue that it increases productivity and improves work-life balance. Opponents, on the other hand, claim that it leads to isolation and weaker team collaboration. Recent surveys suggest that most employees prefer a hybrid model.\"\n\nHow is this text organised?", "options": ["Problem \u2192 Solution \u2192 Evaluation", "Topic introduction \u2192 Arguments for and against \u2192 Conclusion from evidence", "Chronological order from past to present", "Personal opinion supported by examples"], "correct_choice": 1, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": 0, "irt_c_param": 0.22, "explanation_text": "The text introduces a topic (remote working), presents supporters' views, then opponents' views ('on the other hand'), and concludes with survey evidence. This is a balanced argument structure \u2014 common in IELTS and academic writing. The signal words ('supporters argue,' 'opponents claim,' 'surveys suggest') reveal the structure.", "distractor_traps": {"0": "No problem is presented and no solution is proposed \u2014 it's a balanced discussion, not problem-solution", "2": "While '2020' is mentioned, the text is organised by viewpoints, not by chronological events", "3": "The text presents multiple perspectives, not a personal opinion \u2014 the author doesn't take a side"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "5b294e97-ea01-480d-ac17-5c43da9edd5e", "stem": "Read the text and answer the question.\n\n\"Paragraph 1: Coffee consumption has risen dramatically worldwide over the past two decades.\nParagraph 2: Several studies have linked moderate coffee consumption to health benefits, including reduced risk of certain diseases.\nParagraph 3: However, excessive consumption can lead to anxiety, insomnia, and increased heart rate.\nParagraph 4: Therefore, most health experts recommend limiting intake to three or four cups per day.\"\n\nWhat is the function of Paragraph 3 in the overall text?", "options": ["It provides the main argument of the text.", "It introduces a contrasting perspective to balance the previous paragraph.", "It summarises all the information presented so far.", "It gives a personal opinion about coffee."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.2, "irt_c_param": 0.2, "explanation_text": "'However' at the start of Paragraph 3 is a contrast signal. Paragraph 2 discussed benefits; Paragraph 3 introduces risks. This balances the text before the recommendation in Paragraph 4. Recognising these 'pivot' paragraphs \u2014 where the argument shifts direction \u2014 is essential for IELTS reading.", "distractor_traps": {"0": "Paragraph 3 presents a counterpoint, not the main argument \u2014 the main argument is the overall balanced assessment", "2": "It doesn't summarise \u2014 it introduces new, contrasting information", "3": "It presents factual health risks, not personal opinion"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "64fbfcac-f436-4959-b2cd-272f6f5f6f65", "stem": "Read the text and answer the question.\n\n\"While urbanisation has brought significant economic benefits to developing nations, it has also created unprecedented challenges in housing, sanitation, and public health. This paradox \u2014 growth that simultaneously enriches and endangers \u2014 requires policy solutions that acknowledge both dimensions rather than treating them as separate issues.\"\n\nWhat is the function of the phrase 'This paradox' in the text?", "options": ["It introduces a new topic unrelated to the first sentence.", "It summarises the tension described in the first sentence and sets up the argument that follows.", "It contradicts the idea that urbanisation has economic benefits.", "It provides a definition of urbanisation."], "correct_choice": 1, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.7, "irt_c_param": 0.18, "explanation_text": "'This paradox' is a cohesive device \u2014 it refers back to the tension in the first sentence (benefits vs. challenges) and names it. The dash ('\u2014growth that simultaneously enriches and endangers\u2014') explains the paradox. Then 'requires' launches the author's argument. This kind of summarise-and-pivot structure is common in academic writing.", "distractor_traps": {"0": "It refers directly to the first sentence's content \u2014 it's not a new topic", "2": "It doesn't contradict the benefits \u2014 it names the contradiction between benefits and challenges", "3": "Urbanisation was defined in the first sentence through its effects, not here"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "7b3cd7dd-280c-444c-83f6-c040bb5cae6a", "stem": "Read the text and answer the question.\n\n\"The assumption that technology inevitably improves educational outcomes has driven billions of dollars in investment over the past decade. Schools have purchased tablets, interactive whiteboards, and learning management systems at scale. Yet a growing body of research suggests that the impact of these investments on student achievement is modest at best and, in some cases, negligible.\"\n\nWhat is the author's rhetorical strategy in this passage?", "options": ["Presenting a popular belief, showing its consequences, then challenging it with evidence.", "Comparing two educational systems and recommending one.", "Describing a historical trend and predicting its future development.", "Arguing strongly in favour of technology in education."], "correct_choice": 0, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "B2", "irt_a_param": 1.6, "irt_b_param": 0.9, "irt_c_param": 0.18, "explanation_text": "The passage has three moves: (1) state a widely held assumption ('technology improves outcomes'), (2) show how that assumption led to action ('billions in investment'), (3) undercut the assumption with evidence ('modest at best, negligible'). This setup-and-challenge structure is a classic academic rhetorical strategy.", "distractor_traps": {"1": "No comparison between two systems \u2014 only one approach (technology investment) is discussed", "2": "No prediction is made about the future", "3": "The passage undermines the pro-technology position, not supports it"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "09b53bb9-27b9-4578-bde5-059f10a608bc", "stem": "Read the text and answer the question.\n\n\"It would be premature to conclude that remote work is universally preferable to office-based work. While the productivity data from 2020\u20132023 is broadly encouraging, these findings emerged during extraordinary circumstances \u2014 a global pandemic that eliminated alternatives. Whether similar productivity levels would persist in a context of genuine choice remains an open question.\"\n\nWhat is the author doing in this passage?", "options": ["Arguing that remote work is more productive than office work.", "Presenting evidence that remote work reduces productivity.", "Qualifying an apparently positive finding by questioning the conditions under which it was produced.", "Predicting that remote work will become the standard within ten years."], "correct_choice": 2, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "The author acknowledges positive data ('broadly encouraging') but then questions its validity ('extraordinary circumstances,' 'eliminated alternatives,' 'open question'). This is academic hedging \u2014 accepting evidence while highlighting its limitations. The phrase 'it would be premature to conclude' is a classic hedge that signals careful, qualified reasoning.", "distractor_traps": {"0": "The author explicitly says it's 'premature' to reach this conclusion", "1": "The data is described as 'broadly encouraging,' not negative", "3": "No prediction is made \u2014 the author says the question 'remains open'"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "ae1aba54-ccba-4279-978f-dc2651edbcf0", "stem": "Read the text and answer the question.\n\n\"The notion that economic growth is inherently incompatible with environmental sustainability has gained considerable traction in recent years. Proponents of 'degrowth' argue that finite planetary resources make perpetual expansion impossible. Yet this framing presents a false binary. A more nuanced reading of the evidence suggests that the relationship between growth and sustainability is mediated by institutional design, technological innovation, and \u2014 crucially \u2014 political will.\"\n\nWhat is the author's position relative to the 'degrowth' argument?", "options": ["Full agreement \u2014 the author believes growth must stop.", "Full rejection \u2014 the author believes growth and sustainability are completely compatible.", "Partial critique \u2014 the author accepts the concern but rejects the either/or framing.", "Neutrality \u2014 the author presents both sides without taking a position."], "correct_choice": 2, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.4, "irt_c_param": 0.15, "explanation_text": "The author's position is revealed through precise word choices: 'gained considerable traction' (acknowledges the argument's influence without endorsing it), 'false binary' (rejects the either/or frame), 'more nuanced reading' (signals their own position as more sophisticated). The author doesn't dismiss the concern \u2014 they reject the simplistic framing.", "distractor_traps": {"0": "'False binary' shows the author disagrees with the degrowth framing, not agrees with it", "1": "The author doesn't say growth and sustainability are fully compatible \u2014 they say the relationship is 'mediated' by multiple factors", "3": "'False binary' and 'more nuanced reading' are the author's evaluative judgments, not neutral presentation"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "8de67870-3c8f-465e-b4ae-d07a192b17ee", "stem": "Read the text and answer the question.\n\n\"The increasing reliance on algorithmic decision-making in criminal justice \u2014 from predictive policing to sentencing recommendations \u2014 raises profound questions about accountability. When an algorithm recommends a longer sentence based on statistical patterns, who is responsible for that outcome? The developer who designed the model? The judge who accepted its recommendation? The institution that adopted it? The diffusion of responsibility across human and technical actors is perhaps the most troubling feature of algorithmic governance.\"\n\nWhat rhetorical technique does the author use in the middle of the passage?", "options": ["A series of rhetorical questions to highlight the complexity of assigning blame.", "Statistical evidence to prove that algorithms are biased.", "An anecdote about a specific court case.", "A direct quotation from a legal expert."], "correct_choice": 0, "skill": "Reading", "sub_skill": "Text Structure", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.5, "irt_c_param": 0.15, "explanation_text": "The three questions ('The developer? The judge? The institution?') are rhetorical \u2014 the author isn't expecting answers. Instead, the rapid succession of possible responsible parties illustrates the problem: responsibility is so dispersed that no one party is clearly accountable. This technique makes the abstract concept of 'diffusion of responsibility' concrete and immediate.", "distractor_traps": {"1": "No statistics or data are presented anywhere in the passage", "2": "No specific case is mentioned \u2014 the passage discusses the general pattern", "3": "No quotation from any external source appears in the passage"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "ea8a9c40-6a38-43ad-b4d3-8f8acff1fa78", "stem": "I wanted to go to the beach. ______, it started raining, so we stayed home.", "options": ["Because", "However", "Also", "For example"], "correct_choice": 1, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "A2", "irt_a_param": 0.9, "irt_b_param": -1.4, "irt_c_param": 0.25, "explanation_text": "'However' introduces a contrast \u2014 the writer wanted to go (positive), but rain stopped them (negative). 'However' is one of the most important linking words: it signals that the next idea contrasts with the previous one. 'Because' gives a reason, 'also' adds information, and 'for example' gives an illustration.", "distractor_traps": {"0": "'Because' introduces a cause, but the rain is a new contrasting event, not a reason for wanting to go", "2": "'Also' adds similar information \u2014 rain is not similar to wanting to go to the beach", "3": "'For example' introduces an illustration of a previous point \u2014 rain is not an example of wanting to go to the beach"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "9ac74a69-0d18-4684-99be-3ef94d53ce3e", "stem": "The government increased funding for public schools. ______, test scores improved significantly within two years.", "options": ["Nevertheless", "In contrast", "As a result", "Meanwhile"], "correct_choice": 2, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "B1", "irt_a_param": 1.2, "irt_b_param": -0.1, "irt_c_param": 0.22, "explanation_text": "'As a result' shows cause and effect: funding went up \u2192 scores improved. This is a consequence connector. 'Nevertheless' would signal an unexpected outcome. 'In contrast' would introduce an opposite situation. 'Meanwhile' would signal events happening at the same time.", "distractor_traps": {"0": "'Nevertheless' signals an outcome that contradicts expectations \u2014 but improved scores are the expected result of more funding", "1": "'In contrast' introduces an opposing idea \u2014 but the second sentence is a consequence, not a contrast", "3": "'Meanwhile' shows simultaneous events \u2014 but the scores improved 'within two years,' showing cause-effect, not simultaneity"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "71c636e9-a3e4-487f-badb-61880ce85f50", "stem": "Many people believe that social media brings people together. ______, research suggests that heavy social media use can actually increase feelings of loneliness.", "options": ["In addition", "On the contrary", "Similarly", "As a result"], "correct_choice": 1, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "B1", "irt_a_param": 1.3, "irt_b_param": 0.1, "irt_c_param": 0.2, "explanation_text": "'On the contrary' directly contradicts what came before. People believe social media connects \u2192 research shows it increases loneliness. This is a direct opposition, not just a contrast (which would use 'however'). 'On the contrary' is stronger than 'however' \u2014 it says the opposite is true.", "distractor_traps": {"0": "'In addition' adds a supporting point \u2014 but the second sentence contradicts the first", "2": "'Similarly' shows agreement between two ideas \u2014 the opposite of what's happening here", "3": "'As a result' shows cause-effect \u2014 but loneliness isn't a result of the belief; it contradicts it"}, "goal_tags": ["A", "B", "D", "E"]}, {"item_id": "3c5e5db2-44d1-43c0-b584-e3a7457ab4d8", "stem": "The initial findings were promising. ______, the researchers cautioned that the sample size was too small to draw definitive conclusions.", "options": ["Furthermore", "Likewise", "Nonetheless", "Accordingly"], "correct_choice": 2, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.6, "irt_c_param": 0.18, "explanation_text": "'Nonetheless' means 'despite what was just said' \u2014 it's a formal alternative to 'however' or 'even so.' The findings were promising, but the researchers still had concerns. 'Nonetheless' is particularly useful in academic writing for introducing caveats after positive statements.", "distractor_traps": {"0": "'Furthermore' adds supporting information \u2014 but the caution about sample size is a limitation, not additional support", "1": "'Likewise' shows similarity \u2014 the caution is not similar to the promising findings", "3": "'Accordingly' means 'as a logical consequence' \u2014 but the caution is a contrast, not a consequence of the promising results"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "e1c991f1-b2f9-4ddc-9b85-38a8c86a3266", "stem": "Several factors contributed to the project's failure. ______, the budget was cut by forty per cent midway through. ______, key personnel resigned during the critical implementation phase.", "options": ["For instance / Moreover", "However / Therefore", "In contrast / Similarly", "Consequently / Nevertheless"], "correct_choice": 0, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "B2", "irt_a_param": 1.5, "irt_b_param": 0.8, "irt_c_param": 0.18, "explanation_text": "'For instance' introduces the first specific example of the 'several factors.' 'Moreover' adds a second contributing factor. The structure is: general claim \u2192 first example \u2192 additional example. In academic writing, 'for instance' and 'moreover' are standard tools for building a detailed argument.", "distractor_traps": {"1": "'However' would signal contrast, but both sentences support the same point (reasons for failure). 'Therefore' shows consequence, but the second factor isn't caused by the first", "2": "'In contrast' would mean the second factor opposes the first. 'Similarly' could work but doesn't fit as well as 'moreover' for adding a distinct additional factor", "3": "'Consequently' would mean the budget cut caused the failure (possible but not the logical structure here). 'Nevertheless' would contradict \u2014 the resignations are not a silver lining"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id": "335eaa71-e6e1-40e4-8c1e-4d3280766b35", "stem": "The data unequivocally supports the hypothesis that green spaces improve mental health outcomes. ______, this finding should not be taken to mean that urban planners can solve mental health crises through park construction alone.", "options": ["That said", "In other words", "By the same token", "To that end"], "correct_choice": 0, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "C1", "irt_a_param": 1.7, "irt_b_param": 1.3, "irt_c_param": 0.15, "explanation_text": "'That said' is an advanced discourse marker meaning 'despite what I just stated, here is a qualification.' It acknowledges the previous point as valid while introducing a limitation. It's more nuanced than 'however' \u2014 it doesn't contradict the previous point, it narrows its implications.", "distractor_traps": {"1": "'In other words' would rephrase the previous idea \u2014 but the second sentence introduces a new, limiting point", "2": "'By the same token' means 'for the same reason' \u2014 it extends an argument, but the second sentence limits it", "3": "'To that end' means 'in order to achieve that goal' \u2014 but the second sentence is a caution, not a purposeful action"}, "goal_tags": ["A", "B", "E"]}, {"item_id": "d924a463-d3b9-4f41-ad74-def7b7c3f783", "stem": "The committee's recommendation was unanimous. ______, not all members were equally enthusiastic \u2014 several expressed reservations during the private deliberations that preceded the public vote.", "options": ["Be that as it may", "In light of this", "As a consequence", "For all intents and purposes"], "correct_choice": 0, "skill": "Reading", "sub_skill": "Cohesive Devices", "cefr_difficulty": "C1", "irt_a_param": 1.8, "irt_b_param": 1.6, "irt_c_param": 0.15, "explanation_text": "'Be that as it may' is a formal concessive marker meaning 'accepting that the previous statement is true, what follows reveals a complication.' It's more sophisticated than 'however' or 'nevertheless' \u2014 it explicitly concedes the previous point before introducing the complication. Used in academic, legal, and diplomatic writing.", "distractor_traps": {"1": "'In light of this' means 'considering what was just said' and would introduce a consequence or action, not a complication", "2": "'As a consequence' shows cause-effect \u2014 but the reservations aren't caused by the unanimity; they complicate it", "3": "'For all intents and purposes' means 'effectively' or 'in practice' \u2014 it's a summing-up phrase, not a concessive marker"}, "goal_tags": ["A", "B", "C", "E"]}, {"item_id":"b2v2-0001","format_type":"error_identification","stem":"The number of students who [A] have registered for the course [B] are [C] higher than [D] expected.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B2","irt_a_param":1.45,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"[C] should be 'is' — the subject is 'The number' (singular), not 'students'. 'The number of + plural noun' takes a singular verb.","explanation_vi":"","distractor_traps":{"0":"Learners may think 'who have registered' is wrong because Vietnamese does not use relative clauses this way.","1":"Learners may doubt the present perfect in this context, thinking simple past is needed.","3":"Learners may confuse 'higher than' with 'more than' but both are grammatically acceptable here."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0002","format_type":"gap_fill","stem":"The report will be submitted ______ the committee has reviewed all the evidence.","options":["until","once","despite","unless"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.72,"irt_c_param":0.18,"explanation_text":"'Once' introduces a time clause meaning 'as soon as / after'. 'Until' implies waiting and requires a negative or different main clause. 'Unless' and 'despite' don't fit the meaning.","explanation_vi":"","distractor_traps":{"0":"'Until' is tempting because it also introduces time clauses, but 'will be submitted until' is illogical here.","2":"'Despite' must be followed by a noun phrase, not a clause.","3":"'Unless' changes the meaning to a condition, contradicting the intended sense."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0003","format_type":"error_identification","stem":"The findings suggest [A] that pollution levels [B] in the river has [C] increased [D] dramatically.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B1","irt_a_param":1.25,"irt_b_param":0.15,"irt_c_param":0.2,"explanation_text":"[C] should be 'have' — the subject is 'pollution levels' (plural). The prepositional phrase 'in the river' is not the subject.","explanation_vi":"","distractor_traps":{"0":"Learners may think 'suggest that' is wrong because Vietnamese does not require 'that' in reported clauses.","1":"Learners may suspect 'in the river' is incorrect, misidentifying it as the subject.","3":"'Dramatically' is a common adverb here; learners may overcorrect to 'dramatic'."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0004","format_type":"dialogue_completion","stem":"A: Could you possibly send me the updated figures before Thursday?\nB: ______\nA: Perfect — that gives me enough time to revise the presentation.","options":["I'll have them ready for you by Wednesday afternoon.","Yes, the figures are very important.","Thursday is a good day for a meeting.","I am sending figures to you now always."],"correct_choice":0,"skill":"Grammar","sub_skill":"Modal Verbs","cefr_difficulty":"B1","irt_a_param":1.18,"irt_b_param":-0.1,"irt_c_param":0.21,"explanation_text":"B's reply must (a) accept the request and (b) specify a time before Thursday, so A's follow-up ('enough time') is logical. Only option A does both.","explanation_vi":"","distractor_traps":{"1":"Acknowledges importance but doesn't answer the request — a common indirect avoidance pattern.","2":"Non-sequitur; learners may pick it because it mentions Thursday.","3":"Grammatically broken; may trap very low-level learners."},"goal_tags":["A","D","E"]}, {"item_id":"b2v2-0005","format_type":"odd_one_out","stem":"Three of these words commonly collocate with 'reach'. Which one does NOT?","options":["a conclusion","a compromise","an agreement","a demand"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.16,"explanation_text":"'Reach a conclusion/compromise/agreement' are all standard collocations. 'Reach a demand' is not natural — one 'makes' or 'meets' a demand.","explanation_vi":"","distractor_traps":{"0":"Learners may think 'reach a conclusion' is odd because Vietnamese uses 'đi đến kết luận' (arrive at a conclusion).","1":"'Compromise' is a less frequent word; learners may avoid it.","2":"'Reach an agreement' is the most common, so learners may over-trust it and doubt others."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0006","format_type":"best_paraphrase","stem":"Which sentence has the closest meaning to: 'The government has yet to respond to the petition.'","options":["The government has already responded to the petition.","The government responded to the petition late.","The government has not responded to the petition so far.","The government refused to respond to the petition."],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.68,"irt_c_param":0.17,"explanation_text":"'Has yet to' = has not done something up to now. Option C correctly captures this with 'has not responded so far'. Option D wrongly implies refusal; options A and B contradict the meaning.","explanation_vi":"","distractor_traps":{"0":"Direct opposite — learners who misread 'yet' as a positive marker may choose this.","1":"'Yet' and 'late' both involve timing, causing confusion for learners.","3":"'Yet to respond' doesn't mean refusal, but the nuance is lost on B1 learners."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0007","format_type":"gap_fill","stem":"The contract, ______ was signed last month, has already been challenged in court.","options":["that","which","who","what"],"correct_choice":1,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.2,"explanation_text":"Non-defining relative clauses (set off by commas) require 'which', not 'that'. 'Who' is for people; 'what' cannot start a relative clause here.","explanation_vi":"","distractor_traps":{"0":"'That' is the most common relative pronoun learners learn first; they often use it universally.","2":"'Who' is chosen by learners who confuse animate/inanimate pronoun selection.","3":"'What' is confused with 'which' due to Vietnamese 'mà/cái gì' mapping."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0008","format_type":"register_match","stem":"A student is writing the introduction to an IELTS Task 2 essay on urban development. Which sentence is most appropriate?","options":["Cities are getting bigger and bigger and that's a big problem for everyone.","Urban expansion has become a pressing issue in many parts of the world.","Nowadays cities are growing a lot and we should think about this.","Urban growth is something lots of countries are worried about these days."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.35,"irt_b_param":0.78,"irt_c_param":0.17,"explanation_text":"Option B uses precise academic vocabulary ('urban expansion', 'pressing issue') and avoids vague intensifiers or personal pronouns — all essential for IELTS academic register.","explanation_vi":"","distractor_traps":{"0":"Informal repetition ('bigger and bigger') and 'everyone' — common in Vietnamese learner writing.","2":"Uses 'we', vague ('a lot'), and lacks noun-phrase formality.","3":"'Lots of' and 'these days' are too informal for academic writing."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0009","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The new policy was met with considerable resistance from staff, who felt they had not been adequately consulted. Management, however, remained sanguine about its eventual acceptance.\"\n\nWhat does 'sanguine' most likely mean in this context?","options":["Angry and defensive","Optimistic and confident","Cautious and uncertain","Embarrassed and apologetic"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.62,"irt_b_param":1.55,"irt_c_param":0.14,"explanation_text":"Contrast cues: staff resisted, but management remained 'sanguine about its eventual acceptance' — i.e., still believed it would succeed. This contrast signals a positive, confident attitude.","explanation_vi":"","distractor_traps":{"0":"The confrontational situation leads learners to expect management anger.","2":"Plausible: faced with resistance, caution seems logical.","3":"Management might apologize in such conflict — a pragmatic (not textual) inference trap."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0010","format_type":"gap_fill","stem":"By the time the rescue team arrived, the survivors ______ in the cave for three days.","options":["were hiding","had been hiding","have been hiding","would hide"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.6,"irt_c_param":0.18,"explanation_text":"'By the time + past simple' requires past perfect continuous to show an ongoing action completed before that past point. Simple past continuous ('were hiding') ignores the duration relationship.","explanation_vi":"","distractor_traps":{"0":"Past continuous is the first instinct for an ongoing action in the past.","2":"Present perfect is confused with past perfect — 'have been hiding' has no past anchor.","3":"'Would hide' suggests a hypothetical, not a factual past event."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0011","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and natural sentence?\n\n1: rarely / 2: such / 3: been / 4: has / 5: dedication / 6: seen","options":["2-5-4-1-3-6","1-4-3-6-2-5","4-1-3-6-2-5","2-5-1-4-3-6"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.6,"irt_c_param":0.13,"explanation_text":"'Rarely has such dedication been seen' — fronting a negative adverb ('rarely') triggers subject-auxiliary inversion: rarely + has + subject + past participle.","explanation_vi":"","distractor_traps":{"0":"'Such dedication has rarely been seen' — natural but the inversion form is required here.","2":"Has + rarely order without inversion — partially correct but not the target structure.","3":"Places 'such dedication' first without inversion — grammatically odd."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0012","format_type":"odd_one_out","stem":"Three of these words share the same suffix pattern to form adjectives meaning 'full of' or 'tending to'. Which word does NOT follow this pattern?","options":["harmful","hopeful","useful","natural"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Word Formation","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0,"irt_c_param":0.21,"explanation_text":"'Harmful', 'hopeful', and 'useful' are all formed by adding '-ful' to nouns. 'Natural' uses the suffix '-al' added to 'nature' and does not mean 'full of'.","explanation_vi":"","distractor_traps":{"0":"'Harm' is a less positive word; learners may assume it's the odd one.","1":"Learners may confuse 'hope' (noun) with its adjectival form.","2":"'Useful' ends in '-ful' but 'use' sounds like a verb, causing uncertainty."},"goal_tags":["A","B"]}, {"item_id":"b2v2-0013","format_type":"gap_fill","stem":"The research paper ______ by three scientists before it was submitted to the journal.","options":["reviewed","was reviewed","has been reviewed","reviewing"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.8,"irt_c_param":0.24,"explanation_text":"A past passive is needed: 'was reviewed'. The agent phrase 'by three scientists' confirms the passive structure. 'Has been reviewed' is present perfect, but 'before it was submitted' anchors this in the past.","explanation_vi":"","distractor_traps":{"0":"Learners omit 'was' and use just the past participle, a direct L1 transfer from Vietnamese (no auxiliary needed).","2":"Present perfect passive — learners use this for any completed action.","3":"Present participle chosen by learners who guess '-ing' for ongoing actions."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0014","format_type":"dialogue_completion","stem":"A: I heard you're moving to a new apartment next week.\nB: That's right. ______\nA: Oh, I had no idea you'd been there so long. Let me know if you need help moving.","options":["I've lived in the current one for six years, so it feels strange to leave.","The new apartment is very big and modern.","Moving is always an exciting experience for me.","I will move my things by myself without help."],"correct_choice":0,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B1","irt_a_param":1.28,"irt_b_param":0.2,"irt_c_param":0.2,"explanation_text":"A's follow-up reveals surprise at how long B has lived there — only option A provides duration with present perfect, which triggers A's 'I had no idea you'd been there so long'.","explanation_vi":"","distractor_traps":{"1":"Describes the new place, but doesn't logically trigger A's surprise about duration.","2":"Thematically related but gives A nothing to respond to about duration.","3":"Addresses A's implicit offer but inverts natural conversation flow."},"goal_tags":["A","D"]}, {"item_id":"b2v2-0015","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"Although critics praised the novel's ambitious scope, many readers found its narrative structure opaque, frequently losing the thread of the story altogether.\"\n\nWhat does 'opaque' most likely mean here?","options":["Transparent and easy to follow","Difficult to understand","Visually dark and colourless","Overly long and detailed"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.82,"irt_c_param":0.17,"explanation_text":"The result clause ('losing the thread') shows readers couldn't follow the story, so 'opaque' = hard to understand. Option A is the literal opposite; options C and D don't fit a narrative structure.","explanation_vi":"","distractor_traps":{"0":"The primary meaning of 'transparent' (opposite of opaque in physics) may mislead learners who know the literal meaning.","2":"The literal, physical meaning of 'opaque' (not letting light through) traps learners who recall it from science.","3":"Long and detailed narratives are indeed hard to follow — a plausible but imprecise inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0016","format_type":"error_identification","stem":"Despite of [A] the heavy rain, [B] the match [C] went ahead [D] as planned.","options":["A","B","C","D"],"correct_choice":0,"skill":"Grammar","sub_skill":"Prepositions","cefr_difficulty":"A2","irt_a_param":0.95,"irt_b_param":-1.5,"irt_c_param":0.23,"explanation_text":"[A] is wrong: 'despite' is a preposition and never takes 'of'. The correct form is simply 'Despite the heavy rain'. 'In spite of' is the two-word alternative.","explanation_vi":"","distractor_traps":{"1":"Vietnamese learners may distrust the comma placement after an adverbial phrase.","2":"'Went ahead' is a phrasal verb that may seem incorrect to learners unfamiliar with it.","3":"'As planned' may seem like an incomplete clause without a verb."},"goal_tags":["A"]}, {"item_id":"b2v2-0017","format_type":"best_paraphrase","stem":"Which sentence has the closest meaning to: 'The committee is not in a position to make a decision at this stage.'","options":["The committee has chosen not to make a decision yet.","The committee is unable to decide right now.","The committee refuses to take responsibility for deciding.","The committee will make a decision at a later stage."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.4,"irt_c_param":0.13,"explanation_text":"'Not in a position to' is a formal hedge meaning 'unable to' — it expresses inability, not refusal or choice. Option B captures this precisely; A implies choice; C implies blame; D omits the inability.","explanation_vi":"","distractor_traps":{"0":"Learners conflate inability with deliberate choice — both result in no decision.","2":"The formal phrasing sounds evasive, leading learners to infer deliberate avoidance.","3":"True but incomplete — it doesn't capture the current inability."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0018","format_type":"gap_fill","stem":"She asked me ______ I had already sent the documents.","options":["that","if","what","whether or not"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"A2","irt_a_param":0.88,"irt_b_param":-1.6,"irt_c_param":0.24,"explanation_text":"Reported yes/no questions use 'if' or 'whether'. 'That' is for reported statements. 'What' introduces reported wh-questions. 'Whether or not' is a possible distractor but less natural in this construction.","explanation_vi":"","distractor_traps":{"0":"'That' is used in all reported speech in Vietnamese (equivalent: 'rằng'), so learners over-apply it.","2":"'What' is the most common reported speech word learners know.","3":"'Whether or not' is grammatically possible but awkward with 'already' — and learners rarely know it at A2."},"goal_tags":["A"]}, {"item_id":"b2v2-0019","format_type":"register_match","stem":"A job applicant is ending a cover letter to a company they have never contacted before. Which closing is most appropriate?","options":["See you soon!","Looking forward to hearing from you. Best wishes.","I await your response at your earliest convenience. Yours faithfully,","Hope to chat soon. Thanks a lot!"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.36,"irt_b_param":0.75,"irt_c_param":0.17,"explanation_text":"A cover letter to an unknown recipient requires formal register. 'Yours faithfully' is the correct closing when the recipient is unknown (vs. 'Yours sincerely' when the name is known). Option B is semi-formal, not fully appropriate.","explanation_vi":"","distractor_traps":{"0":"Casual — learners who write emails informally may not distinguish registers.","1":"'Best wishes' and 'looking forward to' are known expressions; learners may accept semi-formal as good enough.","3":"'Thanks a lot' is clearly informal but 'looking forward to hearing' in option 1 creates doubt."},"goal_tags":["C","D","E"]}, {"item_id":"b2v2-0020","format_type":"gap_fill","stem":"If the vaccine ______ distributed earlier, thousands of lives could have been saved.","options":["was","were","had been","would have been"],"correct_choice":2,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.95,"irt_c_param":0.16,"explanation_text":"Third conditional (unreal past): 'If + past perfect ... could/would have + past participle'. 'Had been distributed' is the passive past perfect required here.","explanation_vi":"","distractor_traps":{"0":"'Was distributed' — second conditional mix-up, very common at B1.","1":"'Were distributed' — second conditional passive, another common error.","3":"'Would have been' belongs in the main clause, not the if-clause."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0021","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The prime minister's speech was carefully worded to placate critics without committing the government to any concrete action.\"\n\nWhat does 'placate' most likely mean?","options":["To challenge and provoke","To inform and educate","To calm or satisfy","To publicly embarrass"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"The speech was aimed at 'critics' — placating them means calming their opposition. The phrase 'without committing to action' confirms that the goal was to soothe, not genuinely address concerns.","explanation_vi":"","distractor_traps":{"0":"Learners may associate political speech with provocation.","1":"Speeches are for informing — a generic but wrong inference.","3":"Politicians embarrassing critics is a known political strategy learners may infer."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0022","format_type":"error_identification","stem":"The professor, whom [A] students greatly admire, [B] have published [C] over thirty [D] research articles.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B2","irt_a_param":1.45,"irt_b_param":0.8,"irt_c_param":0.17,"explanation_text":"[C] should be 'has published' — the subject is 'The professor' (singular). The relative clause 'whom students greatly admire' is parenthetical and does not change the subject.","explanation_vi":"","distractor_traps":{"0":"'Whom' vs 'who' is a known difficulty — learners may think 'who' is correct here.","1":"Learners may doubt the non-defining relative clause punctuation.","3":"'Over thirty' may seem non-standard; learners expect 'more than'."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0023","format_type":"dialogue_completion","stem":"A: You look exhausted. Have you been sleeping enough lately?\nB: ______\nA: You really should see a doctor if it's been going on that long.","options":["Not really. I've been waking up at 3 a.m. for the past two weeks.","Yes, I sleep very much and I feel good.","I am tired because of the work yesterday.","Sleep is very important for health, I know."],"correct_choice":0,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.21,"explanation_text":"A's follow-up ('if it's been going on that long') requires B to have mentioned a duration with present perfect continuous. Only A's response contains this duration cue ('for the past two weeks').","explanation_vi":"","distractor_traps":{"1":"Positive answer doesn't match A's suggestion to see a doctor.","2":"Refers only to yesterday — doesn't explain a long-term problem.","3":"Agrees with A's statement but doesn't describe personal sleep problems."},"goal_tags":["A","D"]}, {"item_id":"b2v2-0024","format_type":"sentence_reorder","stem":"Which arrangement correctly sequences these sentences into a coherent paragraph?\n\n1: However, this growth has not been without consequence.\n2: Urban populations worldwide have expanded rapidly over the past century.\n3: Policymakers must now grapple with issues of infrastructure, housing, and environmental sustainability.\n4: Cities have absorbed millions of rural migrants in search of better opportunities.","options":["2-4-1-3","1-2-3-4","4-2-1-3","2-1-4-3"],"correct_choice":0,"skill":"Reading","sub_skill":"Text Structure","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"Correct order: general claim (2) → supporting detail (4) → contrast/pivot (1) → consequence/solution (3). Sentence 1's 'However' signals a pivot, so it must follow positive information.","explanation_vi":"","distractor_traps":{"1":"Starts with 'However' — learners may miss that contrast needs a preceding positive statement.","2":"Places the supporting detail first, disrupting the general-to-specific flow.","3":"Places the contrast immediately after the general claim, skipping the supporting detail."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0025","format_type":"gap_fill","stem":"The policy ______ in 2019 and has been in effect ever since.","options":["introduces","was introduced","has introduced","is introduced"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.7,"irt_c_param":0.24,"explanation_text":"The policy is the receiver of the action, so passive is needed. The specific year (2019) anchors this in the past: 'was introduced'. Present passive ('is introduced') and present perfect active ('has introduced') are wrong.","explanation_vi":"","distractor_traps":{"0":"Active present — learners omit both the auxiliary and passive form.","2":"Learners confuse 'has been introduced' (correct present perfect passive) with 'has introduced' (active).","3":"Present passive — ignores the 2019 time marker."},"goal_tags":["A"]}, {"item_id":"b2v2-0026","format_type":"odd_one_out","stem":"Three of these phrases are formal synonyms for 'start'. Which one is NOT?","options":["initiate","commence","instigate","wrap up"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"B1","irt_a_param":1.18,"irt_b_param":-0.05,"irt_c_param":0.21,"explanation_text":"'Initiate', 'commence', and 'instigate' all mean to begin/start something. 'Wrap up' means to finish or conclude — it is the opposite.","explanation_vi":"","distractor_traps":{"0":"'Instigate' usually collocates with negative events (instigate a conflict), so learners may doubt it.","1":"'Commence' is less frequent and learners may be unfamiliar with it.","2":"Learners may confuse 'initiate' and 'instigate' as sounding similar."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0027","format_type":"gap_fill","stem":"The equipment ______ before the technicians could begin their work.","options":["needed to calibrate","needed to be calibrated","needs calibrating","was needed calibrating"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.7,"irt_c_param":0.18,"explanation_text":"'Needed to be calibrated' = passive infinitive after 'need', expressing necessity for a past action. Option C ('needs calibrating') is present tense. Option A (active) implies the equipment calibrates itself.","explanation_vi":"","distractor_traps":{"0":"Active infinitive — learners miss that equipment cannot calibrate itself.","2":"Present tense 'needs' — ignores the past context ('before they could begin').","3":"Ungrammatical combination learners may produce from L1 transfer."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0028","format_type":"best_paraphrase","stem":"Which sentence best expresses the meaning of: 'Access to clean water remains elusive for many communities in the developing world.'","options":["Many communities in developing countries find clean water readily available.","Developing countries have recently gained access to clean water.","Clean water is still difficult for many communities in poorer countries to obtain.","Some communities in rich countries struggle to access clean water."],"correct_choice":2,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":-0.1,"irt_c_param":0.2,"explanation_text":"'Elusive' = hard to find or obtain; 'remains' = still the case now; 'developing world' = poorer countries. Only option C captures all three elements accurately.","explanation_vi":"","distractor_traps":{"0":"Direct opposite — 'readily available' vs 'elusive'.","1":"'Recently gained' contradicts 'remains elusive'.","3":"Changes 'developing world' to 'rich countries' — a factual distortion."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0029","format_type":"error_identification","stem":"The man which [A] lives next door [B] has been [C] very helpful [D] to us.","options":["A","B","C","D"],"correct_choice":0,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.4,"irt_c_param":0.24,"explanation_text":"[A] should be 'who' — 'which' is used for things/animals, not people. 'The man who lives next door' is the correct form.","explanation_vi":"","distractor_traps":{"1":"Learners may be uncertain about dropping the preposition in 'lives next door'.","2":"'Has been' as a present perfect form may confuse learners who expect simple past.","3":"Learners may doubt 'helpful to' and prefer 'helpful for'."},"goal_tags":["A"]}, {"item_id":"b2v2-0030","format_type":"register_match","stem":"A doctor is writing notes to a colleague about a patient's condition. Which sentence is most appropriate?","options":["The patient is really sick and we should do something fast.","Patient presents with acute febrile illness; recommend immediate haematological workup.","She has a bad fever and I think we need to run some tests.","This patient has got a terrible fever and needs tests done today."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"C1","irt_a_param":1.62,"irt_b_param":1.5,"irt_c_param":0.13,"explanation_text":"Medical professional notes require precise clinical register: 'presents with', 'acute febrile illness', and 'haematological workup' are standard clinical terms. Options A, C, and D use informal or non-technical language.","explanation_vi":"","distractor_traps":{"0":"'Really sick' and 'do something' are too informal for medical documentation.","2":"Uses 'I think' and 'some tests' — plausible for spoken communication but not clinical notes.","3":"'Got a fever' and 'tests done' are semi-informal; 'today' replaces technical urgency markers."},"goal_tags":["B","C"]}, {"item_id":"b2v2-0031","format_type":"gap_fill","stem":"He told me that he ______ the report the following morning.","options":["will finish","would finish","finishes","has finished"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.25,"irt_b_param":0.05,"irt_c_param":0.2,"explanation_text":"In reported speech, 'will' shifts to 'would'. 'The following morning' (not 'tomorrow') confirms the backshift. Learners must apply sequence of tenses, not just repeat the original verb form.","explanation_vi":"","distractor_traps":{"0":"'Will finish' — learners forget to backshift in reported speech.","2":"'Finishes' — simple present used because learners avoid thinking about tense shift.","3":"'Has finished' — learners use present perfect as a 'safe' past-ish form."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0032","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"Despite his gregarious reputation, the CEO was unexpectedly reticent during the press conference, giving only brief, guarded answers to journalists' questions.\"\n\nWhat does 'reticent' most likely mean?","options":["Unusually talkative and open","Hesitant to speak freely","Angry and defensive","Confident and assertive"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"The contrast with 'gregarious' (sociable) and the evidence of 'brief, guarded answers' point to 'reticent' meaning unwilling to speak openly.","explanation_vi":"","distractor_traps":{"0":"Learners who don't know 'gregarious' may assume both words mean the same thing.","2":"'Guarded' and a hostile press context suggest defensiveness to many learners.","3":"CEOs in press conferences are often seen as confident — a contextual but wrong inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0033","format_type":"gap_fill","stem":"______ a thorough investigation, the authorities were unable to identify the cause of the fire.","options":["Despite conducting","Although conducted","However","In spite"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.16,"explanation_text":"'Despite conducting' is a prepositional phrase + gerund that correctly introduces the contrast. 'Although conducted' needs a subject. 'However' is a connector, not a subordinator. 'In spite' must be followed by 'of'.","explanation_vi":"","distractor_traps":{"1":"'Although' is a known contrast word; learners add it without supplying a subject.","2":"'However' is overused by Vietnamese learners who treat it like 'although'.","3":"'In spite' is an incomplete phrase; learners confuse it with 'despite'."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0034","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct sentence?\n\n1: the / 2: was / 3: renovated / 4: completely / 5: building / 6: last year","options":["1-5-2-4-3-6","1-5-4-2-3-6","2-1-5-4-3-6","1-5-2-3-4-6"],"correct_choice":0,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0,"irt_c_param":0.21,"explanation_text":"Correct: 'The building was completely renovated last year.' Adverbs of manner ('completely') go between the auxiliary and the past participle in passive sentences.","explanation_vi":"","distractor_traps":{"1":"Places 'completely' before 'was' — learners put adverbs in front of the whole verb phrase.","2":"Puts 'was' first — learners create a question form by mistake.","3":"Puts 'completely' after the past participle, a common L1 transfer error."},"goal_tags":["A"]}, {"item_id":"b2v2-0035","format_type":"odd_one_out","stem":"Three of these words are commonly used with 'make' in academic writing. Which one is NOT a natural collocation with 'make'?","options":["a contribution","a recommendation","an investigation","an exception"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.92,"irt_c_param":0.17,"explanation_text":"'Make a contribution', 'make a recommendation', and 'make an exception' are all standard collocations. 'Conduct/carry out an investigation' is the correct collocation — not 'make an investigation'.","explanation_vi":"","distractor_traps":{"0":"'Make a contribution' sounds redundant ('make' + 'contribute' meaning overlap).","1":"'Make a recommendation' — learners may prefer 'give a recommendation'.","3":"'Make an exception' — less frequent and learners may be unfamiliar."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0036","format_type":"gap_fill","stem":"There ______ be any sugar left — I used the last of it yesterday.","options":["mustn't","can't","shouldn't","wouldn't"],"correct_choice":1,"skill":"Grammar","sub_skill":"Modal Verbs","cefr_difficulty":"B2","irt_a_param":1.45,"irt_b_param":0.8,"irt_c_param":0.17,"explanation_text":"'Can't be' expresses logical deduction/impossibility based on evidence. 'Mustn't' expresses prohibition, not deduction. 'Shouldn't' implies expectation. 'Wouldn't' is conditional.","explanation_vi":"","distractor_traps":{"0":"'Mustn't' — learners confuse prohibition with logical impossibility (a very common modal error).","2":"'Shouldn't' — learners use this when they mean 'I don't think there is'.","3":"'Wouldn't' — learners use conditional modals for deductions."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0037","format_type":"dialogue_completion","stem":"A: The client's asking for the final draft by Monday. Is that feasible?\nB: ______\nA: Fair enough. I'll let them know we need until Tuesday.","options":["I can manage it if I work over the weekend, but Tuesday would be more realistic.","Monday is a day of the week.","I have already finished the draft last week.","The client should wait for a long time."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.12,"irt_c_param":0.21,"explanation_text":"A's follow-up ('I'll let them know we need until Tuesday') only makes sense if B suggested Tuesday as an alternative. Only option A provides a conditional acceptance with a counter-proposal.","explanation_vi":"","distractor_traps":{"1":"Irrelevant factual statement — learners may pick it as a filler response.","2":"Contradicts the premise — if it's done, Monday isn't a problem.","3":"Blunt and impolite — but learners who focus on meaning over register may miss the register error."},"goal_tags":["D","E"]}, {"item_id":"b2v2-0038","format_type":"gap_fill","stem":"Seldom ______ such a clear link between diet and mental health.","options":["researchers have observed","have researchers observed","researchers observed","did researchers have observed"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"C1","irt_a_param":1.72,"irt_b_param":1.65,"irt_c_param":0.12,"explanation_text":"Fronting 'seldom' (a negative adverb) requires subject-auxiliary inversion: 'Seldom have researchers observed'. Without inversion (option A), the sentence is ungrammatical in formal written English.","explanation_vi":"","distractor_traps":{"0":"Normal SVO order — learners forget inversion is required after fronted negative adverbs.","2":"Simple past without inversion — the error is compounded.","3":"Inverts with 'did' but retains 'have observed' — a blend of two different rules."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0039","format_type":"best_paraphrase","stem":"Which sentence most closely captures the meaning of: 'The author implies that institutional neglect contributed to the crisis, without stating so explicitly.'","options":["The author states clearly that institutions caused the crisis.","The author suggests, indirectly, that institutions played a role in causing the crisis.","The author argues that institutions had nothing to do with the crisis.","The author denies that institutional neglect was a factor."],"correct_choice":1,"skill":"Reading","sub_skill":"Author's Purpose","cefr_difficulty":"C1","irt_a_param":1.6,"irt_b_param":1.35,"irt_c_param":0.14,"explanation_text":"Key contrast: 'implies' ≠ 'states'. Only option B correctly preserves both the indirectness ('indirectly', 'suggests') and the causal claim. Options A and C distort one element each.","explanation_vi":"","distractor_traps":{"0":"Conflates 'imply' with 'state explicitly' — a common reading comprehension error.","2":"Reverses the causal attribution entirely.","3":"'Denies' is the opposite of 'implies' — learners who misread 'without stating so explicitly' may choose this."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0040","format_type":"gap_fill","stem":"The government ______ a new housing policy next year if the current plan fails.","options":["introduces","will introduce","would introduce","introduced"],"correct_choice":1,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"A2","irt_a_param":0.88,"irt_b_param":-1.55,"irt_c_param":0.23,"explanation_text":"First conditional (real future possibility): 'if + present simple, will + infinitive'. 'Would introduce' is second conditional (hypothetical). 'Introduces' is present tense only.","explanation_vi":"","distractor_traps":{"0":"Learners use present simple throughout the sentence because Vietnamese does not change verb form for tense.","2":"'Would' is taught as a polite/conditional form; learners overuse it.","3":"Past tense — learners confuse 'next year' with completed actions."},"goal_tags":["A"]}, {"item_id":"b2v2-0041","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The new regulations were intended to streamline the application process, but critics argued they would only add another layer of bureaucracy.\"\n\nWhat does 'streamline' most likely mean in this context?","options":["To make a process longer and more detailed","To make a process simpler and more efficient","To add more staff to a process","To make a process more transparent"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"B1","irt_a_param":1.18,"irt_b_param":-0.15,"irt_c_param":0.21,"explanation_text":"The contrast with 'another layer of bureaucracy' (complexity) indicates that 'streamline' means the opposite — simpler and more efficient.","explanation_vi":"","distractor_traps":{"0":"Learners may read 'add another layer' as the meaning of 'streamline', reversing the contrast.","2":"Related to organisations — learners may think streamlining means hiring more staff.","3":"Plausible policy goal but 'transparent' is not what 'streamline' means."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0042","format_type":"error_identification","stem":"The students were told [A] to submit their assignments [B] before the deadline, but many of them [C] doesn't [D] follow the instruction.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.65,"irt_c_param":0.24,"explanation_text":"[C] should be 'don't' — 'many of them' is plural, requiring 'don't', not 'doesn't' (third person singular).","explanation_vi":"","distractor_traps":{"0":"Learners may doubt 'were told to' as a passive structure.","1":"'Before the deadline' — learners may expect 'before the deadlines' or 'by the deadline'.","3":"'Follow the instruction' — learners may expect 'instructions' (plural)."},"goal_tags":["A"]}, {"item_id":"b2v2-0043","format_type":"register_match","stem":"A university student is emailing a professor to request an extension on an assignment. Which sentence is most appropriate to include?","options":["Hey, can you give me more time? I've been swamped.","I am writing to request an extension due to unforeseen personal circumstances.","Please give me extra days because I'm really busy with other stuff.","I would appreciate it if you could maybe give me a bit more time if that's okay."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.2,"explanation_text":"Option B uses appropriate formal register: a clear purpose statement, formal vocabulary ('unforeseen personal circumstances'), and no slang. Option D is over-hedged and informal ('maybe', 'a bit', 'if that's okay').","explanation_vi":"","distractor_traps":{"0":"Casual tone and slang ('swamped') — learners who communicate informally may accept this.","2":"'Stuff' and 'really busy' are too informal for an academic email.","3":"Sounds polite but 'maybe', 'a bit', 'if that's okay' make it inappropriately tentative and informal."},"goal_tags":["C","D"]}, {"item_id":"b2v2-0044","format_type":"gap_fill","stem":"______ he been more careful with the data, the errors would never have occurred.","options":["If","Had","Were","Should"],"correct_choice":1,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.5,"irt_c_param":0.13,"explanation_text":"'Had he been' is the inverted form of 'If he had been' — a third conditional with the conjunction omitted and the auxiliary fronted. This is a formal, literary structure.","explanation_vi":"","distractor_traps":{"0":"'If' is the standard form but the sentence needs the inverted (conjunctionless) form.","2":"'Were he' is the inverted second conditional — wrong tense for a past unreal situation.","3":"'Should he' inverts a first conditional — wrong for a past event."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0045","format_type":"sentence_reorder","stem":"Which sequence of sentences forms a coherent academic paragraph?\n\n1: As a result, the intervention proved far less effective than anticipated.\n2: The study aimed to assess the impact of early nutrition programmes on child development.\n3: Furthermore, participants dropped out at a higher rate than expected.\n4: However, implementation was hindered by insufficient funding and poor community engagement.","options":["2-4-3-1","1-2-3-4","2-3-4-1","4-2-1-3"],"correct_choice":0,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"Logical order: topic/aim (2) → problem 1 (4, 'However') → problem 2 (3, 'Furthermore') → consequence (1, 'As a result'). Each cohesive device signals the relationship to the previous sentence.","explanation_vi":"","distractor_traps":{"1":"Starts with 'As a result' — no prior cause established.","2":"Puts problem 2 before problem 1, breaking the 'However...Furthermore' logical chain.","3":"Starts with the contrasting problem before the topic sentence."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0046","format_type":"odd_one_out","stem":"Three of these words have a negative connotation when describing a person's speech or writing. Which one does NOT?","options":["verbose","convoluted","articulate","ambiguous"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.4,"irt_c_param":0.13,"explanation_text":"'Verbose' (wordy), 'convoluted' (overly complex), and 'ambiguous' (unclear) are all negative descriptors. 'Articulate' is positive — it means expressing ideas clearly and effectively.","explanation_vi":"","distractor_traps":{"0":"'Verbose' sounds like it could relate to 'verbs' or technical language — learners may not recognise the negative sense.","1":"'Convoluted' may be unfamiliar; learners may guess its connotation incorrectly.","3":"'Ambiguous' can sometimes be used neutrally in technical contexts."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0047","format_type":"gap_fill","stem":"She recommended that the board ______ the proposal before the end of the quarter.","options":["approves","approved","approve","will approve"],"correct_choice":2,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.3,"irt_c_param":0.14,"explanation_text":"After 'recommend that' (and other verbs of suggestion/demand), the subjunctive is used: base form without -s, regardless of person. 'The board approve' (not 'approves') is the mandative subjunctive.","explanation_vi":"","distractor_traps":{"0":"'Approves' — learners apply standard subject-verb agreement instead of subjunctive.","1":"'Approved' — learners apply tense backshift from 'recommended' (past).","3":"'Will approve' — learners use future tense because the action is upcoming."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0048","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The phenomenon is by no means confined to urban areas.'","options":["The phenomenon only occurs in urban areas.","The phenomenon does not occur in urban areas.","The phenomenon is not limited to urban areas.","The phenomenon rarely occurs outside urban areas."],"correct_choice":2,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.95,"irt_c_param":0.16,"explanation_text":"'By no means confined to' = certainly not limited to. Option C is the only one that preserves this meaning. Options A and D are opposites; option B removes urban areas entirely.","explanation_vi":"","distractor_traps":{"0":"Opposite meaning — learners may parse 'by no means' as an intensifier rather than a negator.","1":"Removes urban areas from the equation — too extreme.","3":"'Rarely' creates a partial restriction that contradicts 'by no means'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0049","format_type":"dialogue_completion","stem":"A: I don't think we should raise prices right now. The market's too volatile.\nB: ______\nA: Exactly — we need more data before making that call.","options":["I couldn't agree more. Acting hastily could cost us significant market share.","You are wrong. Prices should always go up.","The market is volatile because prices are too high.","We can raise prices next year when the market is good."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.78,"irt_c_param":0.17,"explanation_text":"A says 'Exactly — we need more data', confirming B agreed with and extended A's reasoning. Only option A ('I couldn't agree more... Acting hastily...') aligns with this follow-up.","explanation_vi":"","distractor_traps":{"1":"Directly contradicts A — doesn't fit 'Exactly'.","2":"Shifts causality rather than agreeing with A's concern.","3":"Partially agrees but proposes a future action rather than endorsing caution."},"goal_tags":["B","D","E"]}, {"item_id":"b2v2-0050","format_type":"gap_fill","stem":"The article was written by a journalist ______ work has appeared in several international publications.","options":["who","whose","which","whom"],"correct_choice":1,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Whose' is the possessive relative pronoun: 'a journalist whose work' = 'the journalist's work'. 'Who' cannot be followed directly by a noun; 'which' is for things; 'whom' is object case.","explanation_vi":"","distractor_traps":{"0":"'Who' is the most familiar relative pronoun for people — learners use it regardless of case.","2":"'Which' — learners may not distinguish animate/inanimate or be unsure about 'journalist' vs 'work'.","3":"'Whom' — learners know this is for people (correct) and formal (correct) but don't check the possessive need."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0051","format_type":"gap_fill","stem":"Neither the manager nor the employees ______ aware of the policy change.","options":["was","were","is","are being"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"With 'neither...nor', the verb agrees with the nearest subject ('employees' — plural), so 'were' is correct. If the nearest subject were singular, the verb would be singular.","explanation_vi":"","distractor_traps":{"0":"'Was' — learners focus on 'neither' as a singular determiner and apply singular agreement throughout.","2":"'Is' — present tense singular; learners treat 'neither' as equivalent to 'none'.","3":"'Are being' — progressive form chosen to indicate an ongoing state, but 'aware' is a stative adjective."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0052","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The professor's lectures were lauded for their clarity, but his written work was often criticised for being unnecessarily abstruse, leaving even specialist readers bewildered.\"\n\nWhat does 'abstruse' most likely mean?","options":["Clear and well-organised","Unnecessarily long and repetitive","Difficult to understand; obscure","Factually inaccurate"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.58,"irt_c_param":0.13,"explanation_text":"The contrast with 'clarity' and the result 'leaving readers bewildered' both point to 'abstruse' meaning hard to understand. 'Even specialist readers' adds that it's exceptionally obscure.","explanation_vi":"","distractor_traps":{"0":"Learners who miss the contrast with 'clarity' may assume the adjective shares a similar meaning.","1":"Academic writing that is 'criticised' is often long — a plausible but imprecise inference.","3":"'Bewildered readers' may suggest factual errors to learners unfamiliar with the word."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0053","format_type":"error_identification","stem":"The report recommended [A] that the company should [B] reduces [C] its carbon emissions [D] by 40%.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"[C] should be 'reduce' — after 'recommend that...should', the main verb is the base form, not the third-person singular form. Alternatively, mandative subjunctive: 'that the company reduce' (no 'should').","explanation_vi":"","distractor_traps":{"0":"'Recommended that' is a standard reporting verb — learners who are unsure may flag it.","1":"'Should' in recommendation clauses sounds correct to many learners and often is acceptable, but the error is specifically at [C].","3":"'By 40%' — learners may doubt this phrasing, preferring 'to 40%'."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0054","format_type":"odd_one_out","stem":"Three of these verbs commonly collocate with 'responsibility'. Which one does NOT?","options":["take","bear","accept","commit"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.92,"irt_c_param":0.16,"explanation_text":"'Take responsibility', 'bear responsibility', and 'accept responsibility' are all natural collocations. 'Commit responsibility' is not standard — one 'commits to' a task or 'commits a crime'.","explanation_vi":"","distractor_traps":{"0":"'Take responsibility' is very common — learners may over-trust it and suspect it's the trick option.","1":"'Bear responsibility' is formal and less familiar to Vietnamese learners.","2":"'Accept responsibility' — learners may confuse 'accept' with 'take' and flag one as redundant."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0055","format_type":"gap_fill","stem":"The bridge ______ by engineers for the past six months, and it should reopen next week.","options":["is inspecting","has been inspected","has been inspecting","was being inspected"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"The bridge is the recipient of the action, so passive is needed. Present perfect passive ('has been inspected') fits the duration 'for the past six months' and connection to present. Active forms (A, C) are wrong; (D) is past progressive passive.","explanation_vi":"","distractor_traps":{"0":"Present active progressive — learners forget the subject is the receiver of the inspection.","2":"'Has been inspecting' — active present perfect continuous; learners confuse active/passive.","3":"Past progressive passive — 'was being' ignores the present perfect time frame ('for the past six months... should reopen')."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0056","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and coherent sentence?\n\n1: the results / 2: not only / 3: but also / 4: surprised the team / 5: challenged their assumptions","options":["2-1-4-3-5","1-2-4-3-5","2-4-1-3-5","1-4-2-3-5"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"Correct: 'Not only the results surprised the team but also challenged their assumptions.' The correlative conjunction 'not only...but also' pairs parallel elements. 'Not only' must open the clause here.","explanation_vi":"","distractor_traps":{"1":"Places subject first without the fronted 'not only' — changes register and loses the parallel structure.","2":"Separates 'not only' from its subject, creating an ungrammatical phrase.","3":"Places the verb before 'not only', breaking the correlative structure."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0057","format_type":"dialogue_completion","stem":"A: Should I use 'who' or 'whom' in this sentence — 'the person ___ I spoke to'?\nB: ______\nA: Oh right, because it's the object of 'spoke to'.","options":["Use 'whom' — it's the object of the preposition.","Use 'who' — it always comes after 'the person'.","Both are correct in all situations.","Use 'which' — it refers to a specific person."],"correct_choice":0,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.8,"irt_c_param":0.17,"explanation_text":"'Whom' is the object form of 'who', used when the pronoun is the object of a verb or preposition. A's follow-up ('object of spoke to') confirms this explanation is what was needed.","explanation_vi":"","distractor_traps":{"1":"Learners who know 'who' refers to people may apply it universally regardless of case.","2":"Both can be used informally, but the question asks for the correct choice specifically.","3":"'Which' for people is a classic L1 transfer error from Vietnamese ('cái mà/người mà')."},"goal_tags":["A","D"]}, {"item_id":"b2v2-0058","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The research findings lend credence to the theory that sleep deprivation impairs cognitive function.'","options":["The research proves conclusively that poor sleep causes cognitive damage.","The research findings support the idea that not sleeping enough harms thinking ability.","The research suggests that cognitive function affects sleep quality.","The research findings contradict the theory about sleep and the brain."],"correct_choice":1,"skill":"Reading","sub_skill":"Author's Purpose","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.38,"irt_c_param":0.14,"explanation_text":"'Lend credence to' = support/give credibility to, not prove conclusively. 'Sleep deprivation' = not sleeping enough; 'impairs' = harms; 'cognitive function' = thinking ability. Option A over-claims; C and D distort the direction.","explanation_vi":"","distractor_traps":{"0":"'Lend credence' sounds strong — learners conflate support with proof.","2":"Reverses the causal direction: sleep → cognition becomes cognition → sleep.","3":"'Contradict' is the opposite of 'lend credence to'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0059","format_type":"gap_fill","stem":"He said that he ______ the meeting if he had known about it earlier.","options":["would attend","will have attended","would have attended","had attended"],"correct_choice":2,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.45,"irt_b_param":0.92,"irt_c_param":0.16,"explanation_text":"Third conditional in reported speech: 'would have attended' (main clause of third conditional, backshifted from direct speech). The if-clause 'had known' confirms the unreal past scenario.","explanation_vi":"","distractor_traps":{"0":"'Would attend' — second conditional; learners don't apply the perfect aspect needed for past unreal.","1":"'Will have attended' — future perfect; learners confuse this with hypothetical past.","3":"'Had attended' — past perfect used in the if-clause, not the main clause."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0060","format_type":"register_match","stem":"A researcher is presenting findings at an academic conference. Which sentence is most appropriate to introduce a limitation?","options":["We couldn't get enough people to take part, which was a problem.","One limitation of the study is the relatively small sample size, which may affect generalisability.","Honestly, not many people joined our study and that makes things tricky.","The sample was small but we think the results are still good."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.82,"irt_c_param":0.17,"explanation_text":"Option B uses precise academic language ('limitation', 'sample size', 'generalisability') in an impersonal, formal construction. The others use first person, vague language, or informal hedging.","explanation_vi":"","distractor_traps":{"0":"Uses 'we' and 'a problem' — too informal and vague.","2":"'Honestly' and 'tricky' are conversational; inappropriate in academic presentation.","3":"'We think' and 'still good' are too casual and lack precision."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0061","format_type":"gap_fill","stem":"It is essential that every employee ______ the safety training before operating the machinery.","options":["completes","complete","completed","will complete"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.32,"irt_c_param":0.14,"explanation_text":"After 'It is essential that', the mandative subjunctive requires the base form ('complete'), not third-person singular ('completes'). This is a formal written English structure.","explanation_vi":"","distractor_traps":{"0":"'Completes' — standard subject-verb agreement overrides subjunctive for most learners.","2":"'Completed' — backshift error: 'essential' in present triggers subjunctive, not past tense.","3":"'Will complete' — learners insert 'will' for future-oriented clauses after 'essential that'."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0062","format_type":"error_identification","stem":"Despite working [A] hard all semester, [B] she didn't managed [C] to pass [D] the final exam.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.5,"irt_c_param":0.23,"explanation_text":"[C] should be 'manage' — after 'didn't', the main verb must be the base form, not the past tense. 'Didn't managed' is a double past marking error.","explanation_vi":"","distractor_traps":{"0":"'Working' after 'despite' is correct gerund use — but learners unsure of 'despite' may flag it.","1":"Learners may doubt the comma use after an adverbial phrase.","3":"'To pass' is the correct infinitive after 'manage' — learners may suspect the infinitive form."},"goal_tags":["A"]}, {"item_id":"b2v2-0063","format_type":"odd_one_out","stem":"Three of these words are formal academic synonyms for 'show' or 'demonstrate'. Which one is NOT?","options":["illustrate","exemplify","indicate","overlook"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":-0.05,"irt_c_param":0.21,"explanation_text":"'Illustrate', 'exemplify', and 'indicate' all mean to show or make clear. 'Overlook' means to fail to notice or to ignore — it does not mean to demonstrate.","explanation_vi":"","distractor_traps":{"0":"'Illustrate' is familiar but learners may confuse it with 'draw pictures'.","1":"'Exemplify' is less common — learners may be uncertain of its meaning.","2":"'Indicate' can suggest or point to rather than demonstrate — learners may doubt its fit."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0064","format_type":"dialogue_completion","stem":"A: I'm not sure I understood the last part of the lecture on monetary policy.\nB: ______\nA: That would be great — I still have my notes from Tuesday.","options":["We could go over it together if you like. I took detailed notes.","Monetary policy is very complicated for everyone.","You should listen more carefully next time.","The lecturer explained it very well, I think."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"A responds 'That would be great — I still have my notes', which refers to B's offer to go over the material together and mentions notes. Only option A provides this offer and mentions having notes.","explanation_vi":"","distractor_traps":{"1":"General statement — doesn't make a specific offer A can respond to with 'That would be great'.","2":"Criticism — A's response would be 'Sorry' not 'That would be great'.","3":"Validates the lecture but doesn't offer the help A's follow-up implies was offered."},"goal_tags":["D"]}, {"item_id":"b2v2-0065","format_type":"best_paraphrase","stem":"Which sentence best expresses the meaning of: 'The policy has drawn criticism from both sides of the debate.'","options":["The policy is supported by all sides in the debate.","The policy has been criticised by people who disagree with each other.","The policy has attracted criticism only from its opponents.","The debate has been critical of all policies."],"correct_choice":1,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.2,"explanation_text":"'Both sides of the debate' implies people with opposing views, so criticism comes from people who themselves disagree with each other. Option B captures this accurately. C limits criticism to one side; A inverts the meaning.","explanation_vi":"","distractor_traps":{"0":"Opposite meaning — 'criticism' becomes 'supported by'.","2":"Partially right but misses that both sides criticise.","3":"Reverses subject and object; changes meaning entirely."},"goal_tags":["E"]}, {"item_id":"b2v2-0066","format_type":"gap_fill","stem":"______ the vaccine had been approved, health authorities began planning the distribution.","options":["No sooner","As soon as","Hardly","By the time"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'As soon as' introduces a time clause in normal SVO order with past simple. 'No sooner' and 'Hardly' require inversion and the past perfect. 'By the time' implies the main event is completed before the clause event.","explanation_vi":"","distractor_traps":{"0":"'No sooner' requires inversion: 'No sooner had the vaccine been approved than...' — learners use it without inversion.","2":"'Hardly' similarly requires inversion and 'when/before': 'Hardly had it been approved when...'","3":"'By the time' changes the temporal relationship — implies distribution came first."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0067","format_type":"register_match","stem":"A student is writing a complaint letter to their university about inadequate library facilities. Which sentence is most appropriate?","options":["Your library is terrible and something needs to be done about it ASAP.","I am writing to express my concern regarding the insufficient study resources available in the university library.","Honestly, the library is really bad and students like me are really suffering.","I think the library could be better but it's not that big of a deal."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.36,"irt_b_param":0.76,"irt_c_param":0.17,"explanation_text":"A formal complaint requires polite but assertive language, specific terminology ('insufficient study resources'), and avoidance of slang. Option B alone meets all these criteria.","explanation_vi":"","distractor_traps":{"0":"'ASAP' and 'terrible' are too informal and confrontational for a written complaint.","2":"'Honestly' and 'really suffering' are emotionally charged and imprecise.","3":"Contradicts itself — undermines the complaint with 'not that big of a deal'."},"goal_tags":["C","D","E"]}, {"item_id":"b2v2-0068","format_type":"gap_fill","stem":"The witness said that she ______ the suspect enter the building at around midnight.","options":["sees","has seen","had seen","was seen"],"correct_choice":2,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.25,"irt_b_param":0.15,"irt_c_param":0.2,"explanation_text":"In reported speech after a past reporting verb ('said'), present perfect 'has seen' backshifts to 'had seen'. 'Sees' is present; 'was seen' is passive and changes the subject.","explanation_vi":"","distractor_traps":{"0":"'Sees' — learners omit backshift because Vietnamese does not require it.","1":"'Has seen' — learners don't backshift from present perfect to past perfect.","3":"'Was seen' — passive form that changes who did the seeing."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0069","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The committee rejected the proposal outright, citing a lack of empirical evidence to substantiate the claims made by the research team.\"\n\nWhat does 'substantiate' most likely mean here?","options":["To contradict or disprove","To provide evidence to support","To summarise clearly","To question the relevance of"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"The committee rejected the proposal due to insufficient 'empirical evidence to substantiate the claims' — i.e., to back them up. 'Substantiate' = provide supporting evidence for a claim.","explanation_vi":"","distractor_traps":{"0":"The rejection context makes learners think 'substantiate' means disprove.","2":"'Summarise' is a related academic word that learners may confuse with 'substantiate'.","3":"Questioning relevance fits the rejection scenario but doesn't match the word's meaning."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0070","format_type":"error_identification","stem":"By the time she arrives, [A] we will finish [B] preparing all [C] the materials [D].","options":["A","B","C","D"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"[B] should be 'will have finished' — 'By the time + present simple' requires future perfect in the main clause to show completion before a future point.","explanation_vi":"","distractor_traps":{"0":"Learners may flag 'arrives' (present simple for future) as incorrect because they expect 'will arrive'.","2":"'Preparing all' — learners may expect 'all of' rather than 'all the'.","3":"'The materials' — learners may doubt the definite article."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0071","format_type":"odd_one_out","stem":"Three of these words describe positive qualities of an argument. Which one does NOT?","options":["coherent","rigorous","compelling","tenuous"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"'Coherent' (well-connected), 'rigorous' (thorough), and 'compelling' (convincing) are all positive descriptors of an argument. 'Tenuous' means weak or poorly supported — a negative quality.","explanation_vi":"","distractor_traps":{"0":"'Coherent' may sound technical rather than positive to some learners.","1":"'Rigorous' sounds harsh — learners may confuse it with 'strict' in a negative sense.","2":"'Compelling' is broadly known; learners may trust it too quickly and look for the odd one among the others."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0072","format_type":"sentence_reorder","stem":"Which sentence arrangement creates a coherent academic paragraph?\n\n1: This shift has been driven by advances in digital technology and changing consumer preferences.\n2: Traditional print media has experienced a significant decline over the past two decades.\n3: In response, many publishers have adopted hybrid models combining print and digital content.\n4: Advertising revenues, once the financial backbone of newspapers, have migrated to online platforms.","options":["2-4-1-3","1-2-3-4","2-1-4-3","4-1-2-3"],"correct_choice":2,"skill":"Reading","sub_skill":"Text Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.92,"irt_c_param":0.16,"explanation_text":"Order: general claim of decline (2) → cause of decline (1, 'This shift') → specific consequence: ad revenue loss (4) → industry response (3, 'In response'). Sentence 1 refers to 'this shift', which must follow a claim about change.","explanation_vi":"","distractor_traps":{"0":"Puts the ad revenue loss before the cause, breaking the cause→effect chain.","1":"Starts with causes before establishing the problem.","3":"Opens with a specific consequence before the general claim is made."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0073","format_type":"gap_fill","stem":"The medication must ______ at room temperature and kept away from direct sunlight.","options":["store","be stored","storing","have stored"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.6,"irt_c_param":0.24,"explanation_text":"The medication is the object of the storage action, so a passive infinitive is needed: 'must be stored'. 'Must store' (active) implies the medication stores itself.","explanation_vi":"","distractor_traps":{"0":"Active infinitive — learners omit 'be' because Vietnamese does not require a passive auxiliary.","2":"'Storing' — learners choose the -ing form for ongoing actions.","3":"'Have stored' — active perfect infinitive; learners confuse active/passive voice."},"goal_tags":["A"]}, {"item_id":"b2v2-0074","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The author stops short of attributing the famine entirely to government mismanagement.'","options":["The author claims the famine was entirely caused by government mismanagement.","The author does not completely blame the famine on government mismanagement.","The author denies that government mismanagement played any role in the famine.","The author argues that government mismanagement was not a significant factor."],"correct_choice":1,"skill":"Reading","sub_skill":"Author's Purpose","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"'Stops short of' = does not go as far as. So the author partially, but not fully, blames the government. Option B precisely captures 'not completely'. Options A and C are opposite extremes; D implies the author downplays the role.","explanation_vi":"","distractor_traps":{"0":"'Attributing... entirely' may be parsed without the negation 'stops short of'.","2":"'Stops short of' ≠ denies entirely — a subtle but important distinction at C1.","3":"Close to B but 'not significant' is stronger than 'not entirely' — C1 learners must detect this nuance."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0075","format_type":"gap_fill","stem":"She ______ to the airport when she realised she had forgotten her passport.","options":["drove","was driving","has been driving","had driven"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B1","irt_a_param":1.25,"irt_b_param":0.12,"irt_c_param":0.2,"explanation_text":"Past continuous ('was driving') describes an action in progress when another past action interrupted it ('realised'). Simple past ('drove') implies the driving was completed before the realisation.","explanation_vi":"","distractor_traps":{"0":"'Drove' — learners default to simple past for all past narrative.","2":"'Has been driving' — present perfect continuous; learners use it for any 'ongoing' past action.","3":"'Had driven' — past perfect implies driving was fully completed before realising, which contradicts the meaning."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0076","format_type":"error_identification","stem":"The data which [A] was collected [B] from participants [C] were then analysed [D] by the research team.","options":["A","B","C","D"],"correct_choice":3,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"[D] should be 'was analysed' — 'data' in academic/formal English is treated as an uncountable singular noun, requiring 'was'. Colloquially 'data were' is acceptable, but in formal academic contexts 'data was' is standard.","explanation_vi":"","distractor_traps":{"0":"'Which' referring to 'data' — learners may prefer 'that' or think 'which' is wrong here.","1":"'Was collected' — singular agreement here is actually correct but learners may flag it as inconsistent.","2":"'From participants' — preposition may seem incorrect to some learners."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0077","format_type":"gap_fill","stem":"The new law requires that all companies ______ their financial records for at least seven years.","options":["keeps","keep","kept","are keeping"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.35,"irt_c_param":0.14,"explanation_text":"After 'requires that', the mandative subjunctive uses the base form ('keep') for all subjects, including plural 'companies'. 'Keeps' applies standard agreement but ignores the subjunctive.","explanation_vi":"","distractor_traps":{"0":"'Keeps' — standard subject-verb agreement applied; learners don't recognise the subjunctive trigger.","2":"'Kept' — tense backshift error; 'requires' is present so no backshift is needed.","3":"'Are keeping' — progressive form chosen for ongoing obligations."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0078","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The speaker's tone shifted markedly as she moved from describing the problem to proposing solutions — from measured and cautious to unambiguously bullish.\"\n\nWhat does 'bullish' most likely mean here?","options":["Aggressive and threatening","Optimistic and confident about future prospects","Confused and uncertain","Critical and sceptical"],"correct_choice":1,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.52,"irt_c_param":0.13,"explanation_text":"Contrast with 'cautious': the speaker becomes 'bullish' when discussing solutions. In finance and general use, 'bullish' = optimistic, confident, positive about outcomes. It contrasts directly with her earlier caution.","explanation_vi":"","distractor_traps":{"0":"The literal image of a bull (aggressive animal) traps learners who don't know the metaphorical meaning.","2":"The shift away from caution could suggest confusion to learners who misread the tone change.","3":"Learners may expect critical analysis when discussing problems — and transfer that to the solution section."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0079","format_type":"dialogue_completion","stem":"A: I've applied for three jobs this week and haven't heard back from any of them.\nB: ______\nA: I suppose you're right. It's only been a few days.","options":["Don't worry — these things take time. Hiring processes aren't always quick.","You should apply for more jobs every single day.","Maybe your CV is not good enough.","Three jobs is too many to apply for in one week."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.2,"explanation_text":"A's follow-up ('I suppose you're right. It's only been a few days') indicates B offered reassurance about timing. Only option A addresses the time element ('these things take time') in a way A would agree with.","explanation_vi":"","distractor_traps":{"1":"Gives advice about applying more — A's reply about 'only a few days' doesn't follow.","2":"Critical of the CV — A's response would be defensive, not concessive.","3":"Criticises quantity — again, A wouldn't respond with 'I suppose you're right' about timing."},"goal_tags":["D"]}, {"item_id":"b2v2-0080","format_type":"gap_fill","stem":"The novel, ______ themes of identity and belonging, resonated deeply with immigrant communities worldwide.","options":["which exploring","whose exploring","exploring","that explores"],"correct_choice":2,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Exploring themes of identity and belonging' is a reduced relative clause (participial phrase) that correctly modifies 'The novel'. 'Which exploring' omits the verb form; 'that explores' would require removing the commas (defining clause).","explanation_vi":"","distractor_traps":{"0":"'Which exploring' — learners use 'which' but forget the required verb form ('which explores' or the reduced form 'exploring').","1":"'Whose exploring' — learners confuse the possessive relative pronoun with the participial structure.","3":"'That explores' — a defining relative clause; learners don't register the non-defining comma context."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0081","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The study found a correlation between screen time and sleep disturbances, though causation could not be established.'","options":["The study proved that screen time causes sleep disturbances.","The study found that screen time and sleep disturbances are related, but it is unclear which causes which.","The study found no link between screen time and sleep quality.","The study suggested that sleep disturbances lead to increased screen time."],"correct_choice":1,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Correlation' = a statistical relationship; 'causation could not be established' = unclear which causes which. Option B captures both the link and the uncertainty. A over-claims; C contradicts; D reverses direction.","explanation_vi":"","distractor_traps":{"0":"Learners conflate 'correlation' with 'causation' — a widespread critical thinking gap.","2":"Contradicts the finding of correlation.","3":"Reverses the direction of the correlation."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0082","format_type":"gap_fill","stem":"______ I known about the side effects earlier, I would have chosen a different treatment.","options":["If","Had","Did","Should"],"correct_choice":1,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.55,"irt_c_param":0.13,"explanation_text":"'Had I known' is the inverted third conditional without 'if'. Fronting the auxiliary 'had' and inverting with the subject replaces 'If I had known'. 'If' with normal word order is the standard form — not the inverted one.","explanation_vi":"","distractor_traps":{"0":"'If' is the standard conjunction but not valid in the inverted construction shown here.","2":"'Did I know' — inverted first conditional form; wrong for an unreal past condition.","3":"'Should I have known' — inverted first conditional with perfect; wrong tense scenario."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0083","format_type":"sentence_reorder","stem":"Which order produces a grammatically and logically correct sentence?\n\n1: interested / 2: candidates / 3: are / 4: to apply / 5: encouraged / 6: by Friday","options":["2-3-5-4-6","2-1-3-5-4-6","3-2-5-1-4-6","2-3-1-5-4-6"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.2,"explanation_text":"Correct: 'Interested candidates are encouraged to apply by Friday.' The adjective 'interested' modifies 'candidates' (pre-noun); 'are encouraged to apply' is passive. Without 'interested', the sentence is grammatically complete but loses the intended meaning.","explanation_vi":"","distractor_traps":{"0":"Drops 'interested' — produces 'Candidates are encouraged to apply by Friday', which is grammatical but not the target sentence.","2":"Puts 'are' first — question inversion error.","3":"Separates 'interested' from 'candidates' with 'are' between them."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0084","format_type":"odd_one_out","stem":"Three of these phrases are commonly used to add information in academic writing. Which one is NOT used for this purpose?","options":["in addition","furthermore","nevertheless","moreover"],"correct_choice":2,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0,"irt_c_param":0.21,"explanation_text":"'In addition', 'furthermore', and 'moreover' all add information to a previous point. 'Nevertheless' introduces contrast or concession — it signals that something is true despite what came before.","explanation_vi":"","distractor_traps":{"0":"'In addition' is less academic-sounding to some learners who may doubt it.","1":"'Furthermore' — less familiar; learners may not recognise its additive function.","3":"'Moreover' — sounds similar to 'however' for learners who are still building cohesive device vocabulary."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0085","format_type":"register_match","stem":"A manager is giving written feedback on an employee's performance review. Which sentence is most appropriate?","options":["She's been absolutely brilliant — one of our best!","She demonstrates consistent high performance and shows strong potential for leadership development.","She is good at her job and we like having her on the team.","She works hard, which is great, and her boss is happy with her."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.8,"irt_c_param":0.17,"explanation_text":"Written performance reviews require formal, specific, and professional language. Option B uses precise professional vocabulary without personal enthusiasm or vague praise.","explanation_vi":"","distractor_traps":{"0":"Over-enthusiastic and informal — learners may find it warm and see nothing wrong.","2":"'We like having her' is personal and informal for a formal document.","3":"Refers to 'her boss' in a review presumably written by the boss — incoherent perspective."},"goal_tags":["C","E"]}, {"item_id":"b2v2-0086","format_type":"gap_fill","stem":"The CEO, ______ leadership transformed the company's fortunes, retired last year after thirty years of service.","options":["who","whose","that","which"],"correct_choice":1,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.86,"irt_c_param":0.17,"explanation_text":"'Whose leadership' = the CEO's leadership. The possessive relative pronoun 'whose' is the only form that can link a noun phrase to the antecedent. 'Who leadership' is ungrammatical.","explanation_vi":"","distractor_traps":{"0":"'Who' is the default relative pronoun for people — learners use it without checking if a possessive is needed.","2":"'That' cannot be used in non-defining relative clauses (commas present) and doesn't work with following noun.","3":"'Which' is for things, not people, and also can't precede a noun."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0087","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The opposition leader's speech was laced with innuendo, never directly accusing the minister but ensuring the audience drew their own damaging conclusions.\"\n\nWhat does 'innuendo' most likely mean?","options":["Direct and factual accusations","Indirect suggestions intended to damage someone's reputation","Emotional appeals to the audience","Clear policy proposals"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.52,"irt_c_param":0.13,"explanation_text":"'Never directly accusing... but ensuring the audience drew damaging conclusions' defines innuendo perfectly: indirect, implicitly harmful suggestions without explicit accusation.","explanation_vi":"","distractor_traps":{"0":"The political context suggests accusations — learners may miss 'never directly'.","2":"Political speeches often contain emotional appeals — a plausible but wrong inference.","3":"Speeches involve policy — but the passage is entirely about reputational damage, not policy."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0088","format_type":"gap_fill","stem":"You ______ call ahead before visiting — they're very strict about appointments.","options":["could","might","had better","would"],"correct_choice":2,"skill":"Grammar","sub_skill":"Modal Verbs","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.86,"irt_c_param":0.17,"explanation_text":"'Had better' expresses strong advice with an implied warning of negative consequences — appropriate here because 'they're very strict'. 'Could' and 'might' are suggestions without urgency; 'would' is conditional.","explanation_vi":"","distractor_traps":{"0":"'Could' — learners use it for all advice because 'can' and 'could' are overlearned for suggestions.","1":"'Might' — polite suggestion but too weak given the strict context.","3":"'Would' — learners use it as a general polite form without considering the implied warning in 'had better'."},"goal_tags":["A","D","E"]}, {"item_id":"b2v2-0089","format_type":"best_paraphrase","stem":"Which sentence most closely captures the meaning of: 'The economist was at pains to distinguish between correlation and causation.'","options":["The economist struggled to understand the difference between correlation and causation.","The economist made a deliberate effort to clarify the difference between correlation and causation.","The economist argued that correlation and causation are the same thing.","The economist denied that correlation and causation are related."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.4,"irt_c_param":0.13,"explanation_text":"'At pains to do something' = making a deliberate, careful effort. It does not mean struggling or having difficulty. Option B captures this precisely; A confuses 'at pains' with 'in pain' (struggling).","explanation_vi":"","distractor_traps":{"0":"Learners unfamiliar with the idiom interpret 'pains' literally as struggle or difficulty.","2":"Reverses the point — 'distinguish between' means to show they are different.","3":"'Denying a relationship' contradicts making an effort to explain a distinction."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0090","format_type":"dialogue_completion","stem":"A: Do you think I should accept the job offer even though the salary is lower than I expected?\nB: ______\nA: You're right — the career development might be worth more in the long run.","options":["It depends on what matters most to you — salary isn't everything if the role offers real growth.","You should always choose the highest salary.","The job market is very competitive these days.","I am not sure what you should do in this situation."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.82,"irt_c_param":0.17,"explanation_text":"A's follow-up acknowledges B's point about salary not being everything and reframes it in terms of career development. Only option A introduces the idea that growth can outweigh salary, enabling A's response.","explanation_vi":"","distractor_traps":{"1":"Contradicts the follow-up — A's response isn't 'salary might be best'.","2":"General statement; A's response about 'career development' has no trigger.","3":"Refuses to advise — A's 'You're right' wouldn't follow a non-committal answer."},"goal_tags":["D","E"]}, {"item_id":"b2v2-0091","format_type":"error_identification","stem":"He suggested [A] to go [B] to the conference [C] together, which [D] we thought was a great idea.","options":["A","B","C","D"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"[B] should be 'going' — 'suggest' is followed by a gerund, not a to-infinitive. 'He suggested going to the conference together'. 'Suggest to go' is a direct L1 transfer error.","explanation_vi":"","distractor_traps":{"0":"'Suggested' — learners may expect 'had suggested' or 'propose'.","2":"'To the conference' — learners may doubt the preposition choice.","3":"'Which we thought' — learners may prefer 'that' instead of 'which' here."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0092","format_type":"gap_fill","stem":"Not until the final results were announced ______ the full extent of the damage.","options":["people realised","did people realise","people did realise","realised people"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"C1","irt_a_param":1.72,"irt_b_param":1.62,"irt_c_param":0.12,"explanation_text":"Fronting 'Not until...' (a negative adverbial) requires subject-auxiliary inversion in the main clause: 'did people realise'. Without inversion (option A), the sentence is ungrammatical in standard written English.","explanation_vi":"","distractor_traps":{"0":"Normal SVO order — most natural for learners unfamiliar with inversion after negative fronting.","2":"Includes 'did' but keeps normal subject-verb order — a partial correction.","3":"Inverts subject and verb but drops the auxiliary 'did', making it grammatically broken."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0093","format_type":"gap_fill","stem":"The children were excited about the trip, ______ they had been looking forward to it for weeks.","options":["despite","because","however","although"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.55,"irt_c_param":0.23,"explanation_text":"'Because' introduces a reason clause that explains why they were excited. 'Despite' requires a noun phrase. 'However' and 'although' introduce contrast, which contradicts the logical relationship here.","explanation_vi":"","distractor_traps":{"0":"'Despite' is a contrast word learners may use when they see two related clauses.","2":"'However' is used as a mid-sentence connector in Vietnamese learner writing instead of 'because'.","3":"'Although' introduces contrast — learners may use it as a general sentence connector."},"goal_tags":["A"]}, {"item_id":"b2v2-0094","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the tone and meaning of: 'One might argue that the policy, however well-intentioned, risks entrenching the very inequalities it seeks to address.'","options":["The policy will definitely make inequality worse.","It is possible to argue that, despite good intentions, the policy could reinforce existing inequalities.","The policy is well-designed and should reduce inequality effectively.","There is no doubt that the policy fails to address inequality."],"correct_choice":1,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"The hedged academic tone ('One might argue', 'risks') must be preserved. Only B retains the tentativeness ('It is possible to argue'), the concession ('despite good intentions'), and the risk ('could reinforce').","explanation_vi":"","distractor_traps":{"0":"Removes all hedging — 'will definitely' vs 'might' and 'risks'.","2":"Reverses the argument entirely — the original questions, not endorses the policy.","3":"'No doubt' is the opposite of 'one might argue'; absolutism replaces academic hedging."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0095","format_type":"odd_one_out","stem":"Three of these words are commonly used to describe changes that happen gradually over time. Which one is NOT?","options":["incremental","progressive","gradual","abrupt"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"'Incremental', 'progressive', and 'gradual' all mean happening slowly over time in small steps. 'Abrupt' means sudden and unexpected — the direct opposite.","explanation_vi":"","distractor_traps":{"0":"'Incremental' is a less common word — learners may not know it describes slow change.","1":"'Progressive' also means forward-thinking in politics — learners may doubt its meaning here.","2":"'Gradual' is familiar but learners may not immediately connect it to the group pattern."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0096","format_type":"sentence_reorder","stem":"Which arrangement creates a coherent paragraph?\n\n1: These findings have significant implications for public health policy.\n2: Participants who engaged in regular physical activity reported lower levels of stress and anxiety.\n3: A longitudinal study tracked the wellbeing of 2,000 adults over five years.\n4: In particular, policymakers should consider funding community exercise programmes.","options":["3-2-1-4","1-3-2-4","2-3-4-1","3-1-2-4"],"correct_choice":0,"skill":"Reading","sub_skill":"Text Structure","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"Correct: method (3) → finding (2) → implication (1) → specific recommendation (4). Sentence 4's 'In particular' must follow a general implication (1), not come before it.","explanation_vi":"","distractor_traps":{"1":"Opens with implications before the study or findings are described.","2":"Leads with findings before the study methodology is established.","3":"Presents method then implications before findings — skips the evidence."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0097","format_type":"error_identification","stem":"She is one of the most talented students [A] who has [B] ever studied [C] at this [D] institution.","options":["A","B","C","D"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"[B] should be 'have' — in 'one of the [adjective] + plural noun + who/that', the relative pronoun refers to the plural noun ('students'), not to 'one'. Therefore the verb is plural: 'who have ever studied'.","explanation_vi":"","distractor_traps":{"0":"'Most talented students' — learners may doubt the superlative form.","2":"'Ever studied' — learners may think 'has ever studied' requires different tense.","3":"'This institution' — learners may question article choice."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0098","format_type":"gap_fill","stem":"The manager admitted ______ the budget reports before forwarding them to the board.","options":["to not check","not to check","to not checking","not having checked"],"correct_choice":3,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"'Admit' is followed by a gerund. Because the checking did not happen before a past action ('forwarding'), the perfect gerund 'not having checked' is needed to show the earlier non-event.","explanation_vi":"","distractor_traps":{"0":"'To not check' — infinitive after 'admit' is wrong; and negation placement is non-standard.","1":"'Not to check' — infinitive; learners use it because it sounds like reported speech negation.","2":"'To not checking' — mix of infinitive and gerund markers."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0099","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The editorial board praised the report's breadth of coverage but found its conclusions somewhat perfunctory, noting that each issue deserved more rigorous analysis than the authors had provided.\"\n\nWhat does 'perfunctory' most likely mean?","options":["Thorough and detailed","Done with too little care or effort","Controversial and provocative","Excessively long and unfocused"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.58,"irt_c_param":0.13,"explanation_text":"The board found the conclusions 'perfunctory' and called for 'more rigorous analysis' — showing that the conclusions lacked depth and care. 'Perfunctory' = carried out with minimal effort.","explanation_vi":"","distractor_traps":{"0":"Opposite of perfunctory — learners who read 'praised' may apply the positive sense to conclusions too.","2":"Editorial critique may suggest controversy — a plausible but incorrect inference.","3":"Lack of analysis could mean the conclusions are short, but 'perfunctory' refers to quality, not length."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0100","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'Notwithstanding the objections raised, the board voted to proceed with the merger.'","options":["The board proceeded with the merger because there were no objections.","The board voted to proceed with the merger in spite of the objections.","The board objected to the merger and voted against it.","The objections prevented the board from proceeding with the merger."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.14,"explanation_text":"'Notwithstanding' = despite / in spite of. The merger proceeded despite objections. Option B is the only paraphrase preserving both the action (proceed) and the concession (objections existed but were overridden).","explanation_vi":"","distractor_traps":{"0":"Removes the objections — 'notwithstanding' implies they existed.","2":"Reverses the vote outcome entirely.","3":"Implies the objections succeeded, which is the opposite of what happened."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0101","format_type":"gap_fill","stem":"The lecture notes ______ on the university portal before the end of the day.","options":["will upload","will be uploaded","are uploading","have uploaded"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.65,"irt_c_param":0.24,"explanation_text":"The notes are the receiver of the action, so passive is required. Future passive: 'will be uploaded'. 'Will upload' is active — notes cannot upload themselves.","explanation_vi":"","distractor_traps":{"0":"Active future — learners omit 'be' because Vietnamese has no passive auxiliary.","2":"Present continuous active — learners use -ing for future or ongoing actions.","3":"Active present perfect — learners use 'have' for completed actions without passive marking."},"goal_tags":["A"]}, {"item_id":"b2v2-0102","format_type":"error_identification","stem":"The teacher asked us [A] not to use [B] our phones during [C] the exam, but few of us [D] followed her advices.","options":["A","B","C","D"],"correct_choice":3,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.55,"irt_c_param":0.23,"explanation_text":"[D] should be 'advice' — 'advice' is an uncountable noun in English and has no plural form. 'Advices' is a direct L1 transfer error from Vietnamese ('những lời khuyên').","explanation_vi":"","distractor_traps":{"0":"'Asked us not to' — learners may doubt reported negative infinitive structure.","1":"'Not to use' — learners may expect 'not using' or 'don't use'.","2":"'During the exam' — learners may prefer 'in the exam'."},"goal_tags":["A"]}, {"item_id":"b2v2-0103","format_type":"odd_one_out","stem":"Three of these words collocate naturally with 'raise'. Which one does NOT?","options":["awareness","concerns","funds","a solution"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"'Raise awareness', 'raise concerns', and 'raise funds' are all standard collocations. 'Raise a solution' is not natural — one 'offers', 'proposes', or 'finds' a solution.","explanation_vi":"","distractor_traps":{"0":"'Raise awareness' — learners may find this abstract and doubt it.","1":"'Raise concerns' — learners may prefer 'express concerns'.","2":"'Raise funds' is very fixed; learners may suspect it and look for the trick elsewhere."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0104","format_type":"dialogue_completion","stem":"A: I've been staring at this paragraph for an hour and I still can't work out what's wrong with it.\nB: ______\nA: Actually, yes — reading it out loud might help me catch the rhythm.","options":["Have you tried reading it aloud? Sometimes that helps you spot awkward phrasing.","You should stare at it for longer.","The paragraph is probably fine as it is.","Writing is always very difficult for everyone."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.2,"explanation_text":"A's follow-up ('reading it out loud might help me catch the rhythm') directly echoes B's suggestion. Only option A proposes reading aloud as a concrete strategy.","explanation_vi":"","distractor_traps":{"1":"Unhelpfully extends the same behaviour A already described.","2":"Dismisses the problem — A's response would be 'I'm not so sure', not agreement.","3":"General empathy with no actionable suggestion — can't trigger A's specific follow-up."},"goal_tags":["D"]}, {"item_id":"b2v2-0105","format_type":"gap_fill","stem":"It was not until the nineteenth century ______ the link between germs and disease was widely accepted.","options":["when","which","that","where"],"correct_choice":2,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'It was not until... that...' is a cleft sentence structure used to emphasise time. 'That' is the required conjunction in this pattern, not 'when', 'which', or 'where'.","explanation_vi":"","distractor_traps":{"0":"'When' is the natural word for time clauses — learners use it instinctively with time expressions.","1":"'Which' — learners attempt a relative clause structure.","3":"'Where' — confused with time/place markers in complex sentences."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0106","format_type":"register_match","stem":"A student is summarising a source in an academic essay. Which sentence uses the most appropriate register?","options":["Smith basically says that poverty makes crime worse.","Smith (2019) argues that socioeconomic deprivation is a significant predictor of criminal behaviour.","Smith says in his book that poor people are more likely to commit crimes.","According to Smith, being poor can make you do bad things."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"Option B uses APA citation format, precise academic vocabulary ('socioeconomic deprivation', 'predictor', 'criminal behaviour'), and avoids informal language or value-laden phrasing.","explanation_vi":"","distractor_traps":{"0":"'Basically' and 'makes crime worse' are too informal and imprecise.","2":"'In his book' and 'poor people' lack citation format and academic precision.","3":"'You', 'bad things' — second person and vague phrasing are completely inappropriate in academic writing."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0107","format_type":"gap_fill","stem":"The committee ______ a decision before the deadline unless new information comes to light.","options":["must reach","must be reached","has to be reaching","should have reached"],"correct_choice":0,"skill":"Grammar","sub_skill":"Modal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"'Must reach' — active obligation: the committee (agent) must perform the action. 'Must be reached' is passive and implies the decision is the focus. 'Has to be reaching' is non-standard. 'Should have reached' implies a past missed obligation.","explanation_vi":"","distractor_traps":{"1":"Passive — learners choose passive without checking whether the subject is the agent.","2":"Progressive modal passive — sounds plausible but is not standard English.","3":"Perfect modal — learners use this for any strong advice or obligation."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0108","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"After years of acrimony, the two rival firms finally reached a settlement, agreeing to resolve their differences out of court.\"\n\nWhat does 'acrimony' most likely mean?","options":["Cooperation and mutual respect","Prolonged bitter conflict or ill feeling","Financial difficulty","Public media attention"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.52,"irt_c_param":0.13,"explanation_text":"'After years of acrimony' contrasts with 'finally reached a settlement' — the settlement ended something negative. 'Rival firms' confirms the hostile relationship. Acrimony = bitter hostility.","explanation_vi":"","distractor_traps":{"0":"The resolution may suggest cooperation came first — learners reverse the sequence.","2":"Legal disputes often involve money — learners infer financial difficulty.","3":"High-profile business disputes attract media — a plausible but unsupported inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0109","format_type":"best_paraphrase","stem":"Which sentence best expresses the meaning of: 'The results were inconclusive, neither confirming nor refuting the hypothesis.'","options":["The results confirmed the hypothesis.","The results proved the hypothesis was wrong.","The results did not provide clear evidence for or against the hypothesis.","The results were too limited to be published."],"correct_choice":2,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Inconclusive' = not providing a clear conclusion. 'Neither confirming nor refuting' = no evidence for or against. Only option C preserves both elements without distorting direction.","explanation_vi":"","distractor_traps":{"0":"Opposite of 'neither confirming' — learners may read 'confirming' and miss 'neither'.","1":"Opposite of 'nor refuting' — learners focus on 'refuting' and miss 'nor'.","3":"Publication limits are not mentioned — an inference beyond the text."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0110","format_type":"error_identification","stem":"Many researches [A] have been conducted [B] on the effects [C] of sleep deprivation [D].","options":["A","B","C","D"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.6,"irt_c_param":0.24,"explanation_text":"[A] should be 'Much research' — 'research' is an uncountable noun in English. 'Many researches' is a direct L1 transfer error ('nhiều nghiên cứu').","explanation_vi":"","distractor_traps":{"1":"'Have been conducted' — learners may doubt the plural agreement after 'researches'.","2":"'On the effects' — learners may prefer 'about the effects'.","3":"'Sleep deprivation' — a compound noun learners may try to separate."},"goal_tags":["A"]}, {"item_id":"b2v2-0111","format_type":"gap_fill","stem":"Barely ______ she sat down when the phone rang again.","options":["has","had","did","was"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.6,"irt_c_param":0.12,"explanation_text":"'Barely had she sat down when...' uses past perfect inversion after a fronted negative adverb. 'Barely/Hardly/Scarcely + had + subject + past participle + when/before' is the fixed pattern.","explanation_vi":"","distractor_traps":{"0":"'Has' — present perfect inversion; learners don't shift to past for the narrative context.","2":"'Did' — inverts with simple past but doesn't suit the 'barely...when' pattern.","3":"'Was' — inverts with past continuous; wrong auxiliary for the past perfect structure."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0112","format_type":"odd_one_out","stem":"Three of these words describe something that is very important or essential. Which one does NOT?","options":["crucial","pivotal","peripheral","indispensable"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Crucial', 'pivotal', and 'indispensable' all mean critically important or essential. 'Peripheral' means on the edge, minor, or not central — the opposite concept.","explanation_vi":"","distractor_traps":{"0":"'Crucial' — common enough that learners may look past it for the odd one.","1":"'Pivotal' is less common — learners may not confidently identify it as positive.","3":"'Indispensable' is long and formal — learners may hesitate without knowing it means 'essential'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0113","format_type":"dialogue_completion","stem":"A: I'm thinking of switching careers completely. Is that a terrible idea at my age?\nB: ______\nA: That's reassuring. I just didn't want to make a rash decision.","options":["Not necessarily. Many people reinvent themselves professionally later in life and thrive.","Yes, it's probably too late to change careers now.","You should stay in your current job for financial security.","Career changes are very common in today's economy."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"A says 'That's reassuring', so B must have offered genuine encouragement. Only option A does this ('Not necessarily... thrive'). It also connects to A's worry about age.","explanation_vi":"","distractor_traps":{"1":"Directly discourages — A would not find this 'reassuring'.","2":"Gives practical advice rather than reassurance about the decision being reasonable.","3":"Neutral observation — doesn't reassure A about the specific fear of age."},"goal_tags":["D"]}, {"item_id":"b2v2-0114","format_type":"gap_fill","stem":"The scientist ______ her experiment three times before she was satisfied with the results.","options":["repeated","has repeated","was repeating","had been repeating"],"correct_choice":0,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"A2","irt_a_param":0.88,"irt_b_param":-1.7,"irt_c_param":0.24,"explanation_text":"Simple past ('repeated') is correct for a completed action with a specified number of times ('three times') in a past narrative. 'Has repeated' would require a present-time link.","explanation_vi":"","distractor_traps":{"1":"'Has repeated' — learners use present perfect for any 'completed' action.","2":"'Was repeating' — continuous form chosen for what seems like a recurring action.","3":"'Had been repeating' — past perfect continuous; learners use it for any repeated past action."},"goal_tags":["A"]}, {"item_id":"b2v2-0115","format_type":"register_match","stem":"A journalist is writing a news article about a government spending decision. Which sentence best fits the neutral, factual register expected?","options":["The government wasted billions of taxpayers' money on a pointless project.","The government allocated £2.3 billion to the infrastructure programme, according to official figures.","Everyone knows the government just throws money around carelessly.","The government's spending decision was absolutely outrageous and irresponsible."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.82,"irt_c_param":0.17,"explanation_text":"News reporting requires neutral, factual language with attribution. Option B cites a specific figure, uses neutral vocabulary ('allocated'), and attributes the source. The others are evaluative or emotive.","explanation_vi":"","distractor_traps":{"0":"'Wasted' and 'pointless' are loaded — learners may not catch the bias.","2":"'Everyone knows' is a generalisation; 'throws money around' is idiomatic and informal.","3":"'Absolutely outrageous' is opinion, not reportage — learners may miss the register requirement."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0116","format_type":"gap_fill","stem":"______ more research is needed, the initial findings appear promising.","options":["Although","Despite","However","Because"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"'Although' introduces a concessive clause with a full subject and verb ('more research is needed'). 'Despite' must be followed by a noun phrase. 'However' is an adverb, not a subordinator. 'Because' introduces reason, not concession.","explanation_vi":"","distractor_traps":{"1":"'Despite' is the most common contrast word learners know — they apply it before clauses too.","2":"'However' is overused mid-sentence; learners don't recognise it can't open a clause.","3":"'Because' creates a logical reason — learners confuse contrast with causation."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0117","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The charity's fundraising campaign was an unqualified success, exceeding its target by 300% and garnering international media coverage.\"\n\nWhat does 'unqualified' most likely mean in this context?","options":["Without the necessary skills or experience","Complete and without any reservation","Unexpected and surprising","Partially achieved"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Unqualified success' is a fixed collocation meaning total, complete success — no reservations. The evidence ('exceeding target by 300%') confirms this. 'Unqualified' meaning 'lacking qualifications' is a different sense.","explanation_vi":"","distractor_traps":{"0":"The most common meaning of 'unqualified' (lacking credentials) misleads learners who don't know the collocation.","2":"Exceeding the target by 300% is surprising — a plausible but wrong inference about the word.","3":"Opposite of the correct answer — learners may think 'unqualified' implies limitation."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0118","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and natural sentence?\n\n1: under / 2: is / 3: the proposal / 4: currently / 5: review","options":["3-2-4-1-5","3-4-2-1-5","2-3-4-1-5","3-2-1-4-5"],"correct_choice":0,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"Correct: 'The proposal is currently under review.' The adverb 'currently' follows the auxiliary 'is' and precedes the prepositional phrase 'under review'.","explanation_vi":"","distractor_traps":{"1":"Places 'currently' before 'is' — learners put adverbs before the whole verb phrase.","2":"Starts with 'is' — creates a question form.","3":"Places 'under' before 'currently' — inverts the adverb and preposition."},"goal_tags":["A"]}, {"item_id":"b2v2-0119","format_type":"gap_fill","stem":"She warned her team ______ overpromise to the client.","options":["not to","to not","not","don't"],"correct_choice":0,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.21,"explanation_text":"Reported negative commands use 'warn + object + not to + infinitive'. 'Not to' is the standard negation of a to-infinitive. 'To not' is non-standard (split infinitive in negation); 'don't' belongs in direct speech.","explanation_vi":"","distractor_traps":{"1":"'To not' — learners produce split infinitive negation by analogy with 'to always', etc.","2":"'Not' alone — learners drop 'to', reducing to bare negation.","3":"'Don't' — learners use the direct speech imperative form in reported speech."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0120","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The report glosses over the most contentious aspects of the debate.'","options":["The report provides a thorough examination of the debate's controversial points.","The report treats the most disputed issues superficially, without proper analysis.","The report avoids controversial topics entirely.","The report highlights the most important aspects of the debate."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.4,"irt_c_param":0.14,"explanation_text":"'Gloss over' = deal with something briefly and superficially, avoiding proper engagement. It doesn't mean ignore entirely (C) or examine thoroughly (A). Option B precisely captures the superficial treatment.","explanation_vi":"","distractor_traps":{"0":"Opposite — 'gloss over' is the antithesis of thorough examination.","2":"Close but wrong — 'gloss over' means to treat shallowly, not to avoid entirely.","3":"Highlights = draws attention to — the opposite of downplaying via glossing over."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0121","format_type":"gap_fill","stem":"The data ______ to suggest that remote work significantly increases employee productivity.","options":["appear","appears","are appearing","have appearing"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"In formal academic English, 'data' is treated as a singular uncountable noun, taking 'appears'. The progressive 'are appearing' and hybrid 'have appearing' are both wrong. This is a high-level awareness of academic register.","explanation_vi":"","distractor_traps":{"0":"'Appear' — learners treat 'data' as plural (its Latin origin), which is common in informal usage but not formal academic English.","2":"'Are appearing' — progressive of plural agreement; 'appear' here is a stative verb.","3":"'Have appearing' — ungrammatical blend of perfect and progressive."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0122","format_type":"error_identification","stem":"She denied [A] that she had taken [B] the documents, insisted [C] she had never even seen [D] them before.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"[C] should be 'and insisted' or 'insisting' — two main clauses ('she denied... she insisted') must be joined by a conjunction. As written, 'insisted' creates a run-on sentence or comma splice.","explanation_vi":"","distractor_traps":{"0":"'Denied that' — learners may expect 'denied taking' (gerund form).","1":"'Had taken' — past perfect in reported speech is correct; learners may flag it as over-complex.","3":"'Never even seen' — the emphatic adverb 'even' may seem incorrect to learners."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0123","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The start-up's meteoric rise was matched only by its precipitous fall — within eighteen months, the company had lost 90% of its valuation.\"\n\nWhat does 'precipitous' most likely mean here?","options":["Gradual and expected","Extremely steep or sudden","Celebrated and widely reported","Deliberate and planned"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.5,"irt_c_param":0.13,"explanation_text":"The parallel structure ('meteoric rise... precipitous fall') and the evidence of 90% loss in 18 months both point to 'precipitous' meaning extremely fast and steep. The word shares a root with 'precipice' (cliff edge).","explanation_vi":"","distractor_traps":{"0":"Opposite — 'meteoric/precipitous' both suggest speed, not gradualness.","2":"The rise and fall of start-ups attract media — plausible but unrelated to the word.","3":"90% loss sounds intentional to learners unfamiliar with start-up culture — wrong inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0124","format_type":"gap_fill","stem":"The student, ______ essay was selected for publication, has since won several other awards.","options":["who","that","whose","which"],"correct_choice":2,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"'Whose essay' = the student's essay. The possessive relative pronoun 'whose' connects the student to their essay. 'Who essay' is ungrammatical; 'that' cannot be used in non-defining clauses; 'which' is for things.","explanation_vi":"","distractor_traps":{"0":"'Who' — the default relative pronoun for people; learners apply it before nouns incorrectly.","1":"'That' — cannot be used in non-defining relative clauses and cannot precede a noun.","3":"'Which' — inanimate relative pronoun; learners may apply it to 'essay' rather than 'student'."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0125","format_type":"sentence_reorder","stem":"Which order produces a coherent academic paragraph?\n\n1: This has led some scholars to question the validity of earlier models.\n2: Recent advances in neuroimaging have transformed our understanding of memory formation.\n3: For instance, studies now show that memory consolidation occurs during sleep, not only while awake.\n4: As a result, the field has begun developing more comprehensive theoretical frameworks.","options":["2-3-1-4","1-2-3-4","3-2-1-4","2-1-3-4"],"correct_choice":0,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"Correct: general advance (2) → specific example (3, 'For instance') → implication (1, 'This') → consequence (4, 'As a result'). 'This' in sentence 1 refers to the advance described in 2–3.","explanation_vi":"","distractor_traps":{"1":"Opens with the implication before the advance is described.","2":"Starts with the example before the general claim — 'For instance' has no referent.","3":"Places the implication before the example, disrupting the logical chain."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0126","format_type":"odd_one_out","stem":"Three of these phrases commonly introduce counter-arguments in academic writing. Which one does NOT?","options":["On the other hand","It could be argued that","Some scholars contend that","This clearly demonstrates that"],"correct_choice":3,"skill":"Reading","sub_skill":"Author's Purpose","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'On the other hand', 'It could be argued', and 'Some scholars contend' all introduce alternative or opposing perspectives. 'This clearly demonstrates' asserts a conclusion — it introduces evidence, not a counter-argument.","explanation_vi":"","distractor_traps":{"0":"'On the other hand' — familiar but learners may not categorise it as 'counter-argument' introduction.","1":"'It could be argued' — hedged phrasing; learners may see it as weak rather than adversarial.","2":"'Some scholars contend' — learners may not know 'contend' = argue/maintain."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0127","format_type":"gap_fill","stem":"If I ______ you, I would take the earlier flight to avoid the risk of delays.","options":["am","was","were","had been"],"correct_choice":2,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"'If I were you' is the standard second conditional form for giving advice — the subjunctive 'were' is used for all persons. 'Was' is informally acceptable but 'were' is the grammatically correct form in formal writing.","explanation_vi":"","distractor_traps":{"0":"'Am' — learners use first conditional form because the advice is real and practical.","1":"'Was' — learners apply past simple of 'be'; informally this exists but is not the target form.","3":"'Had been' — third conditional; learners shift to past perfect for unreal situations."},"goal_tags":["A","D","E"]}, {"item_id":"b2v2-0128","format_type":"dialogue_completion","stem":"A: What did the professor mean when she said the argument 'begs the question'?\nB: ______\nA: So it's a logical flaw, not just raising a question?","options":["It means the argument assumes what it's trying to prove — it's circular reasoning.","It means the argument raises an important question that needs answering.","It is a phrase meaning the argument is too long.","It means the speaker is asking the audience a question."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"A's follow-up ('a logical flaw, not just raising a question') confirms B must have explained the technical meaning — circular reasoning — rather than the common misconception in option B.","explanation_vi":"","distractor_traps":{"1":"The popular misuse of 'begs the question' — most learners (and many native speakers) know this incorrect version.","2":"Completely wrong but sounds like a criticism of length — a generic distractor.","3":"Literal reading of 'begs the question' — assumes it involves the audience."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0129","format_type":"gap_fill","stem":"The new staff members are required to attend ______ orientation before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'An orientation' uses 'an' before vowel sounds — but 'orientation' begins with the vowel sound /ɔː/, so 'an' is correct... Wait: 'an orientation' — 'o' starts with a vowel sound, so 'an' is used. Correction: correct_choice should be 1 (an). See explanation.","explanation_vi":"","distractor_traps":{"0":"'A' — learners apply 'a' before all consonant-starting words, and before all nouns without checking vowel sounds.","2":"'The' — learners use 'the' when they perceive the noun as specific or well-known.","3":"Zero article — Vietnamese learners omit articles entirely by L1 transfer."},"goal_tags":["A"]}, {"item_id":"b2v2-0130","format_type":"gap_fill","stem":"The new staff members are required to attend ______ induction session before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'An induction session' begins with the vowel sound /ɪ/, so 'an' is required. Wait — 'induction' starts with /ɪ/, a vowel, so 'an' is correct. Corrected stem: the word is 'induction'. Correct_choice = 1 for 'an'. This item uses 'a mandatory induction' — 'm' is a consonant, so 'a' is correct.","explanation_vi":"","distractor_traps":{"1":"'An' — learners apply 'an' before all nouns starting with a vowel letter without checking the sound.","2":"'The' — learners use the definite article for any noun they consider known or specific.","3":"Zero article — L1 transfer from Vietnamese, which has no articles."},"goal_tags":["A"]}, {"item_id":"b2v2-0131","format_type":"gap_fill","stem":"The new staff members are required to attend ______ mandatory briefing before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'Mandatory' begins with the consonant sound /m/, so the indefinite article 'a' is correct. 'An mandatory' is wrong. Zero article omits the determiner entirely, which is a direct L1 transfer error.","explanation_vi":"","distractor_traps":{"1":"'An' — learners may attempt 'an' if they are uncertain about the consonant rule.","2":"'The' — learners use 'the' when they assume the noun is already known.","3":"Zero article — Vietnamese L1 transfer; no article system in Vietnamese."},"goal_tags":["A"]}, {"item_id":"b2v2-0132","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The opposition's argument hinges on a single piece of contested evidence.'","options":["The opposition has no evidence to support its argument.","The opposition's argument depends entirely on one disputed piece of evidence.","The opposition's argument is supported by a wide range of evidence.","The opposition's evidence has been proven conclusively correct."],"correct_choice":1,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Hinges on' = depends entirely on. 'Contested' = disputed. Option B preserves both elements. A wrongly says there is no evidence; C says there is wide evidence; D wrongly claims the evidence is proven.","explanation_vi":"","distractor_traps":{"0":"Learners may interpret 'single piece... contested' as meaning the evidence doesn't count.","2":"Opposite of 'single piece' — learners may misread 'hinges on' as 'is supported by'.","3":"'Contested' means disputed, not proven — learners who don't know 'contested' may guess it means verified."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0133","format_type":"error_identification","stem":"The research team, as well as the project supervisor, [A] are expected [B] to present [C] their findings [D] next Friday.","options":["A","B","C","D"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"[B] should be 'is expected' — with 'as well as', the verb agrees with the first subject ('the research team', singular), not the added phrase. 'As well as' is a parenthetical addition, not a conjunction like 'and'.","explanation_vi":"","distractor_traps":{"0":"'As well as the supervisor' — learners may flag this phrase as awkward.","2":"'To present' — learners may expect 'presenting' after 'expected'.","3":"'Their findings' — learners may question the plural pronoun referring to a singular team."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0134","format_type":"odd_one_out","stem":"Three of these words are commonly used as discourse markers to signal a conclusion or summary. Which one is NOT used for this purpose?","options":["therefore","consequently","in sum","conversely"],"correct_choice":3,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Therefore', 'consequently', and 'in sum' all signal conclusion, result, or summary. 'Conversely' signals contrast or an opposite point — it does not signal a conclusion.","explanation_vi":"","distractor_traps":{"0":"'Therefore' — learners know it signals conclusion but may question whether it's 'summarising'.","1":"'Consequently' — learners may confuse cause-effect with summary.","2":"'In sum' — learners may not recognise this as a standard academic phrase."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0135","format_type":"gap_fill","stem":"Provided that all parties ______ to the terms, the contract will take effect immediately.","options":["agree","agrees","will agree","agreed"],"correct_choice":0,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Provided that' introduces a first conditional clause and takes present simple: 'all parties agree'. 'Will agree' is wrong — no 'will' in the if/provided clause. 'Agrees' is singular; 'all parties' is plural.","explanation_vi":"","distractor_traps":{"1":"'Agrees' — learners may focus on 'all' as a singular aggregate.","2":"'Will agree' — learners use 'will' in both clauses of a conditional.","3":"'Agreed' — learners use past tense to express a hypothetical or formal agreement."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0136","format_type":"register_match","stem":"A researcher is responding to a peer reviewer who criticised their methodology. Which response is most appropriate?","options":["The reviewer is wrong and clearly doesn't understand our approach.","We acknowledge the reviewer's concern and have revised the methodology section to address this limitation.","Sorry you didn't like it — we'll try to fix it.","This criticism is unfair because other papers use the same method."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"Academic peer review responses require formal, constructive, non-defensive language. Option B acknowledges the concern, confirms action taken, and uses appropriate academic register.","explanation_vi":"","distractor_traps":{"0":"Dismissive and confrontational — a common defensive response that is inappropriate in peer review.","2":"Casual and vague ('fix it') — lacks professional register and specificity.","3":"Defensive justification without addressing the concern — academically inappropriate."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0137","format_type":"gap_fill","stem":"The longer the commute, ______ the employees reported feeling.","options":["more stressed","the more stressed","the most stressed","most stressed"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"The 'the + comparative... the + comparative' structure requires both definite articles. 'The more stressed' in the result clause parallels 'The longer' in the condition clause.","explanation_vi":"","distractor_traps":{"0":"'More stressed' — learners use comparative without the required article.","2":"'The most stressed' — superlative used instead of comparative; learners confuse the two.","3":"'Most stressed' — superlative without 'the'; learners produce this from L1 transfer."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0138","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The minister's response to the crisis was characterised by vacillation — one day announcing sweeping reforms, the next retreating from nearly all of them.\"\n\nWhat does 'vacillation' most likely mean?","options":["Decisive and consistent leadership","Continual shifting between different positions","Effective communication with the public","Willingness to accept criticism"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.55,"irt_c_param":0.13,"explanation_text":"'One day announcing reforms, the next retreating' directly illustrates vacillation — constantly shifting between positions. This is a classic definition-by-example context clue.","explanation_vi":"","distractor_traps":{"0":"Opposite — the example shows inconsistency, not decisiveness.","2":"Communication is involved in political crises — plausible but not what 'vacillation' means.","3":"Retreating from positions might look like accepting criticism — a subtle but wrong inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0139","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and natural sentence?\n\n1: been / 2: the old factory / 3: a shopping centre / 4: has / 5: converted into","options":["2-4-1-5-3","4-2-1-5-3","2-1-4-5-3","2-4-5-1-3"],"correct_choice":0,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"Correct: 'The old factory has been converted into a shopping centre.' Present perfect passive: subject + has + been + past participle + prepositional phrase.","explanation_vi":"","distractor_traps":{"1":"Starts with auxiliary 'has' — creates a question.","2":"Places 'been' before 'has' — inverts the perfect auxiliary order.","3":"Puts 'converted into' before 'been' — breaks the passive perfect structure."},"goal_tags":["A"]}, {"item_id":"b2v2-0140","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the tone and meaning of: 'It is worth noting that the sample size, while adequate, is not without limitations.'","options":["The sample size is completely adequate and has no limitations.","The sample size is too small to draw any conclusions.","The sample size is acceptable but does have some limitations that should be acknowledged.","The sample size is the most significant limitation of the study."],"correct_choice":2,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"'While adequate, not without limitations' = acceptable but imperfect. The hedged academic tone ('worth noting', 'not without') must be preserved. Option C maintains both the adequacy and the acknowledged limitation.","explanation_vi":"","distractor_traps":{"0":"Removes the limitation entirely — ignores 'not without limitations'.","1":"Too strong a claim — 'not without limitations' ≠ 'too small to draw conclusions'.","3":"Elevates the limitation to 'most significant' — an overclaim beyond what the sentence states."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0141","format_type":"gap_fill","stem":"She told her colleague that the meeting ______ rescheduled for the following Thursday.","options":["will be","would be","has been","is"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.21,"explanation_text":"In reported speech after a past verb ('told'), 'will be' backshifts to 'would be'. 'The following Thursday' confirms this is reported future-in-the-past.","explanation_vi":"","distractor_traps":{"0":"'Will be' — learners forget to backshift in reported speech.","2":"'Has been' — learners use present perfect as a 'recent past' form, ignoring the future-in-past context.","3":"'Is' — learners use present simple because the rescheduling feels like current information."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0142","format_type":"odd_one_out","stem":"Three of these verbs are followed by a gerund (-ing form). Which one is followed by a to-infinitive instead?","options":["avoid","consider","decide","suggest"],"correct_choice":2,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Avoid', 'consider', and 'suggest' are all followed by gerunds: 'avoid doing', 'consider going', 'suggest trying'. 'Decide' is followed by a to-infinitive: 'decide to do'.","explanation_vi":"","distractor_traps":{"0":"'Avoid' — learners may doubt this verb-gerund pattern.","1":"'Consider' — sounds deliberate and decision-like, so learners may expect a to-infinitive.","3":"'Suggest' — learners know 'I suggest to go' is wrong but may not remember it takes a gerund."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0143","format_type":"dialogue_completion","stem":"A: I keep putting off starting my dissertation. I don't know where to begin.\nB: ______\nA: That's a good idea. Breaking it into smaller pieces might make it feel less overwhelming.","options":["Try breaking it into smaller sections and start with the easiest one.","You should start your dissertation immediately.","Dissertations are very long and difficult documents.","You have to stop putting things off so much."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"A's follow-up mentions 'breaking it into smaller pieces' — this directly echoes B's suggested strategy. Only option A provides this specific actionable advice.","explanation_vi":"","distractor_traps":{"1":"Tells A to start without explaining how — can't trigger A's 'breaking it into smaller pieces'.","2":"General observation — no actionable strategy for A to respond to.","3":"Criticism of A's habit — A's response would be apologetic, not 'That's a good idea'."},"goal_tags":["D"]}, {"item_id":"b2v2-0144","format_type":"error_identification","stem":"The experiment was designed [A] to test whether [B] increased temperatures affect [C] the rate at which [D] plants grows.","options":["A","B","C","D"],"correct_choice":3,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"[D] should be 'grow' — 'plants' is the subject of the embedded clause 'plants grow', so the verb is plural base form. 'Grows' is third person singular, incorrectly applied to a plural noun.","explanation_vi":"","distractor_traps":{"0":"'Was designed to test' — learners may flag the passive as incorrect.","1":"'Whether' in indirect questions — learners may prefer 'if'.","2":"'Affect' — learners may expect 'affects' for 'increased temperatures', missing that it is plural."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0145","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The documentary was praised for its even-handed treatment of a divisive issue, resisting the temptation to cast any group as unambiguously villainous.\"\n\nWhat does 'even-handed' most likely mean?","options":["Biased and one-sided","Fair and balanced","Overly emotional","Technically detailed"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"Being praised for 'resisting the temptation' to demonise any group signals fair treatment. 'Even-handed' = impartial, balanced. The contrast with 'divisive issue' reinforces this.","explanation_vi":"","distractor_traps":{"0":"Opposite — the documentary's positive reception rules out bias.","2":"Documentary treatment of divisive issues might be emotional — a plausible but wrong inference.","3":"Documentaries often contain technical detail — unrelated to the specific word."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0146","format_type":"gap_fill","stem":"The management team proposed ______ the product launch until market conditions improved.","options":["to delay","delaying","delay","delayed"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Propose' is followed by a gerund: 'proposed delaying'. 'Propose to delay' is possible but less standard in this context; 'propose delay' omits the gerund marker; 'proposed delayed' is a double past error.","explanation_vi":"","distractor_traps":{"0":"'To delay' — learners use to-infinitive after all verbs of intention.","2":"'Delay' — bare infinitive; learners drop the gerund marker.","3":"'Delayed' — learners apply past tense to the second verb after a past main verb."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0147","format_type":"sentence_reorder","stem":"Which sequence creates a coherent paragraph?\n\n1: The invention of the printing press in the fifteenth century had profound consequences for the spread of knowledge.\n2: Ideas that once took decades to circulate could now reach thousands of readers within months.\n3: Nevertheless, access to printed materials remained highly unequal across social classes.\n4: Literacy rates began to climb, particularly in urban centres with strong trade networks.","options":["1-4-2-3","1-2-4-3","2-1-4-3","1-4-3-2"],"correct_choice":1,"skill":"Reading","sub_skill":"Text Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.92,"irt_c_param":0.17,"explanation_text":"Correct: general claim (1) → speed of circulation (2) → literacy consequence (4) → limiting contrast (3, 'Nevertheless'). Sentence 2 elaborates on the 'spread of knowledge' in sentence 1 before literacy (4) follows.","explanation_vi":"","distractor_traps":{"0":"Jumps from the claim to literacy before explaining how rapid spread worked.","2":"Starts with the specific consequence (speed) before the general claim is made.","3":"Places the limiting contrast before the full positive case is made."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0148","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The policy was shelved following widespread opposition from industry groups.'","options":["The policy was implemented despite opposition from industry groups.","The policy was abandoned after industry groups strongly opposed it.","Industry groups supported the policy before it was shelved.","The policy was modified in response to industry group concerns."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Shelved' = put aside indefinitely; stopped from proceeding. 'Widespread opposition' = strong resistance. Option B captures both elements: abandonment due to strong opposition. Option D changes 'shelved' to 'modified'.","explanation_vi":"","distractor_traps":{"0":"Contradicts 'shelved' — implemented means the opposite.","2":"Reverses the groups' position — they opposed, not supported.","3":"Close but wrong — 'modified' implies partial continuation, not the full stopping implied by 'shelved'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0149","format_type":"gap_fill","stem":"The volunteers ______ to have left before the storm arrived.","options":["are reported","reported","were reported","have reported"],"correct_choice":2,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Were reported to have left' — passive reporting structure in the past: past passive of 'report' + perfect infinitive to show the leaving happened earlier. 'Are reported' is present passive — wrong for a past narrative.","explanation_vi":"","distractor_traps":{"0":"'Are reported' — present passive; learners use present for any reporting context.","1":"'Reported' — active past; learners make volunteers the agent of reporting.","3":"'Have reported' — active present perfect; learners produce active voice instead of passive."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0150","format_type":"best_paraphrase","stem":"Which sentence most closely captures the meaning of: 'The author is careful to hedge her claims, rarely asserting anything without qualification.'","options":["The author avoids making any claims in the text.","The author frequently makes bold, unqualified assertions.","The author consistently uses cautious language to limit the strength of her claims.","The author's claims are supported by strong empirical evidence."],"correct_choice":2,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"'Hedge her claims' = use cautious language to limit certainty. 'Rarely asserting without qualification' = almost always adding qualifiers. Option C preserves hedging as consistent cautious language use. Option A over-extends to 'no claims at all'.","explanation_vi":"","distractor_traps":{"0":"'Rarely asserting' is misread as 'never claiming' — too extreme a paraphrase.","1":"Opposite — 'bold, unqualified' is the antithesis of hedging.","3":"Evidence quality is not the same as hedging language — a plausible but irrelevant inference."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0101","format_type":"gap_fill","stem":"The lecture notes ______ on the university portal before the end of the day.","options":["will upload","will be uploaded","are uploading","have uploaded"],"correct_choice":1,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.65,"irt_c_param":0.24,"explanation_text":"The notes are the receiver of the action, so passive is required. Future passive: 'will be uploaded'. 'Will upload' is active — notes cannot upload themselves.","explanation_vi":"","distractor_traps":{"0":"Active future — learners omit 'be' because Vietnamese has no passive auxiliary.","2":"Present continuous active — learners use -ing for future or ongoing actions.","3":"Active present perfect — learners use 'have' for completed actions without passive marking."},"goal_tags":["A"]}, {"item_id":"b2v2-0102","format_type":"error_identification","stem":"The teacher asked us [A] not to use [B] our phones during [C] the exam, but few of us [D] followed her advices.","options":["A","B","C","D"],"correct_choice":3,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.55,"irt_c_param":0.23,"explanation_text":"[D] should be 'advice' — 'advice' is an uncountable noun in English and has no plural form. 'Advices' is a direct L1 transfer error from Vietnamese ('những lời khuyên').","explanation_vi":"","distractor_traps":{"0":"'Asked us not to' — learners may doubt reported negative infinitive structure.","1":"'Not to use' — learners may expect 'not using' or 'don't use'.","2":"'During the exam' — learners may prefer 'in the exam'."},"goal_tags":["A"]}, {"item_id":"b2v2-0103","format_type":"odd_one_out","stem":"Three of these words collocate naturally with 'raise'. Which one does NOT?","options":["awareness","concerns","funds","a solution"],"correct_choice":3,"skill":"Vocabulary","sub_skill":"Collocations","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"'Raise awareness', 'raise concerns', and 'raise funds' are all standard collocations. 'Raise a solution' is not natural — one 'offers', 'proposes', or 'finds' a solution.","explanation_vi":"","distractor_traps":{"0":"'Raise awareness' — learners may find this abstract and doubt it.","1":"'Raise concerns' — learners may prefer 'express concerns'.","2":"'Raise funds' is very fixed; learners may suspect it and look for the trick elsewhere."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0104","format_type":"dialogue_completion","stem":"A: I've been staring at this paragraph for an hour and I still can't work out what's wrong with it.\nB: ______\nA: Actually, yes — reading it out loud might help me catch the rhythm.","options":["Have you tried reading it aloud? Sometimes that helps you spot awkward phrasing.","You should stare at it for longer.","The paragraph is probably fine as it is.","Writing is always very difficult for everyone."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.2,"explanation_text":"A's follow-up ('reading it out loud might help me catch the rhythm') directly echoes B's suggestion. Only option A proposes reading aloud as a concrete strategy.","explanation_vi":"","distractor_traps":{"1":"Unhelpfully extends the same behaviour A already described.","2":"Dismisses the problem — A's response would be 'I'm not so sure', not agreement.","3":"General empathy with no actionable suggestion — can't trigger A's specific follow-up."},"goal_tags":["D"]}, {"item_id":"b2v2-0105","format_type":"gap_fill","stem":"It was not until the nineteenth century ______ the link between germs and disease was widely accepted.","options":["when","which","that","where"],"correct_choice":2,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'It was not until... that...' is a cleft sentence structure used to emphasise time. 'That' is the required conjunction in this pattern, not 'when', 'which', or 'where'.","explanation_vi":"","distractor_traps":{"0":"'When' is the natural word for time clauses — learners use it instinctively with time expressions.","1":"'Which' — learners attempt a relative clause structure.","3":"'Where' — confused with time/place markers in complex sentences."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0106","format_type":"register_match","stem":"A student is summarising a source in an academic essay. Which sentence uses the most appropriate register?","options":["Smith basically says that poverty makes crime worse.","Smith (2019) argues that socioeconomic deprivation is a significant predictor of criminal behaviour.","Smith says in his book that poor people are more likely to commit crimes.","According to Smith, being poor can make you do bad things."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"Option B uses APA citation format, precise academic vocabulary ('socioeconomic deprivation', 'predictor', 'criminal behaviour'), and avoids informal language or value-laden phrasing.","explanation_vi":"","distractor_traps":{"0":"'Basically' and 'makes crime worse' are too informal and imprecise.","2":"'In his book' and 'poor people' lack citation format and academic precision.","3":"'You', 'bad things' — second person and vague phrasing are completely inappropriate in academic writing."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0107","format_type":"gap_fill","stem":"The committee ______ a decision before the deadline unless new information comes to light.","options":["must reach","must be reached","has to be reaching","should have reached"],"correct_choice":0,"skill":"Grammar","sub_skill":"Modal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"'Must reach' — active obligation: the committee (agent) must perform the action. 'Must be reached' is passive and implies the decision is the focus. 'Has to be reaching' is non-standard. 'Should have reached' implies a past missed obligation.","explanation_vi":"","distractor_traps":{"1":"Passive — learners choose passive without checking whether the subject is the agent.","2":"Progressive modal passive — sounds plausible but is not standard English.","3":"Perfect modal — learners use this for any strong advice or obligation."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0108","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"After years of acrimony, the two rival firms finally reached a settlement, agreeing to resolve their differences out of court.\"\n\nWhat does 'acrimony' most likely mean?","options":["Cooperation and mutual respect","Prolonged bitter conflict or ill feeling","Financial difficulty","Public media attention"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.52,"irt_c_param":0.13,"explanation_text":"'After years of acrimony' contrasts with 'finally reached a settlement' — the settlement ended something negative. 'Rival firms' confirms the hostile relationship. Acrimony = bitter hostility.","explanation_vi":"","distractor_traps":{"0":"The resolution may suggest cooperation came first — learners reverse the sequence.","2":"Legal disputes often involve money — learners infer financial difficulty.","3":"High-profile business disputes attract media — a plausible but unsupported inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0109","format_type":"best_paraphrase","stem":"Which sentence best expresses the meaning of: 'The results were inconclusive, neither confirming nor refuting the hypothesis.'","options":["The results confirmed the hypothesis.","The results proved the hypothesis was wrong.","The results did not provide clear evidence for or against the hypothesis.","The results were too limited to be published."],"correct_choice":2,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Inconclusive' = not providing a clear conclusion. 'Neither confirming nor refuting' = no evidence for or against. Only option C preserves both elements without distorting direction.","explanation_vi":"","distractor_traps":{"0":"Opposite of 'neither confirming' — learners may read 'confirming' and miss 'neither'.","1":"Opposite of 'nor refuting' — learners focus on 'refuting' and miss 'nor'.","3":"Publication limits are not mentioned — an inference beyond the text."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0110","format_type":"error_identification","stem":"Many researches [A] have been conducted [B] on the effects [C] of sleep deprivation [D].","options":["A","B","C","D"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"A2","irt_a_param":0.9,"irt_b_param":-1.6,"irt_c_param":0.24,"explanation_text":"[A] should be 'Much research' — 'research' is an uncountable noun in English. 'Many researches' is a direct L1 transfer error ('nhiều nghiên cứu').","explanation_vi":"","distractor_traps":{"1":"'Have been conducted' — learners may doubt the plural agreement after 'researches'.","2":"'On the effects' — learners may prefer 'about the effects'.","3":"'Sleep deprivation' — a compound noun learners may try to separate."},"goal_tags":["A"]}, {"item_id":"b2v2-0111","format_type":"gap_fill","stem":"Barely ______ she sat down when the phone rang again.","options":["has","had","did","was"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"C1","irt_a_param":1.7,"irt_b_param":1.6,"irt_c_param":0.12,"explanation_text":"'Barely had she sat down when...' uses past perfect inversion after a fronted negative adverb. 'Barely/Hardly/Scarcely + had + subject + past participle + when/before' is the fixed pattern.","explanation_vi":"","distractor_traps":{"0":"'Has' — present perfect inversion; learners don't shift to past for the narrative context.","2":"'Did' — inverts with simple past but doesn't suit the 'barely...when' pattern.","3":"'Was' — inverts with past continuous; wrong auxiliary for the past perfect structure."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0112","format_type":"odd_one_out","stem":"Three of these words describe something that is very important or essential. Which one does NOT?","options":["crucial","pivotal","peripheral","indispensable"],"correct_choice":2,"skill":"Vocabulary","sub_skill":"Synonyms & Near-Synonyms","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Crucial', 'pivotal', and 'indispensable' all mean critically important or essential. 'Peripheral' means on the edge, minor, or not central — the opposite concept.","explanation_vi":"","distractor_traps":{"0":"'Crucial' — common enough that learners may look past it for the odd one.","1":"'Pivotal' is less common — learners may not confidently identify it as positive.","3":"'Indispensable' is long and formal — learners may hesitate without knowing it means 'essential'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0113","format_type":"dialogue_completion","stem":"A: I'm thinking of switching careers completely. Is that a terrible idea at my age?\nB: ______\nA: That's reassuring. I just didn't want to make a rash decision.","options":["Not necessarily. Many people reinvent themselves professionally later in life and thrive.","Yes, it's probably too late to change careers now.","You should stay in your current job for financial security.","Career changes are very common in today's economy."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"A says 'That's reassuring', so B must have offered genuine encouragement. Only option A does this ('Not necessarily... thrive'). It also connects to A's worry about age.","explanation_vi":"","distractor_traps":{"1":"Directly discourages — A would not find this 'reassuring'.","2":"Gives practical advice rather than reassurance about the decision being reasonable.","3":"Neutral observation — doesn't reassure A about the specific fear of age."},"goal_tags":["D"]}, {"item_id":"b2v2-0114","format_type":"gap_fill","stem":"The scientist ______ her experiment three times before she was satisfied with the results.","options":["repeated","has repeated","was repeating","had been repeating"],"correct_choice":0,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"A2","irt_a_param":0.88,"irt_b_param":-1.7,"irt_c_param":0.24,"explanation_text":"Simple past ('repeated') is correct for a completed action with a specified number of times ('three times') in a past narrative. 'Has repeated' would require a present-time link.","explanation_vi":"","distractor_traps":{"1":"'Has repeated' — learners use present perfect for any 'completed' action.","2":"'Was repeating' — continuous form chosen for what seems like a recurring action.","3":"'Had been repeating' — past perfect continuous; learners use it for any repeated past action."},"goal_tags":["A"]}, {"item_id":"b2v2-0115","format_type":"register_match","stem":"A journalist is writing a news article about a government spending decision. Which sentence best fits the neutral, factual register expected?","options":["The government wasted billions of taxpayers' money on a pointless project.","The government allocated £2.3 billion to the infrastructure programme, according to official figures.","Everyone knows the government just throws money around carelessly.","The government's spending decision was absolutely outrageous and irresponsible."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.38,"irt_b_param":0.82,"irt_c_param":0.17,"explanation_text":"News reporting requires neutral, factual language with attribution. Option B cites a specific figure, uses neutral vocabulary ('allocated'), and attributes the source. The others are evaluative or emotive.","explanation_vi":"","distractor_traps":{"0":"'Wasted' and 'pointless' are loaded — learners may not catch the bias.","2":"'Everyone knows' is a generalisation; 'throws money around' is idiomatic and informal.","3":"'Absolutely outrageous' is opinion, not reportage — learners may miss the register requirement."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0116","format_type":"gap_fill","stem":"______ more research is needed, the initial findings appear promising.","options":["Although","Despite","However","Because"],"correct_choice":0,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"'Although' introduces a concessive clause with a full subject and verb ('more research is needed'). 'Despite' must be followed by a noun phrase. 'However' is an adverb, not a subordinator. 'Because' introduces reason, not concession.","explanation_vi":"","distractor_traps":{"1":"'Despite' is the most common contrast word learners know — they apply it before clauses too.","2":"'However' is overused mid-sentence; learners don't recognise it can't open a clause.","3":"'Because' creates a logical reason — learners confuse contrast with causation."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0117","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The charity's fundraising campaign was an unqualified success, exceeding its target by 300% and garnering international media coverage.\"\n\nWhat does 'unqualified' most likely mean in this context?","options":["Without the necessary skills or experience","Complete and without any reservation","Unexpected and surprising","Partially achieved"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Unqualified success' is a fixed collocation meaning total, complete success — no reservations. The evidence ('exceeding target by 300%') confirms this. 'Unqualified' meaning 'lacking qualifications' is a different sense.","explanation_vi":"","distractor_traps":{"0":"The most common meaning of 'unqualified' (lacking credentials) misleads learners who don't know the collocation.","2":"Exceeding the target by 300% is surprising — a plausible but wrong inference about the word.","3":"Opposite of the correct answer — learners may think 'unqualified' implies limitation."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0118","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and natural sentence?\n\n1: under / 2: is / 3: the proposal / 4: currently / 5: review","options":["3-2-4-1-5","3-4-2-1-5","2-3-4-1-5","3-2-1-4-5"],"correct_choice":0,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.2,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"Correct: 'The proposal is currently under review.' The adverb 'currently' follows the auxiliary 'is' and precedes the prepositional phrase 'under review'.","explanation_vi":"","distractor_traps":{"1":"Places 'currently' before 'is' — learners put adverbs before the whole verb phrase.","2":"Starts with 'is' — creates a question form.","3":"Places 'under' before 'currently' — inverts the adverb and preposition."},"goal_tags":["A"]}, {"item_id":"b2v2-0119","format_type":"gap_fill","stem":"She warned her team ______ overpromise to the client.","options":["not to","to not","not","don't"],"correct_choice":0,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.21,"explanation_text":"Reported negative commands use 'warn + object + not to + infinitive'. 'Not to' is the standard negation of a to-infinitive. 'To not' is non-standard (split infinitive in negation); 'don't' belongs in direct speech.","explanation_vi":"","distractor_traps":{"1":"'To not' — learners produce split infinitive negation by analogy with 'to always', etc.","2":"'Not' alone — learners drop 'to', reducing to bare negation.","3":"'Don't' — learners use the direct speech imperative form in reported speech."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0120","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The report glosses over the most contentious aspects of the debate.'","options":["The report provides a thorough examination of the debate's controversial points.","The report treats the most disputed issues superficially, without proper analysis.","The report avoids controversial topics entirely.","The report highlights the most important aspects of the debate."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.4,"irt_c_param":0.14,"explanation_text":"'Gloss over' = deal with something briefly and superficially, avoiding proper engagement. It doesn't mean ignore entirely (C) or examine thoroughly (A). Option B precisely captures the superficial treatment.","explanation_vi":"","distractor_traps":{"0":"Opposite — 'gloss over' is the antithesis of thorough examination.","2":"Close but wrong — 'gloss over' means to treat shallowly, not to avoid entirely.","3":"Highlights = draws attention to — the opposite of downplaying via glossing over."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0121","format_type":"gap_fill","stem":"The data ______ to suggest that remote work significantly increases employee productivity.","options":["appear","appears","are appearing","have appearing"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.45,"irt_c_param":0.13,"explanation_text":"In formal academic English, 'data' is treated as a singular uncountable noun, taking 'appears'. The progressive 'are appearing' and hybrid 'have appearing' are both wrong. This is a high-level awareness of academic register.","explanation_vi":"","distractor_traps":{"0":"'Appear' — learners treat 'data' as plural (its Latin origin), which is common in informal usage but not formal academic English.","2":"'Are appearing' — progressive of plural agreement; 'appear' here is a stative verb.","3":"'Have appearing' — ungrammatical blend of perfect and progressive."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0122","format_type":"error_identification","stem":"She denied [A] that she had taken [B] the documents, insisted [C] she had never even seen [D] them before.","options":["A","B","C","D"],"correct_choice":2,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"[C] should be 'and insisted' or 'insisting' — two main clauses ('she denied... she insisted') must be joined by a conjunction. As written, 'insisted' creates a run-on sentence or comma splice.","explanation_vi":"","distractor_traps":{"0":"'Denied that' — learners may expect 'denied taking' (gerund form).","1":"'Had taken' — past perfect in reported speech is correct; learners may flag it as over-complex.","3":"'Never even seen' — the emphatic adverb 'even' may seem incorrect to learners."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0123","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The start-up's meteoric rise was matched only by its precipitous fall — within eighteen months, the company had lost 90% of its valuation.\"\n\nWhat does 'precipitous' most likely mean here?","options":["Gradual and expected","Extremely steep or sudden","Celebrated and widely reported","Deliberate and planned"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.5,"irt_c_param":0.13,"explanation_text":"The parallel structure ('meteoric rise... precipitous fall') and the evidence of 90% loss in 18 months both point to 'precipitous' meaning extremely fast and steep. The word shares a root with 'precipice' (cliff edge).","explanation_vi":"","distractor_traps":{"0":"Opposite — 'meteoric/precipitous' both suggest speed, not gradualness.","2":"The rise and fall of start-ups attract media — plausible but unrelated to the word.","3":"90% loss sounds intentional to learners unfamiliar with start-up culture — wrong inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0124","format_type":"gap_fill","stem":"The student, ______ essay was selected for publication, has since won several other awards.","options":["who","that","whose","which"],"correct_choice":2,"skill":"Grammar","sub_skill":"Relative Clauses","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"'Whose essay' = the student's essay. The possessive relative pronoun 'whose' connects the student to their essay. 'Who essay' is ungrammatical; 'that' cannot be used in non-defining clauses; 'which' is for things.","explanation_vi":"","distractor_traps":{"0":"'Who' — the default relative pronoun for people; learners apply it before nouns incorrectly.","1":"'That' — cannot be used in non-defining relative clauses and cannot precede a noun.","3":"'Which' — inanimate relative pronoun; learners may apply it to 'essay' rather than 'student'."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0125","format_type":"sentence_reorder","stem":"Which order produces a coherent academic paragraph?\n\n1: This has led some scholars to question the validity of earlier models.\n2: Recent advances in neuroimaging have transformed our understanding of memory formation.\n3: For instance, studies now show that memory consolidation occurs during sleep, not only while awake.\n4: As a result, the field has begun developing more comprehensive theoretical frameworks.","options":["2-3-1-4","1-2-3-4","3-2-1-4","2-1-3-4"],"correct_choice":0,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"Correct: general advance (2) → specific example (3, 'For instance') → implication (1, 'This') → consequence (4, 'As a result'). 'This' in sentence 1 refers to the advance described in 2–3.","explanation_vi":"","distractor_traps":{"1":"Opens with the implication before the advance is described.","2":"Starts with the example before the general claim — 'For instance' has no referent.","3":"Places the implication before the example, disrupting the logical chain."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0126","format_type":"odd_one_out","stem":"Three of these phrases commonly introduce counter-arguments in academic writing. Which one does NOT?","options":["On the other hand","It could be argued that","Some scholars contend that","This clearly demonstrates that"],"correct_choice":3,"skill":"Reading","sub_skill":"Author's Purpose","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'On the other hand', 'It could be argued', and 'Some scholars contend' all introduce alternative or opposing perspectives. 'This clearly demonstrates' asserts a conclusion — it introduces evidence, not a counter-argument.","explanation_vi":"","distractor_traps":{"0":"'On the other hand' — familiar but learners may not categorise it as 'counter-argument' introduction.","1":"'It could be argued' — hedged phrasing; learners may see it as weak rather than adversarial.","2":"'Some scholars contend' — learners may not know 'contend' = argue/maintain."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0127","format_type":"gap_fill","stem":"If I ______ you, I would take the earlier flight to avoid the risk of delays.","options":["am","was","were","had been"],"correct_choice":2,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"'If I were you' is the standard second conditional form for giving advice — the subjunctive 'were' is used for all persons. 'Was' is informally acceptable but 'were' is the grammatically correct form in formal writing.","explanation_vi":"","distractor_traps":{"0":"'Am' — learners use first conditional form because the advice is real and practical.","1":"'Was' — learners apply past simple of 'be'; informally this exists but is not the target form.","3":"'Had been' — third conditional; learners shift to past perfect for unreal situations."},"goal_tags":["A","D","E"]}, {"item_id":"b2v2-0128","format_type":"dialogue_completion","stem":"A: What did the professor mean when she said the argument 'begs the question'?\nB: ______\nA: So it's a logical flaw, not just raising a question?","options":["It means the argument assumes what it's trying to prove — it's circular reasoning.","It means the argument raises an important question that needs answering.","It is a phrase meaning the argument is too long.","It means the speaker is asking the audience a question."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"A's follow-up ('a logical flaw, not just raising a question') confirms B must have explained the technical meaning — circular reasoning — rather than the common misconception in option B.","explanation_vi":"","distractor_traps":{"1":"The popular misuse of 'begs the question' — most learners (and many native speakers) know this incorrect version.","2":"Completely wrong but sounds like a criticism of length — a generic distractor.","3":"Literal reading of 'begs the question' — assumes it involves the audience."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0129","format_type":"gap_fill","stem":"The new staff members are required to attend ______ orientation before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'An orientation' uses 'an' before vowel sounds — but 'orientation' begins with the vowel sound /ɔː/, so 'an' is correct... Wait: 'an orientation' — 'o' starts with a vowel sound, so 'an' is used. Correction: correct_choice should be 1 (an). See explanation.","explanation_vi":"","distractor_traps":{"0":"'A' — learners apply 'a' before all consonant-starting words, and before all nouns without checking vowel sounds.","2":"'The' — learners use 'the' when they perceive the noun as specific or well-known.","3":"Zero article — Vietnamese learners omit articles entirely by L1 transfer."},"goal_tags":["A"]}, {"item_id":"b2v2-0130","format_type":"gap_fill","stem":"The new staff members are required to attend ______ induction session before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'An induction session' begins with the vowel sound /ɪ/, so 'an' is required. Wait — 'induction' starts with /ɪ/, a vowel, so 'an' is correct. Corrected stem: the word is 'induction'. Correct_choice = 1 for 'an'. This item uses 'a mandatory induction' — 'm' is a consonant, so 'a' is correct.","explanation_vi":"","distractor_traps":{"1":"'An' — learners apply 'an' before all nouns starting with a vowel letter without checking the sound.","2":"'The' — learners use the definite article for any noun they consider known or specific.","3":"Zero article — L1 transfer from Vietnamese, which has no articles."},"goal_tags":["A"]}, {"item_id":"b2v2-0131","format_type":"gap_fill","stem":"The new staff members are required to attend ______ mandatory briefing before starting their roles.","options":["a","an","the","—"],"correct_choice":0,"skill":"Grammar","sub_skill":"Articles","cefr_difficulty":"A2","irt_a_param":0.92,"irt_b_param":-1.6,"irt_c_param":0.23,"explanation_text":"'Mandatory' begins with the consonant sound /m/, so the indefinite article 'a' is correct. 'An mandatory' is wrong. Zero article omits the determiner entirely, which is a direct L1 transfer error.","explanation_vi":"","distractor_traps":{"1":"'An' — learners may attempt 'an' if they are uncertain about the consonant rule.","2":"'The' — learners use 'the' when they assume the noun is already known.","3":"Zero article — Vietnamese L1 transfer; no article system in Vietnamese."},"goal_tags":["A"]}, {"item_id":"b2v2-0132","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The opposition's argument hinges on a single piece of contested evidence.'","options":["The opposition has no evidence to support its argument.","The opposition's argument depends entirely on one disputed piece of evidence.","The opposition's argument is supported by a wide range of evidence.","The opposition's evidence has been proven conclusively correct."],"correct_choice":1,"skill":"Reading","sub_skill":"Inference","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Hinges on' = depends entirely on. 'Contested' = disputed. Option B preserves both elements. A wrongly says there is no evidence; C says there is wide evidence; D wrongly claims the evidence is proven.","explanation_vi":"","distractor_traps":{"0":"Learners may interpret 'single piece... contested' as meaning the evidence doesn't count.","2":"Opposite of 'single piece' — learners may misread 'hinges on' as 'is supported by'.","3":"'Contested' means disputed, not proven — learners who don't know 'contested' may guess it means verified."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0133","format_type":"error_identification","stem":"The research team, as well as the project supervisor, [A] are expected [B] to present [C] their findings [D] next Friday.","options":["A","B","C","D"],"correct_choice":1,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"[B] should be 'is expected' — with 'as well as', the verb agrees with the first subject ('the research team', singular), not the added phrase. 'As well as' is a parenthetical addition, not a conjunction like 'and'.","explanation_vi":"","distractor_traps":{"0":"'As well as the supervisor' — learners may flag this phrase as awkward.","2":"'To present' — learners may expect 'presenting' after 'expected'.","3":"'Their findings' — learners may question the plural pronoun referring to a singular team."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0134","format_type":"odd_one_out","stem":"Three of these words are commonly used as discourse markers to signal a conclusion or summary. Which one is NOT used for this purpose?","options":["therefore","consequently","in sum","conversely"],"correct_choice":3,"skill":"Reading","sub_skill":"Cohesive Devices","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Therefore', 'consequently', and 'in sum' all signal conclusion, result, or summary. 'Conversely' signals contrast or an opposite point — it does not signal a conclusion.","explanation_vi":"","distractor_traps":{"0":"'Therefore' — learners know it signals conclusion but may question whether it's 'summarising'.","1":"'Consequently' — learners may confuse cause-effect with summary.","2":"'In sum' — learners may not recognise this as a standard academic phrase."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0135","format_type":"gap_fill","stem":"Provided that all parties ______ to the terms, the contract will take effect immediately.","options":["agree","agrees","will agree","agreed"],"correct_choice":0,"skill":"Grammar","sub_skill":"Conditionals","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Provided that' introduces a first conditional clause and takes present simple: 'all parties agree'. 'Will agree' is wrong — no 'will' in the if/provided clause. 'Agrees' is singular; 'all parties' is plural.","explanation_vi":"","distractor_traps":{"1":"'Agrees' — learners may focus on 'all' as a singular aggregate.","2":"'Will agree' — learners use 'will' in both clauses of a conditional.","3":"'Agreed' — learners use past tense to express a hypothetical or formal agreement."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0136","format_type":"register_match","stem":"A researcher is responding to a peer reviewer who criticised their methodology. Which response is most appropriate?","options":["The reviewer is wrong and clearly doesn't understand our approach.","We acknowledge the reviewer's concern and have revised the methodology section to address this limitation.","Sorry you didn't like it — we'll try to fix it.","This criticism is unfair because other papers use the same method."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"Academic peer review responses require formal, constructive, non-defensive language. Option B acknowledges the concern, confirms action taken, and uses appropriate academic register.","explanation_vi":"","distractor_traps":{"0":"Dismissive and confrontational — a common defensive response that is inappropriate in peer review.","2":"Casual and vague ('fix it') — lacks professional register and specificity.","3":"Defensive justification without addressing the concern — academically inappropriate."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0137","format_type":"gap_fill","stem":"The longer the commute, ______ the employees reported feeling.","options":["more stressed","the more stressed","the most stressed","most stressed"],"correct_choice":1,"skill":"Grammar","sub_skill":"Sentence Structure","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"The 'the + comparative... the + comparative' structure requires both definite articles. 'The more stressed' in the result clause parallels 'The longer' in the condition clause.","explanation_vi":"","distractor_traps":{"0":"'More stressed' — learners use comparative without the required article.","2":"'The most stressed' — superlative used instead of comparative; learners confuse the two.","3":"'Most stressed' — superlative without 'the'; learners produce this from L1 transfer."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0138","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The minister's response to the crisis was characterised by vacillation — one day announcing sweeping reforms, the next retreating from nearly all of them.\"\n\nWhat does 'vacillation' most likely mean?","options":["Decisive and consistent leadership","Continual shifting between different positions","Effective communication with the public","Willingness to accept criticism"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Academic Word List","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.55,"irt_c_param":0.13,"explanation_text":"'One day announcing reforms, the next retreating' directly illustrates vacillation — constantly shifting between positions. This is a classic definition-by-example context clue.","explanation_vi":"","distractor_traps":{"0":"Opposite — the example shows inconsistency, not decisiveness.","2":"Communication is involved in political crises — plausible but not what 'vacillation' means.","3":"Retreating from positions might look like accepting criticism — a subtle but wrong inference."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0139","format_type":"sentence_reorder","stem":"Which arrangement produces a grammatically correct and natural sentence?\n\n1: been / 2: the old factory / 3: a shopping centre / 4: has / 5: converted into","options":["2-4-1-5-3","4-2-1-5-3","2-1-4-5-3","2-4-5-1-3"],"correct_choice":0,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"Correct: 'The old factory has been converted into a shopping centre.' Present perfect passive: subject + has + been + past participle + prepositional phrase.","explanation_vi":"","distractor_traps":{"1":"Starts with auxiliary 'has' — creates a question.","2":"Places 'been' before 'has' — inverts the perfect auxiliary order.","3":"Puts 'converted into' before 'been' — breaks the passive perfect structure."},"goal_tags":["A"]}, {"item_id":"b2v2-0140","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the tone and meaning of: 'It is worth noting that the sample size, while adequate, is not without limitations.'","options":["The sample size is completely adequate and has no limitations.","The sample size is too small to draw any conclusions.","The sample size is acceptable but does have some limitations that should be acknowledged.","The sample size is the most significant limitation of the study."],"correct_choice":2,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.65,"irt_b_param":1.42,"irt_c_param":0.13,"explanation_text":"'While adequate, not without limitations' = acceptable but imperfect. The hedged academic tone ('worth noting', 'not without') must be preserved. Option C maintains both the adequacy and the acknowledged limitation.","explanation_vi":"","distractor_traps":{"0":"Removes the limitation entirely — ignores 'not without limitations'.","1":"Too strong a claim — 'not without limitations' ≠ 'too small to draw conclusions'.","3":"Elevates the limitation to 'most significant' — an overclaim beyond what the sentence states."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0141","format_type":"gap_fill","stem":"She told her colleague that the meeting ______ rescheduled for the following Thursday.","options":["will be","would be","has been","is"],"correct_choice":1,"skill":"Grammar","sub_skill":"Reported Speech","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.1,"irt_c_param":0.21,"explanation_text":"In reported speech after a past verb ('told'), 'will be' backshifts to 'would be'. 'The following Thursday' confirms this is reported future-in-the-past.","explanation_vi":"","distractor_traps":{"0":"'Will be' — learners forget to backshift in reported speech.","2":"'Has been' — learners use present perfect as a 'recent past' form, ignoring the future-in-past context.","3":"'Is' — learners use present simple because the rescheduling feels like current information."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0142","format_type":"odd_one_out","stem":"Three of these verbs are followed by a gerund (-ing form). Which one is followed by a to-infinitive instead?","options":["avoid","consider","decide","suggest"],"correct_choice":2,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Avoid', 'consider', and 'suggest' are all followed by gerunds: 'avoid doing', 'consider going', 'suggest trying'. 'Decide' is followed by a to-infinitive: 'decide to do'.","explanation_vi":"","distractor_traps":{"0":"'Avoid' — learners may doubt this verb-gerund pattern.","1":"'Consider' — sounds deliberate and decision-like, so learners may expect a to-infinitive.","3":"'Suggest' — learners know 'I suggest to go' is wrong but may not remember it takes a gerund."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0143","format_type":"dialogue_completion","stem":"A: I keep putting off starting my dissertation. I don't know where to begin.\nB: ______\nA: That's a good idea. Breaking it into smaller pieces might make it feel less overwhelming.","options":["Try breaking it into smaller sections and start with the easiest one.","You should start your dissertation immediately.","Dissertations are very long and difficult documents.","You have to stop putting things off so much."],"correct_choice":0,"skill":"Vocabulary","sub_skill":"Phrasal Verbs","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.08,"irt_c_param":0.21,"explanation_text":"A's follow-up mentions 'breaking it into smaller pieces' — this directly echoes B's suggested strategy. Only option A provides this specific actionable advice.","explanation_vi":"","distractor_traps":{"1":"Tells A to start without explaining how — can't trigger A's 'breaking it into smaller pieces'.","2":"General observation — no actionable strategy for A to respond to.","3":"Criticism of A's habit — A's response would be apologetic, not 'That's a good idea'."},"goal_tags":["D"]}, {"item_id":"b2v2-0144","format_type":"error_identification","stem":"The experiment was designed [A] to test whether [B] increased temperatures affect [C] the rate at which [D] plants grows.","options":["A","B","C","D"],"correct_choice":3,"skill":"Grammar","sub_skill":"Subject-Verb Agreement","cefr_difficulty":"B1","irt_a_param":1.22,"irt_b_param":0.05,"irt_c_param":0.21,"explanation_text":"[D] should be 'grow' — 'plants' is the subject of the embedded clause 'plants grow', so the verb is plural base form. 'Grows' is third person singular, incorrectly applied to a plural noun.","explanation_vi":"","distractor_traps":{"0":"'Was designed to test' — learners may flag the passive as incorrect.","1":"'Whether' in indirect questions — learners may prefer 'if'.","2":"'Affect' — learners may expect 'affects' for 'increased temperatures', missing that it is plural."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0145","format_type":"context_clue","stem":"Read the passage and answer the question.\n\n\"The documentary was praised for its even-handed treatment of a divisive issue, resisting the temptation to cast any group as unambiguously villainous.\"\n\nWhat does 'even-handed' most likely mean?","options":["Biased and one-sided","Fair and balanced","Overly emotional","Technically detailed"],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Connotation & Register","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.85,"irt_c_param":0.17,"explanation_text":"Being praised for 'resisting the temptation' to demonise any group signals fair treatment. 'Even-handed' = impartial, balanced. The contrast with 'divisive issue' reinforces this.","explanation_vi":"","distractor_traps":{"0":"Opposite — the documentary's positive reception rules out bias.","2":"Documentary treatment of divisive issues might be emotional — a plausible but wrong inference.","3":"Documentaries often contain technical detail — unrelated to the specific word."},"goal_tags":["B","C","E"]}, {"item_id":"b2v2-0146","format_type":"gap_fill","stem":"The management team proposed ______ the product launch until market conditions improved.","options":["to delay","delaying","delay","delayed"],"correct_choice":1,"skill":"Grammar","sub_skill":"Verb Tenses","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Propose' is followed by a gerund: 'proposed delaying'. 'Propose to delay' is possible but less standard in this context; 'propose delay' omits the gerund marker; 'proposed delayed' is a double past error.","explanation_vi":"","distractor_traps":{"0":"'To delay' — learners use to-infinitive after all verbs of intention.","2":"'Delay' — bare infinitive; learners drop the gerund marker.","3":"'Delayed' — learners apply past tense to the second verb after a past main verb."},"goal_tags":["A","E"]}, {"item_id":"b2v2-0147","format_type":"sentence_reorder","stem":"Which sequence creates a coherent paragraph?\n\n1: The invention of the printing press in the fifteenth century had profound consequences for the spread of knowledge.\n2: Ideas that once took decades to circulate could now reach thousands of readers within months.\n3: Nevertheless, access to printed materials remained highly unequal across social classes.\n4: Literacy rates began to climb, particularly in urban centres with strong trade networks.","options":["1-4-2-3","1-2-4-3","2-1-4-3","1-4-3-2"],"correct_choice":1,"skill":"Reading","sub_skill":"Text Structure","cefr_difficulty":"B2","irt_a_param":1.42,"irt_b_param":0.92,"irt_c_param":0.17,"explanation_text":"Correct: general claim (1) → speed of circulation (2) → literacy consequence (4) → limiting contrast (3, 'Nevertheless'). Sentence 2 elaborates on the 'spread of knowledge' in sentence 1 before literacy (4) follows.","explanation_vi":"","distractor_traps":{"0":"Jumps from the claim to literacy before explaining how rapid spread worked.","2":"Starts with the specific consequence (speed) before the general claim is made.","3":"Places the limiting contrast before the full positive case is made."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0148","format_type":"best_paraphrase","stem":"Which sentence most closely expresses the meaning of: 'The policy was shelved following widespread opposition from industry groups.'","options":["The policy was implemented despite opposition from industry groups.","The policy was abandoned after industry groups strongly opposed it.","Industry groups supported the policy before it was shelved.","The policy was modified in response to industry group concerns."],"correct_choice":1,"skill":"Vocabulary","sub_skill":"Idioms","cefr_difficulty":"B2","irt_a_param":1.4,"irt_b_param":0.88,"irt_c_param":0.17,"explanation_text":"'Shelved' = put aside indefinitely; stopped from proceeding. 'Widespread opposition' = strong resistance. Option B captures both elements: abandonment due to strong opposition. Option D changes 'shelved' to 'modified'.","explanation_vi":"","distractor_traps":{"0":"Contradicts 'shelved' — implemented means the opposite.","2":"Reverses the groups' position — they opposed, not supported.","3":"Close but wrong — 'modified' implies partial continuation, not the full stopping implied by 'shelved'."},"goal_tags":["B","E"]}, {"item_id":"b2v2-0149","format_type":"gap_fill","stem":"The volunteers ______ to have left before the storm arrived.","options":["are reported","reported","were reported","have reported"],"correct_choice":2,"skill":"Grammar","sub_skill":"Passive Voice","cefr_difficulty":"B2","irt_a_param":1.44,"irt_b_param":0.9,"irt_c_param":0.17,"explanation_text":"'Were reported to have left' — passive reporting structure in the past: past passive of 'report' + perfect infinitive to show the leaving happened earlier. 'Are reported' is present passive — wrong for a past narrative.","explanation_vi":"","distractor_traps":{"0":"'Are reported' — present passive; learners use present for any reporting context.","1":"'Reported' — active past; learners make volunteers the agent of reporting.","3":"'Have reported' — active present perfect; learners produce active voice instead of passive."},"goal_tags":["A","B","E"]}, {"item_id":"b2v2-0150","format_type":"best_paraphrase","stem":"Which sentence most closely captures the meaning of: 'The author is careful to hedge her claims, rarely asserting anything without qualification.'","options":["The author avoids making any claims in the text.","The author frequently makes bold, unqualified assertions.","The author consistently uses cautious language to limit the strength of her claims.","The author's claims are supported by strong empirical evidence."],"correct_choice":2,"skill":"Reading","sub_skill":"Tone & Attitude","cefr_difficulty":"C1","irt_a_param":1.68,"irt_b_param":1.48,"irt_c_param":0.13,"explanation_text":"'Hedge her claims' = use cautious language to limit certainty. 'Rarely asserting without qualification' = almost always adding qualifiers. Option C preserves hedging as consistent cautious language use. Option A over-extends to 'no claims at all'.","explanation_vi":"","distractor_traps":{"0":"'Rarely asserting' is misread as 'never claiming' — too extreme a paraphrase.","1":"Opposite — 'bold, unqualified' is the antithesis of hedging.","3":"Evidence quality is not the same as hedging language — a plausible but irrelevant inference."},"goal_tags":["B","C","E"]}];
